globalThis.__MEMO_CAPSULE_EXCERPTS__ = [{"book":"激荡三十年（上卷）","author":"吴晓波","text":"在此之后，我们即将看到，中国开始从观念驱动向利益驱动的时代转型，政府将表现出热烈的参与欲望和强悍的行政调控力，国营、民间和国际三大商业资本将展开更为壮观和激烈的竞争、博弈与交融。"},{"book":"激荡三十年（上卷）","author":"吴晓波","text":"1992年的春天，给喜好“大历史阐述”的中国人留下了太深的印象，以至于在后来的很多记忆中，这一年整个儿都是春天。"},{"book":"激荡三十年（上卷）","author":"吴晓波","text":"这个时候的中国公司，就好像一个青春期的少年冲进一片正在疯长中的草地，你听得到他的骨骼与青草一起向上生长的声音，过度的精力和热情挥霍似乎是无可避免的。"},{"book":"激荡三十年（上卷）","author":"吴晓波","text":"历经千辛万苦，说尽千言万语，跑遍千山万水，想尽千方百计"},{"book":"激荡三十年（上卷）","author":"吴晓波","text":"我觉得每一代人只能做他当时认为最重要的事。人活着总要做点事，做了这件，也许就要放弃那一件。我做事从不后悔，即使做了较为愚蠢的事，也不后悔，因为时间总是在往前走的。"},{"book":"激荡三十年（上卷）","author":"吴晓波","text":"80年代出现了两股改革力量：一股是执行改革开放政策的党政干部，他们的处境和思路，很像清末自强派，是所谓‘体制内’的改革者；另一股则来自知识分子，特别是青年学生。"},{"book":"激荡三十年（上卷）","author":"吴晓波","text":"清楚界定的产权是市场交易的前提。"},{"book":"激荡三十年（上卷）","author":"吴晓波","text":"灰白的太阳终于费力地钻出薄雾，把它那毫无热气的光线投射到这个巨大城市的每一个角落——拥挤的楼房、狭窄的棋盘式街道和蠕动的密集人群中。"},{"book":"激荡三十年（上卷）","author":"吴晓波","text":"一个人要让自己快乐其实是一件不难的事，你只要给自己一个较长时间的目标，然后按部就班地去接近它，实现它。"},{"book":"激荡三十年（上卷）","author":"吴晓波","text":"在这个时刻，我突然能十分真切地感受到100多年前托尔斯泰写信时的那份舍我其谁的使命感、另辟蹊径的自信和即将开始一段充实工作的满足。"},{"book":"激荡三十年（上卷）","author":"吴晓波","text":"当这个时代到来的时候，锐不可当。万物肆意生长，尘埃与曙光升腾，江河汇聚成川，无名山丘崛起为峰，天地一时，无比开阔。"},{"book":"战争论","author":"克劳塞维茨","text":"暴力是一种手段，把自己的意志强加于对方才是目的。为了保证有把握地达到这个目的，就必须使对方丧失抵抗能力。所以从概念上讲，使对方丧失抵抗能力是战争行为真正的直接目标。"},{"book":"战争论","author":"克劳塞维茨","text":"敌人抵抗力的大小是两个不可分割的因素的乘积，这两个因素分别是有多少战胜敌人的手段与意志力的强弱程度。"},{"book":"战争论","author":"克劳塞维茨","text":"“战争无非是国家政治通过另一种手段的继续”，“战争是迫使敌人服从我们意志的一种暴力行为”。"},{"book":"赢（尊享版）","author":"[美]杰克·韦尔奇 [美]苏茜·韦尔奇","text":"商业是由人组成的。实际上，生活也是由人组成的——家人、朋友、同事、上司、老师、教练、邻居。归根结底，人是最重要的"},{"book":"史蒂夫·乔布斯传","author":"沃尔特·艾萨克森","text":"我的激情所在是打造一家可以传世的公司，这家公司里的人动力十足地创造伟大的产品。其他一切都是第二位的。"},{"book":"史蒂夫·乔布斯传","author":"沃尔特·艾萨克森","text":"他高度关注如何发挥人性的作用、让人们获得力量，如何使人类进步，并给人类创造正确的工具去追求进步"},{"book":"史蒂夫·乔布斯传","author":"沃尔特·艾萨克森","text":"“在商业界有个很经典的理论，叫做‘第二个产品综合征’。”症结在于对第一个产品的成功缺乏理解。"},{"book":"史蒂夫·乔布斯传","author":"沃尔特·艾萨克森","text":"我属于少数人，既懂得发明技术需要直觉和创造力，也知道制作艺术作品需要接受真正的专业训练。"},{"book":"史蒂夫·乔布斯传","author":"沃尔特·艾萨克森","text":"一直以来，他都站在人性和科技的交叉点上。他热爱音乐、图片和视频。他也热爱计算机。数字中枢的本质就是把我们对创意艺术的欣赏和伟大的工程技术结合起来。"},{"book":"史蒂夫·乔布斯传","author":"沃尔特·艾萨克森","text":"乔布斯的一个过人之处是知道如何做到专注。“决定不做什么跟决定做什么同样重要，”他说，“对公司来说是这样，对产品来说也是这样。”"},{"book":"史蒂夫·乔布斯传","author":"沃尔特·艾萨克森","text":"马库拉曾教过他，你可以根据封面去评价一本书，而一家伟大的公司必须从给人的第一印象就映射出自己的价值观。"},{"book":"美国增长的起落","author":"罗伯特·戈登","text":"计算机时代产生的问题不是大规模失业，而是良好的、稳定的中层就业岗位的逐渐消失，但这不仅仅是因为机器人和计算机算法，还因为全球化和业务外包给其他国家，以及就业增长主要集中在工资相对较低的常规体力工作。"},{"book":"美国增长的起落","author":"罗伯特·戈登","text":"通常情况下，机器人与人类一起工作，而不是取代人类。"},{"book":"美国增长的起落","author":"罗伯特·戈登","text":"预测未来之前，我们需要问的是这种预测的尝试是否可行。"},{"book":"美国增长的起落","author":"罗伯特·戈登","text":"正是因为有了电影，观看方式才发生了向非竞争性方式的显著转变，才能同时在许多地方观看到卓别林的表演。电影通过自动化、标准化以及可交易化实现了娱乐的工业化。"},{"book":"CFA一级中文精讲①（第2版）","author":"何旋 李斯克编著","text":"普通年金（ordinary annuities）又称后付年金，这是最为常见的年金表现形式。"},{"book":"CFA一级中文精讲①（第2版）","author":"何旋 李斯克编著","text":"EAR=（1+r）m－1"},{"book":"CFA一级中文精讲①（第2版）","author":"何旋 李斯克编著","text":"m趋向于+∞，EAR的计算公式可改写为EAR=er-1"},{"book":"CFA一级中文精讲①（第2版）","author":"何旋 李斯克编著","text":"但是我们这里关注的是商品能否足额变现，即商品变卖的价格能否等于其公允价值"},{"book":"CFA一级中文精讲①（第2版）","author":"何旋 李斯克编著","text":"被舍弃的选项中具有最高价值的选项就是本次决策的机会成本"},{"book":"CFA一级中文精讲①（第2版）","author":"何旋 李斯克编著","text":"拥有专业知识和更多获取信息的途径"},{"book":"生命3.0：AI超级智能与伦理边界重构","author":"迈克斯·泰格马克","text":"毕竟，当全世界第一个超级智能都在为你工作时，你显然最好投资自家的产品，而不是寄希望于别人家的。"},{"book":"游牧者的抉择：面对汉帝国的北亚游牧部族","author":"王明珂","text":"“游牧”是人类为适应特定环境而产生的一种精致经济社会体系。在人类文明史上，它不是介于原始采集、狩猎经济与农业之间的一种生计手段；它出现在人类文明史上的时间远晚于原始农业。"},{"book":"今日简史：人类命运大议题","author":"尤瓦尔·赫拉利","text":"拿破仑有句名言，说他只要用一个勋章，就能让士兵愿意献出自己的生命。"},{"book":"今日简史：人类命运大议题","author":"尤瓦尔·赫拉利","text":"在所有的假新闻之下，都有真正的事实，也有真实的痛苦。人类的痛苦常常来自相信了虚构的故事，但无论如何，痛苦本身仍然真实。"},{"book":"今日简史：人类命运大议题","author":"尤瓦尔·赫拉利","text":"我们把比较多的时间和精力拿来努力控制世界，而非努力理解世界；而且就算我们努力理解世界，通常也是为了事后更容易地控制世界。"},{"book":"今日简史：人类命运大议题","author":"尤瓦尔·赫拉利","text":"在《我的奋斗》（Mein Kampf）里，希特勒也写道：“即便政治宣传手段再出色，如果没把一项基本原则牢记在心，也无法成功——宣传时必须只锁定几个重点，然后不断地一再重复。”"},{"book":"今日简史：人类命运大议题","author":"尤瓦尔·赫拉利","text":"俄罗斯一直遵守着校园霸凌的潜规则：“要打就挑最弱的，而且别打得太狠，免得老师出手。”"},{"book":"今日简史：人类命运大议题","author":"尤瓦尔·赫拉利","text":"不幸的是，亲密关系却可能是一场零和博弈。"},{"book":"今日简史：人类命运大议题","author":"尤瓦尔·赫拉利","text":"古代的狩猎采集部落已经比后来的所有人类社会都更加平等，原因在于他们本来就没什么财产。"},{"book":"今日简史：人类命运大议题","author":"尤瓦尔·赫拉利","text":"如果只是要取代人类驾驶员，算法并不需要做到完美无缺，只要比人类更好就行了。"},{"book":"今日简史：人类命运大议题","author":"尤瓦尔·赫拉利","text":"丘吉尔曾有一句名言，说除了其他所有制度之外，民主是全世界最糟糕的政治制度。不论是对是错，人类都可能对大数据算法得到相同的结论：虽然算法漏洞百出，但我们并没有更好的选择。"},{"book":"今日简史：人类命运大议题","author":"尤瓦尔·赫拉利","text":"有点儿像19世纪汽车取代马车时的情景，当时有许多马车夫转行当出租车司机，只是我们可能不是那些马车夫，而是被淘汰的马。"},{"book":"今日简史：人类命运大议题","author":"尤瓦尔·赫拉利","text":"在一个信息爆炸却多半无用的世界，清晰的见解就成了一种力量。"},{"book":"童年的终结（同名美剧原著）","author":"阿瑟·克拉克","text":"这是一个黄金时代。不过，金色也是日落的颜色，秋天的颜色，只有卡列伦的耳朵能捕捉到冬天风暴的第一声呼号。"},{"book":"哈佛极简经济学","author":"罗伯特·L.海尔布隆纳","text":"他说，对天空的征服，将与对印度的征服一样重大。"},{"book":"哈佛极简经济学","author":"罗伯特·L.海尔布隆纳","text":"霍布森的答案极为简洁。富人自动存下的钱有一条出路，不致引起国内生产过多的麻烦，那就是投资海外。"},{"book":"哈佛极简经济学","author":"罗伯特·L.海尔布隆纳","text":"“人是环境的产物。”但是，除了人自己之外，还有谁来制造环境呢？世界并非必然好或不好，要看我们努力到什么程度而定。欧文身后留下了这个希望的哲学，要比他关于铲子和犁、货币，或者合作村的空想更为有力。"},{"book":"哈佛极简经济学","author":"罗伯特·L.海尔布隆纳","text":"地方工会无法控制其会员，而地方性的罢工又削弱了全国性的组织。"},{"book":"哈佛极简经济学","author":"罗伯特·L.海尔布隆纳","text":"这个基本愿景是什么？就是将“社会”看作一个受到牟利的需要所驱动、受到无所不在的竞争所约束的伟大社会机制，同时也谨慎地给予政府运作的领域，并将政府限缩在该领域内。"},{"book":"哈佛极简经济学","author":"罗伯特·L.海尔布隆纳","text":"对马尔萨斯而言，至关重要的议题是“有多少？”；对李嘉图而言，最具爆炸性的议题是“谁得到什么？”。他们谈论的话题不同，难怪永远没有共识。"},{"book":"哈佛极简经济学","author":"罗伯特·L.海尔布隆纳","text":"亚当·斯密的世界，被称为原子式竞争的世界。在那个世界中，无论是劳动或资本方面的生产要素，都无力对于竞争的压力加以干预或抗拒，人人都被迫在一个巨大的社会自由竞技场中，匆匆地追逐自身的利益。"},{"book":"哈佛极简经济学","author":"罗伯特·L.海尔布隆纳","text":"一般注重实务、自认为不受知识分子影响的人，往往都是某个已故经济学家的奴隶。只聆听来自虚空中的声音的掌权狂人，正在从多年前某个三流学者的学说中提炼其狂想。"},{"book":"冲浪板上的公司：巴塔哥尼亚的创业哲学","author":"伊冯·乔伊纳德","text":"说到公司，如果我真的抱有这些信念，同样消耗资源、产生污染的巴塔哥尼亚就不能坐等政府的改变。我们得对自己征税，并将那些钱用于做好事。"},{"book":"这就是OKR ： 让谷歌、亚马逊实现爆炸性增长的工作法","author":"约翰·杜尔","text":"冷静、清醒和专注"},{"book":"这就是OKR ： 让谷歌、亚马逊实现爆炸性增长的工作法","author":"约翰·杜尔","text":"提升绩效最简单的方法就是强制人们对业务进行深刻、透彻和关联性的思考"},{"book":"这就是OKR ： 让谷歌、亚马逊实现爆炸性增长的工作法","author":"约翰·杜尔","text":"大多数人倾向于认为某件事是不可能的，而不是回归现实世界的本源去寻找可能实现它的机会。"},{"book":"这就是OKR ： 让谷歌、亚马逊实现爆炸性增长的工作法","author":"约翰·杜尔","text":"使命是具有方向性的，而目标则包含一系列具体的步骤，需要个体真正参与其中并为之不懈奋斗。有一个宏伟的目标是必要的，但你必须要知道如何控制它的规模，以及如何对它进行衡量。"},{"book":"这就是OKR ： 让谷歌、亚马逊实现爆炸性增长的工作法","author":"约翰·杜尔","text":"在任何数据驱动的系统中，事后的评估和分析都可以挖掘出巨大的价值。"},{"book":"这就是OKR ： 让谷歌、亚马逊实现爆炸性增长的工作法","author":"约翰·杜尔","text":"知道要去哪里的人，往往会更加清楚如何到达目的地。"},{"book":"这就是OKR ： 让谷歌、亚马逊实现爆炸性增长的工作法","author":"约翰·杜尔","text":"在一线作战的人通常会提前感知到即将发生的变化。销售人员往往比管理者更先理解顾客需求的变化，金融分析师通常是最早知道商业变化的人。"},{"book":"这就是OKR ： 让谷歌、亚马逊实现爆炸性增长的工作法","author":"约翰·杜尔","text":"当目标从计划转向执行时，管理者和员工都必须将自己每天的工作与组织愿景联系起来。这种联系的专业术语就是“协同”。"},{"book":"这就是OKR ： 让谷歌、亚马逊实现爆炸性增长的工作法","author":"约翰·杜尔","text":"免于退步或陷入微观琐碎事务的管理"},{"book":"这就是OKR ： 让谷歌、亚马逊实现爆炸性增长的工作法","author":"约翰·杜尔","text":"是我们自己的选择而不是能力，展示了我们是谁。"},{"book":"这就是OKR ： 让谷歌、亚马逊实现爆炸性增长的工作法","author":"约翰·杜尔","text":"知识是次要的，执行才是最重要的"},{"book":"这就是OKR ： 让谷歌、亚马逊实现爆炸性增长的工作法","author":"约翰·杜尔","text":"在眼花缭乱、不断变化的项目中找出共性的天赋"},{"book":"这就是OKR ： 让谷歌、亚马逊实现爆炸性增长的工作法","author":"约翰·杜尔","text":"规模化则意味着大规模、大体量，强调以系统观来看待可以重复使用的任务完成方式"},{"book":"这就是OKR ： 让谷歌、亚马逊实现爆炸性增长的工作法","author":"约翰·杜尔","text":"只有目标明确，才能实现目标。"},{"book":"这就是OKR ： 让谷歌、亚马逊实现爆炸性增长的工作法","author":"约翰·杜尔","text":"目标应该是重要的、具体的、具有行动导向并且能鼓舞人心的。如果设计合理并且实施得当，目标能够有效地防止思维和执行过程中出现模糊不清的情况。"},{"book":"这就是OKR ： 让谷歌、亚马逊实现爆炸性增长的工作法","author":"约翰·杜尔","text":"明确定义的、被记录下来且能够自由分享的目标"},{"book":"这就是OKR ： 让谷歌、亚马逊实现爆炸性增长的工作法","author":"约翰·杜尔","text":"想法很容易，执行最重要。"},{"book":"昨日的世界","author":"茨威格","text":"我觉得非常幸运，由于我的写作意图从一开始就是面向全欧、超越国界的，所以国外的出版商，如法国、保加利亚、亚美尼亚、葡萄牙、阿根廷、拉脱维亚、挪威、芬兰和中国的出版商，纷纷来信同我联系出书事宜。"},{"book":"昨日的世界","author":"茨威格","text":"令人不胜惊奇的是，实际情况完全相反。人们要求生活连续性的意志远远超过货币的不稳定性。"},{"book":"昨日的世界","author":"茨威格","text":"他对我说：“如果只了解英吉利岛，您就不会了解英国。同样，如果您从未走出欧洲，那您也不会真正懂得我们这块欧洲大陆。"},{"book":"昨日的世界","author":"茨威格","text":"后来我才知道，人生的道路是由内因决定的；我们的道路往往偏离我们的愿望，而且是极混乱的、没有道理的，但它终会把我们引向我们自己看不见的目标。"},{"book":"昨日的世界","author":"茨威格","text":"我还是相信歌德的话，如果要完全理解一部伟大的著作，不仅要看到成品，还必须要了解这部作品的产生过程。"},{"book":"下一站 火星：马斯克、贝佐斯与太空争夺战","author":"克里斯蒂安·达文波特","text":"为行业竞争提供更多奖励，对能够降低太空旅行成本的飞行器给予更多关注，确保政府合同公平公正。"},{"book":"整个巴黎属于我","author":"莱斯利·M.M.布鲁姆","text":"据传在1912年，有一次他在办公室里精神崩溃了，走出去之后就再也没有回去。"},{"book":"整个巴黎属于我","author":"莱斯利·M.M.布鲁姆","text":"革命嘛，不掉几个脑袋那还叫什么革命。"},{"book":"整个巴黎属于我","author":"莱斯利·M.M.布鲁姆","text":"虽然这两位作家笔下的人物都行为放荡，饮酒过度，和不该上床的人上床，但是海明威敏锐地指出，自己的作品探讨的是死亡、重生和人生的意义。"},{"book":"整个巴黎属于我","author":"莱斯利·M.M.布鲁姆","text":"那时他知道自己需要学习的还有很多，但是对于他想达到的成就，他有着强烈的意愿，并将自己的目标精确地执行。"},{"book":"整个巴黎属于我","author":"莱斯利·M.M.布鲁姆","text":"他喜欢固执己见，所以会把不那么坚定的人吸引到他身边去，就像光亮吸引飞蛾一样。"},{"book":"整个巴黎属于我","author":"莱斯利·M.M.布鲁姆","text":"对于那些在巴黎初次见到海明威的人来说，他的名字可算起得十分贴切：欧内斯特（Earnest）￼。"},{"book":"整个巴黎属于我","author":"莱斯利·M.M.布鲁姆","text":"一类新式作家诞生了——头脑发达，四肢也发达，与普鲁斯特和他那些满身灰尘、离群索居的同道截然不同。"},{"book":"旅行的艺术（译文经典）","author":"阿兰·德波顿","text":"旅行的一个危险是，我们还没有积累和具备所需要的接受能力就迫不及待地去观光，而造成时机错误。正如缺乏一条链子将珠子串成项链一样，我们所接纳的新讯息会变得毫无价值，并且散乱无章。"},{"book":"旅行的艺术（译文经典）","author":"阿兰·德波顿","text":"旅人不同于常人，有一种独特的心境，他们在荒漠相遇，在街市邂逅，一抬眼就能彼此沟通。"},{"book":"东晋门阀政治","author":"田余庆","text":"《三国志·魏志·王昶传》王昶诫子侄“遵儒者之教，履道家之言”，是多数当政居位的玄学名士立身行事的共同倾向。这实际上就是《庄子·天下》所说的“内圣外王”之道。"},{"book":"海边的卡夫卡","author":"[日]村上春树","text":"大部分情况下他们寻求的不是学术性的真实，而是符合他们思维体系的结论或单纯实效性。"},{"book":"债务危机","author":"瑞·达利欧","text":"汇率稳定基金本来是用来防止美元挤兑的，但它的授权灵活，可以转用于更紧迫的用途。这一调整也可以迅速完成，只需获得总统批准即可。这正是避开监管和政治雷区，完成必要工作所需的快速思考与创造力。"},{"book":"债务危机","author":"瑞·达利欧","text":"在法规严格、制衡系统强大的民主国家，应对危机的典型挑战之一是，了解必要行动的合法性，并推动行动获得批准。"},{"book":"生命是什么","author":"王立铭","text":"现在我们知道生命源于能量，遗传信息需要复制，分工带来复杂性，而心智的萌芽依靠与客观世界的交流握手和学习互动。但是我们必须承认，这几条全部加起来，也远不足以为“智慧”这个词给出一个完整的描绘。"},{"book":"生命是什么","author":"王立铭","text":"赫布定律其实是在告诉我们，学习过程的本质就是两个相连的神经细胞差不多同时开始活动，因此它们之间的连接会变得更加紧密，从而让我们在两个本来无关的事物之间建立了联系。"},{"book":"生命是什么","author":"王立铭","text":"如果我们人类的大脑真的那么简单，那么容易理解，那如此简单的一颗大脑根本就不可能做到理解自己！"},{"book":"生命是什么","author":"王立铭","text":"作为伟大分工的代价，多细胞生物要面对一个永恒的难题：如何预防、压制和惩罚那些不愿意接受既定分工、特别希望重新拥有繁殖能力的细胞？"},{"book":"生命是什么","author":"王立铭","text":"生命，如果不是因为其确实存在，本来可以很容易地证明其不可能存在。"},{"book":"生命是什么","author":"王立铭","text":"好的科普书重要的作用不是科普知识点，因为知识早晚会变得陈旧，而是普及科学的思维和判断方式。"},{"book":"当下的启蒙","author":"[美]史蒂芬·平克","text":"公正性，存在于许多在理性基础上构建道德的尝试之中：斯宾诺莎关于永恒的观点，霍布斯的社会契约，康德的定言令式，罗尔斯的无知之幕，内格尔的本然观点，洛克和杰弗逊提出的“人人生来平等”的不证自明的真理"},{"book":"当下的启蒙","author":"[美]史蒂芬·平克","text":"之所以出现这些现象，部分是因为人们误认为民主的优越性来源于竞选，而实际上，民主的优越性更取决于拥有一个对权力进行限制、对公民作出回应、对政策结果予以关注的政府"},{"book":"当下的启蒙","author":"[美]史蒂芬·平克","text":"假如更多的人能够消受得起这些人钟爱的奢侈品，即便这些商品本身在更高档次的文化中显得过于轻浮，但是也总归是件好事。"},{"book":"当下的启蒙","author":"[美]史蒂芬·平克","text":"弗林曾经推测认为抽象推理能力中包含了道德感，我也赞成这个推测。从生活中抽离自己的换位思维，以及“我只是运气好了点”或者“如果每个人都这样做，世界会变得怎样”的沉思，无疑都是共情和伦理产生的基础。"},{"book":"当下的启蒙","author":"[美]史蒂芬·平克","text":"实际上成年人的弗林效应比儿童要明显，这意味着在长大成人过程中学到的经验，而不仅仅是儿童时期的生理体质，才是推高智商的主要原因。最显然的经验莫过于教育经历。"},{"book":"当下的启蒙","author":"[美]史蒂芬·平克","text":"事实上，富裕但是贫富差距明显的国家和地区往往拥有比相对贫穷但是平等的国家更健康完满的社会发展环境。"},{"book":"当下的启蒙","author":"[美]史蒂芬·平克","text":"这本书一直被戏称为“左派们的万物理论”，它的弊端与其他理论一样，在于把错综复杂的事物联系大刀阔斧地砍成了单一的原因。"},{"book":"当下的启蒙","author":"[美]史蒂芬·平克","text":"尽管人性存在种种缺陷，但只要人类能设计出各种原则和体系，将局部利益引导为普遍利益，那人性也包含了自我完善的种子。"},{"book":"当下的启蒙","author":"[美]史蒂芬·平克","text":"凡受理性指导的人，亦即以理性作指针而寻求自己的利益的人，他们所追求的东西，也即是他们为别人而追求的东西。"},{"book":"枢纽：3000年的中国（新版增订4万字）","author":"施展","text":"除非，这些不再生产的人其消费行为本身就等于生产"},{"book":"枢纽：3000年的中国（新版增订4万字）","author":"施展","text":"凯恩斯拥有一种超越国家政治的普遍视野，又将其构想的普遍秩序落实在主权国家的框架上，以回应民主政治的要求。"},{"book":"枢纽：3000年的中国（新版增订4万字）","author":"施展","text":"大众政治大大压缩了政治领袖们在国际舞台上的转圜空间，也压缩了他们的秩序想象的视野。"},{"book":"枢纽：3000年的中国（新版增订4万字）","author":"施展","text":"任何秩序得以成立，都离不开暴力对其的底层支撑；但暴力本身是纯工具性的，它无法内生出目标，是政治叙事为其赋予目标，并以此构成暴力行为正当与否的判断标准。"},{"book":"枢纽：3000年的中国（新版增订4万字）","author":"施展","text":"西方世界的“二元外交体系”，将西方的普遍性还原为一种特殊性，或者说堕落为一种伪普遍性，日本对此的反抗因此获得了一种伦理基础。"},{"book":"枢纽：3000年的中国（新版增订4万字）","author":"施展","text":"大唐是个普遍帝国，对多种异质性要素的兼容使帝国理念变得抽象，以致普遍帝国本身丧失了属民的认同，也丧失了其担纲者，终致帝国瓦解。"},{"book":"枢纽：3000年的中国（新版增订4万字）","author":"施展","text":"中国的超大规模过剩人口，只有在中国作为封闭经济体的情况下，才会导向“内卷化”的结果，一旦加入开放的世界经济体系，反倒会成为中国的竞争优势。"},{"book":"枢纽：3000年的中国（新版增订4万字）","author":"施展","text":"然而在黑格尔式辩证法中，正是这段历史为中国的自我意识的不断充实提供了基础。"},{"book":"坏血：一个硅谷巨头的秘密与谎言","author":"约翰·卡雷鲁","text":"西奥多·罗斯福：“有机会努力去做值得做的事情，这是生活给我们最有价值的奖励。”"},{"book":"当我谈跑步时，我谈些什么","author":"[日]村上春树","text":"萨默赛特·毛姆写道：“任何一把剃刀都自有其哲学。”大约是说，无论何等微不足道的举动，只要日日坚持，从中总会产生出某些类似客观认知的东西来。"},{"book":"精通以太坊：开发智能合约和去中心化应用","author":"安德烈亚斯·M.安东波罗斯","text":"回想一下科学发展的历史，就会发现有很多类似情形，比如蒸汽机发明之后所带来的工业变革推动了控制理论的建立。也有很多原本在理论上可行的东西终于找到了现实中对应的模型，就好比非欧几何找到了相对论。"},{"book":"枪炮、病菌与钢铁（修订版）（睿文馆）","author":"贾雷德·戴蒙德","text":"粮食生产之所以具有决定性的意义，在于它能积累剩余粮食以养活不从事粮食生产的专门人材，同时也在于它能形成众多的人口，从而甚至在发展出任何技术和政治优势之前，仅仅凭借人多就可以拥有军事上的优势。"},{"book":"枪炮、病菌与钢铁（修订版）（睿文馆）","author":"贾雷德·戴蒙德","text":"大的单位可能拥有对各个小的单位的某种优势，如果—这是一个大大的“如果”—这些大单位能够解决因规模变大而带来的问题"},{"book":"枪炮、病菌与钢铁（修订版）（睿文馆）","author":"贾雷德·戴蒙德","text":"政府和宗教就是这样结合起来发挥了作用，它们是产生历史最广泛模式的4组主要的直接动力之一，另外3组动力是病菌、文字和技术。"},{"book":"枪炮、病菌与钢铁（修订版）（睿文馆）","author":"贾雷德·戴蒙德","text":"人们通常使用的都是循环论证：由于存在技术上的差异，因此可以推断出相应的意识形态上的差异。"},{"book":"枪炮、病菌与钢铁（修订版）（睿文馆）","author":"贾雷德·戴蒙德","text":"这种对近似原因的分析是本书中容易做到的部分；困难的部分是确定终极原因，因为正是终极原因产生了近似原因，产生了实际结果，而不是产生可能相反的结果，即阿塔瓦尔帕到马德里俘虏了西班牙国王查理一世。"},{"book":"枪炮、病菌与钢铁（修订版）（睿文馆）","author":"贾雷德·戴蒙德","text":"不同民族的历史遵循不同的道路前进，其原因是民族环境的差异，而不是民族自身在生物学上的差异。"},{"book":"枪炮、病菌与钢铁（修订版）（睿文馆）","author":"贾雷德·戴蒙德","text":"不同民族之间相互作用的历史，就是通过征服、流行病和灭绝种族的大屠杀来形成现代世界的。"},{"book":"事实（比尔·盖茨推荐）","author":"汉斯·罗斯林 欧拉·罗斯林 安娜·罗斯林·罗朗德","text":"寻找系统，而不是寻找英雄。"},{"book":"事实（比尔·盖茨推荐）","author":"汉斯·罗斯林 欧拉·罗斯林 安娜·罗斯林·罗朗德","text":"风险=危险程度×发生的可能性。你面临的真实风险，并不取决于它看起来多么吓人，而在于两个因素：危险的程度和发生的概率。"},{"book":"事实（比尔·盖茨推荐）","author":"汉斯·罗斯林 欧拉·罗斯林 安娜·罗斯林·罗朗德","text":"统计数据经常为政治目的而服务，从而以一些比较夸张的形式体现出来。"},{"book":"事实（比尔·盖茨推荐）","author":"汉斯·罗斯林 欧拉·罗斯林 安娜·罗斯林·罗朗德","text":"当人们思考的时候，人们会持续地并且本能地通过他们的世界观来猜测和理解这个世界。所以如果你的世界观是错的，那么你就会系统性地做出错误的猜测。"},{"book":"文明的故事1：东方的遗产","author":"威尔·杜兰特","text":"印度教宗教思想的最后真言便是解脱（Moksha）——先从欲望，再从生命得到解脱。涅槃可以是其中任一种，但两者皆有时，最为完满。"},{"book":"文明的故事1：东方的遗产","author":"威尔·杜兰特","text":"生命真正的问题既然不在于痛苦而在于不该遭受的痛苦，印度的宗教给悲哀和痛苦赋予了意义和价值，借此缓和了人类的悲剧。"},{"book":"文明的故事1：东方的遗产","author":"威尔·杜兰特","text":"基于贫与富、乡与城的冲突，所罗门死后巴勒斯坦便一分为二：北方称以法莲￼，以撒马利亚（Samaria）为都；南方称犹太，以耶路撒冷为都。南北对立，苦战不休，犹太从此即趋式微。"},{"book":"文明的故事1：东方的遗产","author":"威尔·杜兰特","text":"文明￼是增进文化创造的社会秩序。它包含了四大因素：经济的供应、政治的组织、伦理的传统及对知识与艺术的追求。"},{"book":"文明的故事2：希腊的生活","author":"威尔·杜兰特","text":"第欧根尼·拉尔修说：毕达哥拉斯是第一个说地球是圆的人，并且给了世界一个kosmos（英文为Cosmos，指“井然有序的宇宙”，与“混沌”相对）的名称。"},{"book":"文明的故事2：希腊的生活","author":"威尔·杜兰特","text":"正如大多数的希腊殖民地一样，开始是地主专政的寡头政治，然后经过由中产阶级所资助的独裁，最后到了活跃而动乱频繁的民主。"},{"book":"文明的故事3：恺撒与基督","author":"威尔·杜兰特","text":"像这样的行业，几乎宣布了哲学的死刑。因为哲学已为修辞学的浪潮所吞没，当它学习表达时已停止了思考。"},{"book":"文明的故事3：恺撒与基督","author":"威尔·杜兰特","text":"罗马刚好完成柏拉图和我们所知道的政体演变说：君主政体、贵族政体、寡头政治、民主政治、革命混乱、独裁政治。在历史回轮的运转中，一个自由的世纪已经过去，接下来的是一个纪律的世纪了。"},{"book":"文明的故事11：拿破仑时代","author":"威尔·杜兰特 阿里尔·杜兰特","text":"他必须致力于和平的统治，如果他只想模仿我，并非出于绝对必要，再度重启战端，那他除了模仿外，将一无所是。要重新开始我的事业，一定要假定我一无所成，要完成它。"},{"book":"文明的故事11：拿破仑时代","author":"威尔·杜兰特 阿里尔·杜兰特","text":"他维护、发扬了法律之前人人平等的理想。他所建立的平等是机会的平等，而不是成就和能力的平等，这是不可能实现的。社会给予所有人教育、经济、政治的机会，不论上智下愚，均有同等的机会发展自己的潜能。"},{"book":"文明的故事11：拿破仑时代","author":"威尔·杜兰特 阿里尔·杜兰特","text":"在18世纪的欧洲，法国是人口最稠密、经济实力最强大的国家。"},{"book":"理解媒介：论人的延伸","author":"马歇尔·麦克卢汉","text":"有人已经指出，在瞎子的王国里，独眼龙当不了国王。他将被认为是受幻觉支配的狂人。在高度偏重视觉的文化里，传达空间形式的非视觉属性，和向瞎子解释可视性是同样困难的。"},{"book":"理解媒介：论人的延伸","author":"马歇尔·麦克卢汉","text":"借助置身于我们外延的中枢神经系统，借助电子媒介，我们创造了一种动力。有了这一动力以后，虽然一切技术仅仅是手、足、齿和体温控制系统的延伸，虽然一切技术包括城市都是人的延伸，可是它们都会转换成信息系统。"},{"book":"我为什么要写作（小经典系列）","author":"乔治·奥威尔","text":"对当时的正统思想口头上表示奉承是容易做到的，但任何有意义的作品只有在你感到所说的话是真实的时候才能产生；没有这个，就不会有创作的冲动。"},{"book":"我为什么要写作（小经典系列）","author":"乔治·奥威尔","text":"而上层精华分子真正令人羡慕的事是，他们年轻的时候就很富有。"},{"book":"一九八四（译文经典）","author":"乔治·奥威尔","text":"不是由于你的话有人听到了，而是由于你保持清醒的理智，你就继承了人类的传统。"},{"book":"上帝掷骰子吗？：量子物理史话（升级版）","author":"曹天元","text":"具体的细节读者们可以不用理会，只要把握其中的精髓：一个复杂系统的状态可以看成某种高维空间中的一个点或者一个矢量。"},{"book":"重新定义公司：谷歌是如何运营的","author":"埃里克·施密特 乔纳森·罗森伯格等","text":"“共识”并不是指人人都必须同意，而是指共同达成对公司最有利的决策，并围绕决策共同努力。"},{"book":"重新定义公司：谷歌是如何运营的","author":"埃里克·施密特 乔纳森·罗森伯格等","text":"所谓平台，从本质上来说就是一套能够吸引供应商及用户群，从而形成多边市场￼的产品或服务。"},{"book":"繁荣与衰退","author":"艾伦·格林斯潘 阿德里安·伍尔德里奇","text":"“在创设一个以人管人的政府时，面临的最大的问题就是：你首先要赋予这个政府治理民众的权力，其次要强制这个政府约束自己。”"},{"book":"繁荣与衰退","author":"艾伦·格林斯潘 阿德里安·伍尔德里奇","text":"企业帮助市场活动提升质量有两种方式：一种是通过创设企业内部的管理层架构协调从生产原材料到工业产品的生产流程；另一种则是通过赋予企业家在特定产品和生产流程上下赌注的权利，引导未来发展的方向。"},{"book":"繁荣与衰退","author":"艾伦·格林斯潘 阿德里安·伍尔德里奇","text":"1865—1914年，美国社会出现了几项极其重要的新发明：一种新的基本生产原材料（钢铁）、一种新的基础燃料（石油）、一种新的动力来源（电力）、一种新的个人交通工具（汽车）、一种新的沟通工具（电话）。"},{"book":"繁荣与衰退","author":"艾伦·格林斯潘 阿德里安·伍尔德里奇","text":"法国启蒙思想家孟德斯鸠早在1748年出版的《论法的精神》中就说过，天气决定命运。"},{"book":"从一到无穷大（果麦经典）","author":"乔治·伽莫夫","text":"在1到大于1的任意自然数N的区间内，质数所占的百分比约等于N的自然对数的倒数。"},{"book":"探路之役：1978～1992年的中国经济改革","author":"萧冬连","text":"判断的标准，应该主要看是否有利于发展社会主义社会的生产力，是否有利于增强社会主义国家的综合国力，是否有利于提高人民的生活水平。"},{"book":"爱因斯坦传（全2册）","author":"沃尔特·艾萨克森","text":"指控其反复无常肯定会让爱因斯坦感到好笑。对于一个科学家来说，当事实改变时改变他的学说并不代表软弱。"},{"book":"爱因斯坦传（全2册）","author":"沃尔特·艾萨克森","text":"当我判断一个理论时，”他告诉朋友霍夫曼，“我就问我自己，如果我是上帝，我是否会以这种方式设计世界。”"},{"book":"爱因斯坦传（全2册）","author":"沃尔特·艾萨克森","text":"1666年以来，科学界再也没有出现过类似的年份。当时牛顿隐居在伍尔索普（Woolsthorpe）乡下躲避正在剑桥肆虐的瘟疫，在此期间他发明了微积分，对光谱进行了分析，还提出了万有引力定律。"},{"book":"论自由","author":"约翰·穆勒","text":"在不违效率的前提下，尽最大限度地让权力分散；同时由一个集散中枢尽最大可能地让信息得到收集和传播。"},{"book":"论自由","author":"约翰·穆勒","text":"政治理论和哲学理论，也跟人一样，常常因成功而把失败所能遮掩的错误和缺陷暴露出来。当平民政府还只是一个梦想，或者还只是作为见诸史书的远古遗事之时，无需限制人们施于自己的权力似乎就是不证自明的公理。"},{"book":"论自由","author":"约翰·穆勒","text":"人类最为丰富的多样性发展，有着绝对而根本的重要性。"},{"book":"20世纪思想史：从弗洛伊德到互联网（世界思想史）","author":"彼得·沃森","text":"“作为资本主义的主要成就，西方文明所积累的数量惊人的社会财富没有被用来构建更加高雅和人性化的社会，却被越来越多地用在防止这种社会的形成上”。"},{"book":"呼吸（译林幻系列）","author":"特德·姜","text":"因为许多人不假思索地把各种事件归为奇迹，结果贬低了奇迹的价值。"},{"book":"政治秩序的起源：从前人类时代到法国大革命","author":"弗朗西斯·福山","text":"一个学者的敏锐性和洞察力，从来就更多取决于他通过问题意识组织和提炼知识的能力，而不仅仅是对知识本身的掌握。"},{"book":"政治秩序的起源：从前人类时代到法国大革命","author":"弗朗西斯·福山","text":"日益专业化、精细化、技术化"},{"book":"政治秩序的起源：从前人类时代到法国大革命","author":"弗朗西斯·福山","text":"保持思想的开放性是面对复杂与高速变化的时代的唯一方案。但更重要的是，我们希望保持一种非功利的兴趣：对世界的丰富性、复杂性本身充满兴趣，真诚地渴望理解他人的经验。"},{"book":"奥古斯都","author":"约翰·威廉斯","text":"正如我的自述得去适应这样一种公共的必要性，我这一生也如此。"},{"book":"硅谷之火：个人计算机的诞生与衰落（第3版）","author":"迈克尔·斯韦因 保罗·弗赖伯格","text":"这些发烧友清楚地知道，他们所引燃的不仅是一场技术革命，还是一场社会革命。"},{"book":"硅谷之火：个人计算机的诞生与衰落（第3版）","author":"迈克尔·斯韦因 保罗·弗赖伯格","text":"程序员对自己苦心孤诣获得的知识都会有所保留，但盖茨却懂得如何利用自己的年少来赢得TRW公司中年长专家的欢心，让他们倾囊相授。正如盖茨自己所说，他们认为自己“不具威胁性”，毕竟他只是个孩子。"},{"book":"下一站火星","author":"毛新愿","text":"阿波罗8号拍下的地球从月球表面升起——《地出》。事实上，月球被地球潮汐锁定，永远只有一面对着地球，在月球表面不可能看到地球升起。由于飞船是相对月球在飞行，宇航员才有可能拍下这让人感到无比震撼的场景"},{"book":"剧变：人类社会与国家危机的转折点","author":"贾雷德·戴蒙德","text":"一种危机解决方法——借鉴他人/他国在面临类似危机时的处理模式"},{"book":"剧变：人类社会与国家危机的转折点","author":"贾雷德·戴蒙德","text":"问题存在的意义就是被解决。"},{"book":"剧变：人类社会与国家危机的转折点","author":"贾雷德·戴蒙德","text":"这种共同的信仰使日本人克服了明治时代的压力，虽然有些时候他们在如何最好地保障日本的未来方面有些异议，但他们从未怀疑自己国家的价值。"},{"book":"剧变：人类社会与国家危机的转折点","author":"贾雷德·戴蒙德","text":"明治时代的日本领导者和20世纪三四十年代的日本领导者在知识储备方面的差异和进行诚实的自我评估的能力差异"},{"book":"剧变：人类社会与国家危机的转折点","author":"贾雷德·戴蒙德","text":"明治政府领导者在面对真实的或潜在的敌人时，非常善于收买人心、收编委派或调停和解。"},{"book":"剧变：人类社会与国家危机的转折点","author":"贾雷德·戴蒙德","text":"西方力量所指的不仅仅是枪炮武器本身，还有那些为西方国家提供不竭动力的、更为深远的政治和社会改革。"},{"book":"剧变：人类社会与国家危机的转折点","author":"贾雷德·戴蒙德","text":"发现并界定亟待解决的问题"},{"book":"转型中的地方政府：官员激励与治理(第二版)","author":"周黎安","text":"第四种是资源的分散化。当委托人掌握的资源远远不足以救助处于困境中的代理人时，他关于不救助的事前承诺就可以置信了。"},{"book":"转型中的地方政府：官员激励与治理(第二版)","author":"周黎安","text":"“强制意义上的可信承诺”则主要通过以下方式来保证： 第一种方式是信息的分散化。"},{"book":"转型中的地方政府：官员激励与治理(第二版)","author":"周黎安","text":"这些问题在本质上均与政府的职能缺位有关，是属地化的行政发包制、政治锦标赛模式与市场化进程、人们日益增长的“公正公平”的诉求之间的内在冲突，因而可以理解为中国传统政府治理体制所面临的深层次问题。"},{"book":"转型中的地方政府：官员激励与治理(第二版)","author":"周黎安","text":"中国地方官员的治理的核心要素是地方分权、逐级发包、财政分成、晋升竞争四个方面。"},{"book":"转型中的地方政府：官员激励与治理(第二版)","author":"周黎安","text":"高度集中的人事任命权是行政逐级发包的制度基础，也是整合高度集权与高度分权的一个关键。"},{"book":"转型中的地方政府：官员激励与治理(第二版)","author":"周黎安","text":"在传统的小农经济的基础上，国家为了实现重化工业化战略，不得不依靠汲取农业领域的剩余，采取人为扭曲的价格体系（如人为压低农产品价格、抬高工业品价格）实现工业化所需的积累。"},{"book":"转型中的地方政府：官员激励与治理(第二版)","author":"周黎安","text":"如果参与人多于两人，形成多人竞争，那么，就有可能产生某些人形成局部联盟、与另外的竞争对手展开竞争的“报团竞争”的情况，即我们通常所说的“远交近攻”战略。"},{"book":"转型中的地方政府：官员激励与治理(第二版)","author":"周黎安","text":"事实上，只要水权或污染权的法律界定是清晰的，一个水权和污染权的交易市场就会内生地出现。在我国浙江就出现了水权交易市场的雏形。这个水权或污染权交易市场的有效运转必须要求不受地方官员的过多干预。"},{"book":"转型中的地方政府：官员激励与治理(第二版)","author":"周黎安","text":"对于混合竞争来说，只有当合作的净结果不改变地方官员的相对位次时，合作收益才可能实现，否则合作很难发生。"},{"book":"转型中的地方政府：官员激励与治理(第二版)","author":"周黎安","text":"当1990年中央决定开发浦东的时候，就像以前任何一次设立经济特区一样，只给政策不给钱，中央并没有直接注入多少资金，因此上海需要大量的资金投入改造和建设公共基础设施。"},{"book":"转型中的地方政府：官员激励与治理(第二版)","author":"周黎安","text":"地方政府的层层加码也经常使得国家层面制定的一些规划和计划失去长期性指导意义。"},{"book":"转型中的地方政府：官员激励与治理(第二版)","author":"周黎安","text":"与所有其他经济体相比较，中国市场经济最独具特色的方面就是官场竞争与市场竞争的密切互动和高度结合，这个双层市场结构驱动着中国经济的运行。"},{"book":"转型中的地方政府：官员激励与治理(第二版)","author":"周黎安","text":"对于晋升机会渺茫的人来说，锦标赛体制将失去正向的激励效应。"},{"book":"转型中的地方政府：官员激励与治理(第二版)","author":"周黎安","text":"由于他们是这种激励制度的成功者，维护其正常运行自然符合他们自身的偏好和既得利益。"},{"book":"转型中的地方政府：官员激励与治理(第二版)","author":"周黎安","text":"与财政包干制相比，政治锦标赛的一个突出优点是奖励承诺比较可信。"},{"book":"转型中的地方政府：官员激励与治理(第二版)","author":"周黎安","text":"为了最大限度获得地方政府的支持，中央在新体制下对过去的既得利益格局进行了照顾和维持。"},{"book":"转型中的地方政府：官员激励与治理(第二版)","author":"周黎安","text":"在中国，最吊诡的事实是，市场化本身如果离开了有为政府几乎寸步难行，市场化所需的“去政府化”和“去行政化”是通过政府推动甚至“自我革命”来完成的。"},{"book":"转型中的地方政府：官员激励与治理(第二版)","author":"周黎安","text":"Easterly（2005）反思了半个世纪以来发展中国家的经济增长过程，认为强调“把价格搞对”只是一个方面，关键是“把激励搞对”，如何赋予广大的参与人合适的激励，而其中政府的激励尤其重要。"},{"book":"转型中的地方政府：官员激励与治理(第二版)","author":"周黎安","text":"政府治理的核心就在于设计一个合理的激励机制，阻止自由裁量权演变成合法伤害权，将“掠夺之手”转化成“帮助之手”，实现政府官员个人利益与政府治理目标之间的激励兼容。"},{"book":"转型中的地方政府：官员激励与治理(第二版)","author":"周黎安","text":"中央和地方政府在目标函数与约束条件的结构性差异，决定了两者之间在激励和行为方面的诸多不同。如果要深刻理解地方政府在中国改革开放和经济发展过程中所扮演的独特角色，就必须从这些结构性差异出发。"},{"book":"转型中的地方政府：官员激励与治理(第二版)","author":"周黎安","text":"他提出的“三层法”是一种规范的分析，即回答“应该怎样”的问题。为了理解中国地方政府的独特地位，我们还需要进一步做实证的分析，回答“是什么”和“为什么”的问题。"},{"book":"一生的旅程：迪士尼CEO自述","author":"罗伯特·艾格 乔尔·洛弗尔","text":"为了开始搭建新的商业模型，我们是否有胆识开始剥离那些仍处盈利状态的业务？我们能够自我颠覆吗？在公司实行现代化和变革的过程中，损失将不可避免，华尔街是否能够容忍呢？"},{"book":"一生的旅程：迪士尼CEO自述","author":"罗伯特·艾格 乔尔·洛弗尔","text":"我没有为了得到结果而继续努力推进，也没有对自己做出的决定进行辩解，我需要做的，就是控制损失，从错误中汲取经验，然后赶紧继续前进。"},{"book":"一生的旅程：迪士尼CEO自述","author":"罗伯特·艾格 乔尔·洛弗尔","text":"专心致志、精力充沛、全心投入，更加愿意敞开胸怀，相信我们的这个想法（我相信还有很多别的想法）终会实现。"},{"book":"一生的旅程：迪士尼CEO自述","author":"罗伯特·艾格 乔尔·洛弗尔","text":"这又是宝贵的一课：史蒂夫很擅长衡量一件事情的方方面面，不允许优点被缺点掩盖住，在他想要争取的事情上更是如此。这是他的一个很突出的特质。"},{"book":"一生的旅程：迪士尼CEO自述","author":"罗伯特·艾格 乔尔·洛弗尔","text":"史蒂夫说他很喜欢白板练习，无论谁手握着水笔，都可以随心所欲地将愿景中的所有构思、设计以及计算完整涂画出来。"},{"book":"一生的旅程：迪士尼CEO自述","author":"罗伯特·艾格 乔尔·洛弗尔","text":"不要让你的自尊心阻碍你作出最佳抉择。"},{"book":"一生的旅程：迪士尼CEO自述","author":"罗伯特·艾格 乔尔·洛弗尔","text":"概率小得可怜，但尽管如此，我也必须得做出尝试。"},{"book":"一生的旅程：迪士尼CEO自述","author":"罗伯特·艾格 乔尔·洛弗尔","text":"觉得这些得之不易的教训，不仅关乎韧性和坚忍的重要，也关乎不为你无法控制的事情感到愤怒和焦虑的必要。"},{"book":"一生的旅程：迪士尼CEO自述","author":"罗伯特·艾格 乔尔·洛弗尔","text":"我从未在智力上被如此激荡过——至少从商务智能上来说，我从未对公司的运营方式以及需要解决的问题进行过如此深刻的思考，也从未在如此短的时间内处理过如此多的信息。"},{"book":"一生的旅程：迪士尼CEO自述","author":"罗伯特·艾格 乔尔·洛弗尔","text":"一家企业的文化是由许多因素构成的，而其中最重要的一个因素，便是清楚和重复地传达你的优先事项。"},{"book":"一生的旅程：迪士尼CEO自述","author":"罗伯特·艾格 乔尔·洛弗尔","text":"“你不能以在任者的身份赢得这场竞选，”他说，“如果处于守势，你就赢不了。你的唯一关注点是未来，过去已经过去了。”"},{"book":"一生的旅程：迪士尼CEO自述","author":"罗伯特·艾格 乔尔·洛弗尔","text":"对于一位领导者而言，乐观精神是必不可少的一项特质"},{"book":"一生的旅程：迪士尼CEO自述","author":"罗伯特·艾格 乔尔·洛弗尔","text":"他不仅能在把控大局的同时注意微小细节，还能思考二者会相互产生何种影响，这种能力不仅让我印象深刻，对我的个人成长更是有着不可估量的价值。"},{"book":"一生的旅程：迪士尼CEO自述","author":"罗伯特·艾格 乔尔·洛弗尔","text":"重点在于你觉得哪种方法适用于当下——有的时候，更加民主的方法不仅能帮助你得到最好的收效，也有利于提高士气；而有的时候，你或许有足够的把握，即便面对争议，你也愿意坚持做一名独裁者。"},{"book":"一生的旅程：迪士尼CEO自述","author":"罗伯特·艾格 乔尔·洛弗尔","text":"抓住其中的平衡点很重要——把手中的工作做好；有耐心；寻找能够有所贡献的机会，并从中实现拓展和成长；利用你的态度、活力和专注，让自己成为一个上司在机遇出现时觉得必须将之交付于你的人。"},{"book":"一生的旅程：迪士尼CEO自述","author":"罗伯特·艾格 乔尔·洛弗尔","text":"另外，任何让你认识到宇宙并不围着你转的事情，都是好事。"},{"book":"一生的旅程：迪士尼CEO自述","author":"罗伯特·艾格 乔尔·洛弗尔","text":"我发现，人们往往会把注意力放在细枝末节上，以此来掩盖他们对清晰连贯的大格局缺乏把握。"},{"book":"一生的旅程：迪士尼CEO自述","author":"罗伯特·艾格 乔尔·洛弗尔","text":"这并不意味着经验不重要，按照两人的话说，他们这是在“为脑力押注”，他们相信，如果把人才安排在能够成长的职位上，即便这是当事人并不熟悉的领域，局面也终究会打开。"},{"book":"一生的旅程：迪士尼CEO自述","author":"罗伯特·艾格 乔尔·洛弗尔","text":"发自内心的真诚友善与职业上的争强好胜并不是相互排斥的。更进一步地说，真正的诚信——对自己有自知之明，对正误有明确分辨，并将此作为行为的准则——本身就是一件秘密武器"},{"book":"一生的旅程：迪士尼CEO自述","author":"罗伯特·艾格 乔尔·洛弗尔","text":"慎思。慎思是优秀领导力中最被人低估的一个因素。它指的是获取知识，使得提出的观点或作出的决定更具可信度，也更趋于正确。简而言之，这个原则就是潜心花时间去孕育富有见地的观点。"},{"book":"一生的旅程：迪士尼CEO自述","author":"罗伯特·艾格 乔尔·洛弗尔","text":"乐观。一位优秀的领导人最为重要的特质之一就是乐观，也就是对于可能获得的成就抱有符合现实的热情。即便是在困难的抉择和不甚理想的结果面前，一位乐观的领导者也不会落入消极的情绪之中。"},{"book":"一生的旅程：迪士尼CEO自述","author":"罗伯特·艾格 乔尔·洛弗尔","text":"工作的日子充满了挑战和变化，也是一场关于如何归类处理的永无止境的历练。"},{"book":"一生的旅程：迪士尼CEO自述","author":"罗伯特·艾格 乔尔·洛弗尔","text":"我一般不会在事情出差错时太过焦虑。我习惯把坏消息当成可以处理和解决的问题，是可以主动掌控的东西，而不是降临于身的事情。"},{"book":"一生的旅程：迪士尼CEO自述","author":"罗伯特·艾格 乔尔·洛弗尔","text":"在这种高压时刻，分享无法对其他任何人透露的信息而形成的情谊是坚不可摧的。"},{"book":"一生的旅程：迪士尼CEO自述","author":"罗伯特·艾格 乔尔·洛弗尔","text":"打造这座乐园不仅为我上了一堂地缘政治课，也是一个不断在全球扩张的可能性以及文化帝国主义的危险性之间找寻平衡点的过程。"},{"book":"李光耀观天下（精装版）","author":"李光耀","text":"命运总在最关键的转角处对着我微笑。我们被逐出马来西亚时，一下子没了腹地，这个地方很可能就这么垮了。但是世界的整合以及全球化过程，让我们有机会找到自己的立足之地。"},{"book":"李光耀观天下（精装版）","author":"李光耀","text":"我预见社会规范在这方面的改变将会非常缓慢，而政府不可能反而走在人们前头。"},{"book":"李光耀观天下（精装版）","author":"李光耀","text":"到头来，决定国家实力的是工业产能，而不是军舰和枪炮的多寡。你若光有军备，却没有强大的经济基础作为后盾，即便你能为战争做更好的准备，也未必能持久战斗下去。"},{"book":"李光耀观天下（精装版）","author":"李光耀","text":"您似乎比较看重共和党总统，这是不是一种巧合？ 答：可能是因为他们比较注重外交政策。不是因为他们是共和党人，而是因为他们对大国在外交政策上应扮演什么角色比较有意识。"},{"book":"卡拉马佐夫兄弟（套装上下册）（陀思妥耶夫斯基文集2015）","author":"陀思妥耶夫斯基","text":"你没有下来是因为你仍然不愿通过奇迹来役使人，你苦苦追求的是自由信仰，而不是奇迹信仰。你渴望自由的爱，而不是奴隶面对彻底把他镇住的权威表现出来的谄媚性狂喜。"},{"book":"卡拉马佐夫兄弟（套装上下册）（陀思妥耶夫斯基文集2015）","author":"陀思妥耶夫斯基","text":"作者不应该放弃哪怕是唯一的听众"},{"book":"卡拉马佐夫兄弟（套装上下册）（陀思妥耶夫斯基文集2015）","author":"陀思妥耶夫斯基","text":"凡是您觉得自己内心存在什么要不得的想法，那么，您自己发现这一点本身已经在一定程度上把它净化了。"},{"book":"区块链实战：从技术创新到商业模式","author":"冒志鸿 陈俊","text":"真正的智能合约很难形成，因为真正智能的合约需要考虑到所有情况。换言之，要求合约去信任化，意味着合约完全不能有任何模棱两可的空间。"},{"book":"区块链实战：从技术创新到商业模式","author":"冒志鸿 陈俊","text":"计算机系统的安全性其实取决于系统本身的安全性设计，和具体使用的某种技术并无必然联系。因此，当你听到“因为采用了区块链技术，所以我们的方案更安全”这样的说法时，需要格外警惕。"},{"book":"区块链实战：从技术创新到商业模式","author":"冒志鸿 陈俊","text":"大多数这类公司实际上都是服务的聚合者，通过扮演中间人的角色汇聚服务并加以出售。实际上，这类共享经济公司的成功恰恰来自它们的不共享。"},{"book":"区块链实战：从技术创新到商业模式","author":"冒志鸿 陈俊","text":"区块链将有助于构建真正的去中心化应用，但去中心化应用未必一定需要区块链，在区块链诞生之前繁荣的很多P2P应用都有非常好的去中心化特性，但它们并不是区块链，也没有使用区块链技术。"},{"book":"区块链实战：从技术创新到商业模式","author":"冒志鸿 陈俊","text":"也许有人问，如果代码开源不是也可以做到公开吗？是的，开源的代码是公开的，但并不能做到可验证。虽然你能看到项目的源代码，但不能保证真正执行的就是源代码对应的程序。"},{"book":"区块链实战：从技术创新到商业模式","author":"冒志鸿 陈俊","text":"起初，区块链是为支持数字货币交易而开发；如今，人们正在探索将区块链应用于其他领域，如金融服务、软件安全、物联网、零件跟踪（供应链）、资产管理、智能合约、身份验证等。"},{"book":"货币未来：从金本位到区块链","author":"赛费迪安·阿莫斯","text":"让人们放弃使用一项技术的方式不是禁止它，而是发明更好的替代品，消除人们对它的需求。"},{"book":"货币未来：从金本位到区块链","author":"赛费迪安·阿莫斯","text":"虽然大多数人认为市场体系统治着资本主义经济，现实是，没有资本市场的自由，资本主义制度就无法运转。资本的价格是通过供求关系产生的，而资本家的决策是由准确的价格信号驱动的。"},{"book":"货币未来：从金本位到区块链","author":"赛费迪安·阿莫斯","text":"经济学家汉斯-赫尔曼·霍普（Hans-Hermann Hoppe）解释说，一旦时间偏好下降到足以让储蓄、资本或耐久消费品的出现成为可能，时间偏好就会有进一步下降的趋势，于是“文明进程”就启动了。"},{"book":"货币未来：从金本位到区块链","author":"赛费迪安·阿莫斯","text":"政府负责货币供给的问题在于，通货的硬度完全取决于那些主张不扩大货币供给的人的政治实力。货币硬度只来自政治约束，而在物理上、经济上或自然上，政府生产多少货币完全没有任何限制。"},{"book":"货币未来：从金本位到区块链","author":"赛费迪安·阿莫斯","text":"所有认为自己对比特币的拒绝只是因为事不关己的人，都应该牢记这个重大的历史教训。历史向我们证明，如果其他人持有的通货比你的硬，你根本无法置身事外。"},{"book":"货币未来：从金本位到区块链","author":"赛费迪安·阿莫斯","text":"比特币有可能以失败告终，即便如此，人们还可以重新推出一个类似的去中心化的货币，因为我们已经知道了如何发明和运作这样一种去中心化的货币体制。"},{"book":"把自己作为方法","author":"项飙 吴琦","text":"而自我证明这个概念是个悖论。要证明自己其实就是没有自己，意思是说，要通过已经预设的原则和标准、别人的逻辑和流程来证明自己的存在，其实是取悦别人，把自己搞没有了。"},{"book":"把自己作为方法","author":"项飙 吴琦","text":"很明显，对比来看，就能看到法律对谁的声音更敏感。"},{"book":"把自己作为方法","author":"项飙 吴琦","text":"那不是塑造一个有机的共同体，而是塑造一个标签。"},{"book":"把自己作为方法","author":"项飙 吴琦","text":"很遗憾，在现代性之下，“边缘”和“中心”变成一组对立关系，中国人又有那么强的中心情结，觉得边缘的生活不值得过，造成极大的焦虑。"},{"book":"把自己作为方法","author":"项飙 吴琦","text":"那时候只顾着生存，把那一年过完。当然也是很难的，每天都绷得紧紧的，问题是在后来比较从容的情况下出现的，要寻找意义，反而更难处理。"},{"book":"把自己作为方法","author":"项飙 吴琦","text":"理论不在于新不新、深不深，更不在于正确不正确，而是能不能形成沟通性。可沟通性非常重要，哪怕是一个浅显的理论，但它一下子调动起对方的思想，把对方转变成一个新的主体，那这个理论就是革命性的。"},{"book":"把自己作为方法","author":"项飙 吴琦","text":"阅读功力跟年纪很有关系，必须在一定的年纪以一定的力度去阅读，才能达到那种能力。"},{"book":"把自己作为方法","author":"项飙 吴琦","text":"抓住一个题目，迅速进入分析，把一些我们习以为常的概念和现象重新问题化，经过思维的整理之后，再放回经验的抽屉。"},{"book":"把自己作为方法","author":"项飙 吴琦","text":"人们一心奔向结论，奔向情绪性的抒发和感慨，忽视了凡事都有一个具体劳动、结果难测的过程。"},{"book":"重走：在公路、河流和驿道上寻找西南联大","author":"杨潇","text":"“高调”可能是官僚主义，可能是何不食肉糜，也可能是少年意气，但在某些特殊的时刻，它还可能是绝望者的武器：绝不停止鼓劲，绝不停止希望，甚至绝不停止幻想。"},{"book":"重走：在公路、河流和驿道上寻找西南联大","author":"杨潇","text":"“这一次抗战的最大结果：为社会，是替理想与实际造了一条沟渠；为个人，是在纯朴的心灵与敏活的官能开造了一条桥梁，轰雷掣电的给予了将来负大任的人们一个动心忍性的大锻炼。”"},{"book":"重走：在公路、河流和驿道上寻找西南联大","author":"杨潇","text":"乱世读书是中国知识分子几乎发乎本能的世界观，更是他们解决内心危机的方法论。"},{"book":"独裁者手册","author":"布鲁斯·布鲁诺·德·梅斯奎塔 阿拉斯泰尔·史密斯","text":"最高程度的腐败的确属于非自由的、依赖小联盟的政权。但这并不等于说依赖大型联盟就能使政府免于腐败。它甚至并不表明依赖大型联盟的政权花在腐败方面的钱绝对比独裁国家少。"},{"book":"独裁者手册","author":"布鲁斯·布鲁诺·德·梅斯奎塔 阿拉斯泰尔·史密斯","text":"清洁水资源和技术并不偏爱民主国家，而是民主国家偏爱确保其饮用水是清洁的。"},{"book":"独裁者手册","author":"布鲁斯·布鲁诺·德·梅斯奎塔 阿拉斯泰尔·史密斯","text":"好的统治形式要求税收只能被用于解决市场无法提供的东西，比如国防和大型公共基础设施建设。征收相对少的税会鼓励人们过一种更富生产性的生活，创造更大的饼。"},{"book":"独裁者手册","author":"布鲁斯·布鲁诺·德·梅斯奎塔 阿拉斯泰尔·史密斯","text":"它们的政策差异是源于他们的领导人在应付各自的可相互替代者、有影响者和不可或缺者三维结构时面对的激励机制不同。"},{"book":"独裁者手册","author":"布鲁斯·布鲁诺·德·梅斯奎塔 阿拉斯泰尔·史密斯","text":"政府都一个样。差别只在于选择人和致胜联盟维度。这些维度限制或允许领导人为了保住权位能做和应该做什么。限制或允许的程度取决于选择人集团和致胜联盟如何相互作用。"},{"book":"独裁者手册","author":"布鲁斯·布鲁诺·德·梅斯奎塔 阿拉斯泰尔·史密斯","text":"当债务超出了偿债能力，对领导人来说，真正的麻烦不在于必须削减公共开支，而在于他丧失了必要的资源去换取核心支持者的政治忠诚。"},{"book":"新民说·阿尔比恩的种子：美国文化的源与流（上、下）","author":"大卫·哈克特·费舍尔 王剑鹰","text":"这个社会顽强地维持着民主政治，经济上保持资本主义，法律上奉行自由主义，社会里流行个人主义，而文化上则是多元主义。"},{"book":"教父三部曲","author":"马里奥·普佐","text":"他记起教父的叮嘱，说他可以创造出自己想要的生活。只要知道自己想要什么，多半就能心想事成。"},{"book":"运气的诱饵","author":"娜塔莎·道·舒尔","text":"这种由机器带来的速度感，提供了一种可预测性，让他的赌博过程更有结构和规程，风险于是变成了节奏。赌博者只要保持自己速度稳定，就能一直悬置在迷境模式之中。"},{"book":"有限与无限的游戏：一个哲学家眼中的竞技世界","author":"[美]詹姆斯·卡斯","text":"传奇化的情况下，一个人选择成为母亲；演戏的情况下，一个人扮演起母亲的角色。"},{"book":"有限与无限的游戏：一个哲学家眼中的竞技世界","author":"[美]詹姆斯·卡斯","text":"无限游戏的规则像对话语言的语法，而有限游戏的规则像辩论的规则。在前者中，规则是让对话继续下去的方式；而在后者中，规则是让别人的讲话终结的方式。"},{"book":"文明的冲突与世界秩序的重建","author":"塞缪尔·亨廷顿","text":"在社会心理学上，差异性理论认为，人们根据在特定的背景下用把自己区别于其他人的东西来界定自己：“一个人根据把他自己区别于其他人的特性，特别是区别于他通常所处的社会环境中的人的特性……来看待自己。"},{"book":"制造消费者：消费主义全球史","author":"安东尼·加卢佐","text":"人们现在能从异化劳动和牺牲中解放出来，但社会对人类的束缚仍然很牢固，现在它通过种种社会制度维持。这就是马尔库塞所谴责的“过度镇压”的非理性和无用，他认为这会最终导致废除它的反抗。"},{"book":"活着为了讲述","author":"[哥]加西亚•马尔克斯","text":"这些书很神秘，不但另辟蹊径，而且往往与传统背道而驰。事实无须证明，只要落笔，即为真实发生，靠的是无可比拟的才华和毋庸置疑的语气。"},{"book":"活着为了讲述","author":"[哥]加西亚•马尔克斯","text":"理论上，这些主观感受很难被理解，但感受过的人会立刻明白。"},{"book":"毛泽东选集（全四卷）","author":"","text":"武器是战争的重要的因素，但不是决定的因素，决定的因素是人不是物。力量对比不但是军力和经济力的对比，而且是人力和人心的对比。"},{"book":"小米创业思考","author":"雷军 徐洁云","text":"能够持续带来新用户沉淀的，才是闭环；能够形成闭环的，才是高质量的增长。"},{"book":"小米创业思考","author":"雷军 徐洁云","text":"《孙子兵法》中说：上下同欲者胜。一支被使命和愿景召唤的团队，其战斗力将远超一支由商业利益集合起来的团体。"},{"book":"小米创业思考","author":"雷军 徐洁云","text":"有时候局部的慢才是全局的快 在互联网思维中，快是一项准则，而不是目的。所以，在具体执行时，我们要防止本末倒置，要以“口碑”为先，以核心目标为先，而不是一味追求表面上的、局部的快。"},{"book":"小米创业思考","author":"雷军 徐洁云","text":"我们要看到，口碑是个标量，而不是矢量，可以帮助衡量评估产品/服务，在微观上也可以作为改善与提升产品/服务的指导参考，但宏观上来看它是产品/服务的成果衡量标尺，而不是前进方向的指挥棒。"},{"book":"小米创业思考","author":"雷军 徐洁云","text":"我也是琢磨了好久才想明白这个道理：好产品不一定能带来口碑，便宜的产品不一定能带来口碑，又好又便宜的产品也不一定能带来口碑，只有超过预期的产品才能带来口碑。"},{"book":"小米创业思考","author":"雷军 徐洁云","text":"毛主席说过，“存地失人，人地皆失；存人失地，人地皆存”。口碑就是业务的有生力量和群众基础，只要有生力量不灭，群众基础不毁，下一款产品操盘得当，依然能够获得成功。"},{"book":"小米创业思考","author":"雷军 徐洁云","text":"产品的发布不是终点，产品的发售也不是终点。互联网方法论告诉我们，产品卖出去时，才是跟用户关系的开始。产品也需要持续更新，一代一代迭代改善，改改改改再改改，是一条没有止境的路。"},{"book":"小米创业思考","author":"雷军 徐洁云","text":"当我们谈论“专注”时，我们究竟在谈什么？我总结了专注的四个核心命题： • 清晰的使命、愿景。 • 深刻的洞察力，了解行业，了解用户需求，找到机会。 • 明确而坚定的目标及与之匹配的能力。 • 克制贪婪，少就是多。"},{"book":"小米创业思考","author":"雷军 徐洁云","text":"“不专注”是根本问题，毕竟只有想清楚做什么，才知道要怎么做，以什么样的组织形式、争取什么样的资源去做。"},{"book":"小米创业思考","author":"雷军 徐洁云","text":"在任何时候，任何商业实体的资源都是有限的，将有限的资源投入足够聚焦的业务线中，才可能形成最大化的竞争力，拿出足够好的产品与服务。"},{"book":"小米创业思考","author":"雷军 徐洁云","text":"这些思考让我最终发现，长期来看，并不存在所谓的纯互联网公司，互联网的特性是一些原本就存在的商业创新或准则在新技术条件下的极致放大，互联网思维是可以应用于互联网时代所有行业的方法论。"},{"book":"小米创业思考","author":"雷军 徐洁云","text":"当时我还不明白，软件是一个工具，互联网提供的是服务，软件完全可以借由互联网的形式和渠道转化为一种面向用户的服务。而这一点，正是金山在2010年后的移动互联网时代重新焕发活力的题眼。"},{"book":"小米创业思考","author":"雷军 徐洁云","text":"MIUI就是用互联网方式做操作系统，是“专注、极致、口碑、快”互联网七字诀的第一次成功验证。"},{"book":"家庭、私有制和国家的起源","author":"恩格斯","text":"利用人类史前史研究的最新成果，进一步丰富历史唯物主义的理论内涵，更加全面深入地阐述人类历史的发展规律。"},{"book":"创造：用非传统方式做有价值的事","author":"托尼·法德尔","text":"这就是关于B2B2C最需要牢记的一点：不管涉及多少企业，最终撑起整个商业模式的还是终端消费者。"},{"book":"创造：用非传统方式做有价值的事","author":"托尼·法德尔","text":"如果你测试的是产品的核心部分，如果其基本功能可以根据A/B测试结果的变化而变化，这只能说明你的产品没有核心。你的产品图景中存在一个空洞，而你只是在用数据填充这个洞。"},{"book":"创造：用非传统方式做有价值的事","author":"托尼·法德尔","text":"人们很容易将对流程、繁文缛节、职能评定，以及办公室政治这些东西的熟稔和真正的个人成长混为一谈。"},{"book":"新机器智能：边缘计算重塑AIoT产业生态","author":"杰夫·霍金斯 桑德拉·布莱克斯利","text":"如果我的智能理论是正确的，人类就不能摆脱用刻板印象思考的倾向，因为刻板印象是新皮质的工作方式。刻板印象是大脑的固有特征。"},{"book":"新机器智能：边缘计算重塑AIoT产业生态","author":"杰夫·霍金斯 桑德拉·布莱克斯利","text":"不管是具体的还是抽象的，大脑都将一视同仁，因为它们都只是随着时间出现的具有可预测性的模式序列。"},{"book":"新机器智能：边缘计算重塑AIoT产业生态","author":"杰夫·霍金斯 桑德拉·布莱克斯利","text":"这些预测是理解的本质。理解某事意味着你可以对它进行预测。"},{"book":"新机器智能：边缘计算重塑AIoT产业生态","author":"杰夫·霍金斯 桑德拉·布莱克斯利","text":"人类的大脑之所以比其他动物的大脑更聪明，是因为它可以对更抽象的模式和更长的时间模式序列做出预测。"},{"book":"新机器智能：边缘计算重塑AIoT产业生态","author":"杰夫·霍金斯 桑德拉·布莱克斯利","text":"你的大脑通过将他的脸部不变结构的记忆与你直接体验到的细节相结合来实现面部识别。"},{"book":"新机器智能：边缘计算重塑AIoT产业生态","author":"杰夫·霍金斯 桑德拉·布莱克斯利","text":"整个新皮质结构是一个记忆系统，它根本就不是一台计算机。"},{"book":"别找替罪羊：如何跳出自欺欺人的盒子","author":"美国亚宾泽协会","text":"“大多数人想解决的问题不是用了技巧就能解决的，它们都和自我背叛有关。人的问题之所以难解决，并不是因为它们无法解决，而是因为技巧并不是解决问题的办法。”"},{"book":"万历十五年（四十周年纪念版）精","author":"[美]黄仁宇著","text":"这种细碎的事情表现了一个喜欢活动的人物具备着充沛的精力，但又无法用之于作出积极的创造。皇帝的这种苦闷乃是历史的悲剧。"},{"book":"万历十五年（四十周年纪念版）精","author":"[美]黄仁宇著","text":"象征成分，但象征不一定就是虚伪。如果所有参加典礼的人都相信这种象征，而决心以行动促其成为现实，这又是何等壮大的力量！"},{"book":"万历十五年（四十周年纪念版）精","author":"[美]黄仁宇著","text":"例如“知道了”，实际的意义是对本章内的建议并未接受，但也不必对建议者给予斥责。这些深微奥妙之处也只有随着他年龄的增长而逐渐加深理解。"},{"book":"万历十五年（四十周年纪念版）精","author":"[美]黄仁宇著","text":"据此而作进一步探索，可知“民穷”的根本原因不在国家的赋税过重，而端在法律的腐败和政府的低能。国家的税率低，受惠者并非农民，只是鼓励了大小地主加重剥削以及官僚乡里额外加征。"},{"book":"大外交","author":"亨利·基辛格","text":"美国过去的威尔逊式的目标——和平、稳定、进步和人类自由——将必须在无尽头的旅途上去寻求。西班牙有句谚语：“旅人啊，前头没有路，路是人走出来的。”"},{"book":"大外交","author":"亨利·基辛格","text":"这个问题正是政治家最大的困扰——什么样的目的可以使得什么样的手段合理？"},{"book":"大外交","author":"亨利·基辛格","text":"这段毫不客气的宣示可以说与黎塞留所见略同，即人因灵魂不朽，所以必须受上帝之审判，但国家并非不朽，因此仅能以功过论英雄。"},{"book":"大外交","author":"亨利·基辛格","text":"怎样才算革命家？这个问题很难得出确切的答案，否则能成功的革命家就不多了。因为革命家刚起步时必然是处于弱势，但革命家的胜算在于既有势力对本身的弱点总缺乏自知之明。"},{"book":"大外交","author":"亨利·基辛格","text":"附和民众的经验而画地自限的领导人注定会停滞不前；超越民众经验的领导人又有不被谅解的风险。"},{"book":"大外交","author":"亨利·基辛格","text":"他希望在他的领导下把国家带进国际社会，使美国能像英国掌握着19世纪一样塑造20世纪，借庞大无比的国力，循明智温和的方式，以稳定、和平与进步为己任。"},{"book":"哈德良回忆录","author":"[法]玛格丽特·尤瑟纳尔","text":"“从西塞罗到马尔库斯·奥列里乌斯这段时期，曾出现一个独特的时刻：彼时，众神已灭，基督未显，唯人独存。”"},{"book":"哈德良回忆录","author":"[法]玛格丽特·尤瑟纳尔","text":"我很清楚，这一小片种植橄榄树的谷地并非坦佩河谷；但到了我的年岁，每个美丽的地方都令人忆起另一个更美的景点，每项美妙的事物皆因过去的美妙回忆而更深刻。我自愿任这思旧的情绪淹没，那是渴望之哀愁。"},{"book":"哈德良回忆录","author":"[法]玛格丽特·尤瑟纳尔","text":"我们偶尔仍会谈起那段感情；尽管两人皆未说谎，我却经常觉得我们的话中隐含几分虚假，真相即在崇高的升华之下消失了。"},{"book":"哈德良回忆录","author":"[法]玛格丽特·尤瑟纳尔","text":"我们每个人所拥有的美德比想象的多，但只有在功成名就之后，这些美德才会被凸显；或许这是因为人们预期，成功之后，我们就不会继续遵守这些德行。"},{"book":"哈德良回忆录","author":"[法]玛格丽特·尤瑟纳尔","text":"我们人人都以为能逃过生而为人的狭隘限制，觉得我既是我，又是自己的对手；我们跟神明一样，其实并不清楚祂究竟以野兽的形态死去，还是借人类的模样杀生。"},{"book":"哈德良回忆录","author":"[法]玛格丽特·尤瑟纳尔","text":"我以拉丁文治理帝国；我的墓志铭将以拉丁文刻在我位于台伯河￼畔的陵墓墙上，但我这一生都用希腊文思考及活着。"},{"book":"像运动员一样思考：如何将不可能变为可能","author":"诺埃尔·布瑞克 斯科特·道格拉斯","text":"“一件一直困扰着大多数人的事情是，当你站在起点线上时，你的所有神经都达到了紧张的顶峰，或者说所有的神经都在向顶峰进军，你要把它看作是一种选择和特权。"},{"book":"像运动员一样思考：如何将不可能变为可能","author":"诺埃尔·布瑞克 斯科特·道格拉斯","text":"触发词或短语是最终策略，你对自己说的话也可以帮助你集中精力来克服注意力分散，并让自己重新专注。"},{"book":"人工智能：现代方法（第4版）（上下册）","author":"斯图尔特·罗素","text":"俗话说，不记得历史的算法注定要重复历史。"},{"book":"人工智能：现代方法（第4版）（上下册）","author":"斯图尔特·罗素","text":"简单反射型智能体直接响应感知，而基于模型的反射型智能体保持内部状态以跟踪当前感知中不明晰的世界状态。基于目标的智能体采取行动来实现目标，而基于效用的智能体试图最大化自己期望的“快乐”。"},{"book":"人工智能：现代方法（第4版）（上下册）","author":"斯图尔特·罗素","text":"正如谷歌DeepMind首席执行官德米斯·哈萨比斯(Demis Hassabis)所建议的那样：“首先解决人工智能问题，然后再用人工智能解决其他所有问题。”"},{"book":"鱼不存在","author":"露露·米勒","text":"和你在一起的每分每秒，都是我的人生壮丽恢宏的时刻。"},{"book":"鱼不存在","author":"露露·米勒","text":"这个聚会有你想象的那么无聊吗？或许有个还未相识的朋友在等你，嘴里叼根烟，站在舞池旁的后门边。这个人会在余生的每天和你一起大笑，将你的羞耻转变为归属感。"},{"book":"鱼不存在","author":"露露·米勒","text":"这个世界向我承诺，我的生命中有美好的事物。不是因为我值得，不是因为我为之努力，而是因为它们和破坏与失去一样，是混乱的一部分。生是死的另一面，正如生长和腐烂互相依存。"},{"book":"鱼不存在","author":"露露·米勒","text":"卡夫卡认为，每个人的内心深处都有一种不可摧毁之物，不论人们状态如何，它都能赋予他们前行的动力。不可摧毁之物与乐观毫无关系，相反，它比乐观更深刻，处于意识的更深处。"},{"book":"鱼不存在","author":"露露·米勒","text":"或许大卫是在默不作声地信仰上帝，相信世间仍有一种温暖，一种在星辰中难以找寻，只存在于人类心中的温暖。"},{"book":"荒原狼（果麦经典）","author":"[德]赫尔曼·黑塞","text":"这些音乐中四处闪耀着清冷的、群星般的光芒，振荡着以太般的清澈。是的，这就是永恒。它是凝固在空间中的时间，上方回荡着无尽的超人般的欢乐，永恒而神圣的笑声。"},{"book":"翦商：殷周之变与华夏新生","author":"李硕","text":"这是上古时代的常态：并非所有的人类社群都会自动进化成更大的共同体和国家；事实是，多数会一直停滞无为，直到被强大的古国或王朝吞并，被强行裹挟进人类的“发展”大潮中。"},{"book":"透过地理看历史：大航海时代","author":"李不白","text":"波斯是早期希腊人对这个地方的人的称呼，其实波斯人一直自称伊朗。伊朗(Iran)也可以翻译成雅利安。"},{"book":"古希腊思想通识课：修昔底德篇","author":"张新刚","text":"经典作品最大的魅力就在于，它永远不会辜负对它付出时间和精力的人。"},{"book":"古希腊思想通识课：修昔底德篇","author":"张新刚","text":"今天看来，雅典的民主制度是直接民主制，其标志并非选举，而是抽签。选举在古代希腊被视为是贵族制的制度，因为选贤与能是选出更优秀的人，而抽签才是真正平等身份的体现。"},{"book":"古希腊思想通识课：修昔底德篇","author":"张新刚","text":"我的著作不是想赢得听众一时的奖赏，而是要成为永恒的财富。"},{"book":"规则的悖论","author":"大卫·格雷伯","text":"在其他语境下，特别是在官僚语境下，指挥关系有着语言编码：它们与法语密切相关；与之相对，马达加斯加语被视作商议、解释和共识决策所使用的语言。当基层官员想要不由分说地发号施令时，几乎总会切换到法语。"},{"book":"规则的悖论","author":"大卫·格雷伯","text":"这些人的基本论点是，他们执掌的新兴巨头企业的效率本身，能够带来物质的极大丰富，使美国人可以通过消费而非生产去达成自我实现。"},{"book":"芒格之道——查理·芒格股东会讲话1987-2022","author":"查理·芒格 芒格书院","text":"一个文明社会要健康发展，需要的是有效的激励机制。"},{"book":"芒格之道——查理·芒格股东会讲话1987-2022","author":"查理·芒格 芒格书院","text":"对于专业人士搞出来的投资产品，我普遍持怀疑态度。别人不遗余力地推销叫卖的东西，我一般选择远离。你讲的东西，是我不碰的东西，我帮不了你。你讲的这个地方，我不愿意去，我选择远离。"},{"book":"芒格之道——查理·芒格股东会讲话1987-2022","author":"查理·芒格 芒格书院","text":"阿吉特这样的顶尖人才少之又少。现在就算有像阿吉特这样的人才，也无法复制阿吉特的成功，因为现在比以前更难了。"},{"book":"芒格之道——查理·芒格股东会讲话1987-2022","author":"查理·芒格 芒格书院","text":"皮凯蒂和桑德斯谴责社会的不平等，他们的主张没什么道理。我们面临的不是社会不平等的问题，而是不义之财的问题。很多人发了不义之财，尤其是在金融领域。"},{"book":"芒格之道——查理·芒格股东会讲话1987-2022","author":"查理·芒格 芒格书院","text":"大型机构有很多合法生意可做，没必要经营类似赌场的业务。肃清高风险的经营活动，社会将更加安宁。"},{"book":"芒格之道——查理·芒格股东会讲话1987-2022","author":"查理·芒格 芒格书院","text":"我支持凯恩斯的观点，文明社会的资本配置过程不应该如赌场一样混乱，证券产品应该简单清晰，不应该晦涩难懂。"},{"book":"芒格之道——查理·芒格股东会讲话1987-2022","author":"查理·芒格 芒格书院","text":"我更适应衰老了。我好比是一个从摩天大楼上纵身跃下的人，下落到第五层楼的时候，感觉还不错。 年迈体衰，有很多不便之处，但也有很多乐趣。老就老吧，我不会抱怨。不老的话，不就死了吗？"},{"book":"芒格之道——查理·芒格股东会讲话1987-2022","author":"查理·芒格 芒格书院","text":"不看电影公司、不看矿业公司，我一点都不觉得遗憾。我按照自己的喜好做出了选择。"},{"book":"芒格之道——查理·芒格股东会讲话1987-2022","author":"查理·芒格 芒格书院","text":"我刚才说的这种投资思路，关键是要把握好度。再好的生意，价格太高，也不值得投资了。这不是明摆着的吗？再好的公司也不值天价啊。"},{"book":"芒格之道——查理·芒格股东会讲话1987-2022","author":"查理·芒格 芒格书院","text":"我得出的结论是，只要我能受得了波动，同时持有三只股票就足够了。我是通过粗略的计算和逻辑推理得出的这个结论。作为一个扑克玩家，我知道，赢的概率非常高的时候，要下重注。"},{"book":"芒格之道——查理·芒格股东会讲话1987-2022","author":"查理·芒格 芒格书院","text":"在大多数公司，裁员都是个痛苦的过程。员工痛苦、股东痛苦、所有人都痛苦。然而，裁员是资本主义制度的一部分。"},{"book":"芒格之道——查理·芒格股东会讲话1987-2022","author":"查理·芒格 芒格书院","text":"我们不会因为自己是一家保险公司，就什么保险业务都要接。我们只做合理的、值得承接的保险。在合理、值得承接的基础上，业务规模才是越大越好。合理的、值得承接的业务少，我们就少做，宁缺毋滥。"},{"book":"金钱心理学：财富、人性和幸福的永恒真相","author":"摩根·豪泽尔","text":"哪里有选择，哪里便有选择的艺术"},{"book":"金钱心理学：财富、人性和幸福的永恒真相","author":"摩根·豪泽尔","text":"“当我问丹尼他为什么可以彻底推翻前一版，就好像它不存在时，”茨威格说，“他说的话我永远都忘不了：‘我没有沉没成本。’”"},{"book":"奥本海默传（诺兰导演电影《奥本海默》 灵感来源、普利策奖获奖传记）","author":"[美]凯·伯德 [美]马丁·J.舍温","text":"“我们不仅要记住他用自己的特殊才能为我们所做的贡献，还要记住我们都对他做过什么。”"},{"book":"奥本海默传（诺兰导演电影《奥本海默》 灵感来源、普利策奖获奖传记）","author":"[美]凯·伯德 [美]马丁·J.舍温","text":"他被称作“物理学家和水手、哲学家和骑手、语言学家和厨师、美酒和好诗的爱好者”。"},{"book":"奥本海默传（诺兰导演电影《奥本海默》 灵感来源、普利策奖获奖传记）","author":"[美]凯·伯德 [美]马丁·J.舍温","text":"我们正在探索人类能否在保护培育生命、自由和对幸福的追求的同时又无须将战争作为历史的终极仲裁者"},{"book":"奥本海默传（诺兰导演电影《奥本海默》 灵感来源、普利策奖获奖传记）","author":"[美]凯·伯德 [美]马丁·J.舍温","text":"奥本海默总结道：“当了解事实的人找不到可以讨论的人，当事实保密到无法集思广益时，才会出现各种愚蠢之举。”"},{"book":"奥本海默传（诺兰导演电影《奥本海默》 灵感来源、普利策奖获奖传记）","author":"[美]凯·伯德 [美]马丁·J.舍温","text":"“虽然苏联目前落后我们4年，这可能是一个小小的安慰……但我们至少可以得出这样的结论：我们的第20000枚核弹……并不能从根本上抵消他们的第2000枚核弹带来的战略威胁”。"},{"book":"奥本海默传（诺兰导演电影《奥本海默》 灵感来源、普利策奖获奖传记）","author":"[美]凯·伯德 [美]马丁·J.舍温","text":"小组成员甚至建议向公众披露“核弹的生产速度及其影响”，“应该让大家注意到这样一个事实：超过一定限度之后，我们就不能再仅仅通过‘领先于苏联人’来抵御苏联的威胁”。"},{"book":"奥本海默传（诺兰导演电影《奥本海默》 灵感来源、普利策奖获奖传记）","author":"[美]凯·伯德 [美]马丁·J.舍温","text":"如果当时奥本海默迈出了那一步，他的人生就会迥然不同，不会遭遇那么多波折。但他没有，像科南特一样，奥本海默再次选择了顺从。"},{"book":"奥本海默传（诺兰导演电影《奥本海默》 灵感来源、普利策奖获奖传记）","author":"[美]凯·伯德 [美]马丁·J.舍温","text":"“我们都认为，”贝特说，“在这样一场战争之后，即使我们赢得了战争，世界也不会再是……我们想维护的那个样子。我们会失去我们为之奋斗的一切。"},{"book":"奥本海默传（诺兰导演电影《奥本海默》 灵感来源、普利策奖获奖传记）","author":"[美]凯·伯德 [美]马丁·J.舍温","text":"“我们认为不应进行这种（氢弹）研发，这主要是因为我们宁肯战败也不愿用氢弹造成的大规模人类灾难来换取胜利。”（最后两句话还加了重点。）"},{"book":"奥本海默传（诺兰导演电影《奥本海默》 灵感来源、普利策奖获奖传记）","author":"[美]凯·伯德 [美]马丁·J.舍温","text":"奥本海默仍然坚信高等研究院应该对自然科学和人文科学兼收并蓄，这一点至关重要。在他关于高等研究院的演讲中，奥本海默不断强调，人文学科可以帮助科学更好地了解其自身属性及对人类的影响。"},{"book":"奥本海默传（诺兰导演电影《奥本海默》 灵感来源、普利策奖获奖传记）","author":"[美]凯·伯德 [美]马丁·J.舍温","text":"在压力之下，他一次又一次说出一些让他深感后悔的话，这些话将对他的人生造成重创。这一次，他本来有机会打动那个能帮他把核妖怪塞回瓶子里的人，但他完全没有抓住这个机会。"},{"book":"奥本海默传（诺兰导演电影《奥本海默》 灵感来源、普利策奖获奖传记）","author":"[美]凯·伯德 [美]马丁·J.舍温","text":"奥本海默很快就成了华盛顿的圈内人，他乐于与当局合作，一心一意地支持他们，但是真正指引他的是其内心的希望，而支撑他的是其政治上的天真。"},{"book":"奥本海默传（诺兰导演电影《奥本海默》 灵感来源、普利策奖获奖传记）","author":"[美]凯·伯德 [美]马丁·J.舍温","text":"奥本海默会以细微的方式让人们知道，他理解和感激每个人所做的牺牲。尽管居住环境缺乏隐私，生活条件简陋，水、牛奶甚至电力都经常短缺，他还是用自己独特的风趣幽默感染大家。"},{"book":"奥本海默传（诺兰导演电影《奥本海默》 灵感来源、普利策奖获奖传记）","author":"[美]凯·伯德 [美]马丁·J.舍温","text":"危险并不在于核弹的技术信息可能会泄露给另一个国家，真正的秘密是“我们努力的程度”和“涉及的国际投资”的规模。"},{"book":"奥本海默传（诺兰导演电影《奥本海默》 灵感来源、普利策奖获奖传记）","author":"[美]凯·伯德 [美]马丁·J.舍温","text":"科学家们习惯于那些只能利用有限资源但几乎没有截止日期的工作，现在他们不得不去适应一个资源无限而时间紧迫的世界。"},{"book":"奥本海默传（诺兰导演电影《奥本海默》 灵感来源、普利策奖获奖传记）","author":"[美]凯·伯德 [美]马丁·J.舍温","text":"多年后，奥本海默从邓恩的十四行诗中获得了灵感，因为这句“砸烂我的心吧，三位一体的上帝”，他将第一次原子弹试验的代号定为“三位一体”。"},{"book":"奥本海默传（诺兰导演电影《奥本海默》 灵感来源、普利策奖获奖传记）","author":"[美]凯·伯德 [美]马丁·J.舍温","text":"正如物理学家理查德·费曼曾经说的：“以常识来看，量子力学对自然的描述简直荒谬。但是它与实验结果完全吻合。所以我希望你能接受大自然的本来面目，她就是荒谬的。”"},{"book":"奥本海默传（诺兰导演电影《奥本海默》 灵感来源、普利策奖获奖传记）","author":"[美]凯·伯德 [美]马丁·J.舍温","text":"他喜欢卡明斯的观点，即一个被剥夺了一切的人仍能在最清苦的环境中找到属于他的自由。"},{"book":"奥本海默传（诺兰导演电影《奥本海默》 灵感来源、普利策奖获奖传记）","author":"[美]凯·伯德 [美]马丁·J.舍温","text":"“当我到剑桥的时候，”奥本海默说，“我面对的是一个无人知晓答案的问题，而我也不愿意面对它。当我离开剑桥的时候，我仍然不知如何更好地面对它，但是我明白了这就是我的任务，这就是那一年间发生的变化。”"},{"book":"支付的故事","author":"戈特弗里德·莱伯兰特 娜塔莎·德特兰","text":"银行可能需要支付，但支付真的需要银行吗？"},{"book":"埃隆·马斯克传","author":"沃尔特·艾萨克森","text":"马斯克给大家动员鼓劲：“在你们经历所有这些磨难的时候，一定要记得你们正在研究的是地球上最酷的东西。它真的酷毙了！谁知道第二酷的东西是什么？不管第二酷的是什么，跟咱这个都没法比。”"},{"book":"埃隆·马斯克传","author":"沃尔特·艾萨克森","text":"一如既往，他要给大家灌输一种时不我待的紧迫感：“这将是一款具有历史意义的重大革命性产品，它将改变一切，它将让特斯拉成为价值10万亿美元的公司。百年以后，人们会记住这个时刻。”"},{"book":"埃隆·马斯克传","author":"沃尔特·艾萨克森","text":"“我认为言论自由和传播自由之间是有区别的，任何人都可以走到时代广场中央，说什么都行，但这并不意味着这句话应该传播给数百万人听。”"},{"book":"埃隆·马斯克传","author":"沃尔特·艾萨克森","text":"“终有一天抵达火星的那个场面激励着SpaceX做出每个决定。”"},{"book":"埃隆·马斯克传","author":"沃尔特·艾萨克森","text":"前往火星需要花费大量资金，因此马斯克一如往常地将一个目标远大的任务与一个务实的商业计划相结合。"},{"book":"埃隆·马斯克传","author":"沃尔特·艾萨克森","text":"他和父亲一起反复观看了火箭发射视频，在学会从1数到10之前，他先学会了从10数到1。"},{"book":"埃隆·马斯克传","author":"沃尔特·艾萨克森","text":"在自动驾驶日演讲当中，马斯克故技重施，把长期愿景和短期目标混为一谈。即便在他自己的脑海中，他也故意模糊了他的信念和他的意愿之间的界限。"},{"book":"埃隆·马斯克传","author":"沃尔特·艾萨克森","text":"他说：“萨尔兹曼坚持想让我们搭传统车企的便车，而我的想法是他们那艘船可都要沉了啊。”"},{"book":"埃隆·马斯克传","author":"沃尔特·艾萨克森","text":"煤油和液氧注入推力室后只燃烧了半秒，而这就是他们需要的结果，确保这套机制能够运作。"},{"book":"埃隆·马斯克传","author":"沃尔特·艾萨克森","text":"“他觉得银行很蠢，但事实上没有他想的那么蠢。”尼科尔森说，“不过这也是件好事，因为这让他不那么尊重传统的金融业，他才有胆量去创办PayPal，所以这对他的发展还是有益的。”"},{"book":"埃隆·马斯克传","author":"沃尔特·艾萨克森","text":"当其他企业家还在努力形成世界观时，他已经形成了宇宙观。"},{"book":"埃隆·马斯克传","author":"沃尔特·艾萨克森","text":"任何初始版本的电动车制造成本都很高，每辆至少要7万美元。马斯克说：“没有人会为看起来像垃圾一样的东西掏钱。”让一家汽车公司正确起步的方法是先打造一辆高价值的车，然后再转向大众市场车型。"},{"book":"埃隆·马斯克传","author":"沃尔特·艾萨克森","text":"这种机制是结果导向的激励方式，而不是鼓励你在建造过程中浪费资源。"},{"book":"埃隆·马斯克传","author":"沃尔特·艾萨克森","text":"他认为成本加成制度的问题在于它阻碍了创新。如果项目花费超出预算，承包商就会得到更多的报酬。"},{"book":"埃隆·马斯克传","author":"沃尔特·艾萨克森","text":"这种方法在第二次世界大战期间成为通行做法，政府完全控制武器的开发，还能避免让民众误认为军火承包商是在发战争财。"},{"book":"埃隆·马斯克传","author":"沃尔特·艾萨克森","text":"他主张NASA的工作应该鼓励创新，而不是扶持某些公司。"},{"book":"经纬华夏（历史学家许倬云的集大成之作）","author":"许倬云","text":"美国的政治运作表面上是取得大家的协议，实质上不免有许多意见在沟通之间，主要考虑彼此的私人利益。于是，看上去严肃的过程，背后却躲不开利益的交换。"},{"book":"经纬华夏（历史学家许倬云的集大成之作）","author":"许倬云","text":"孙中山就属于游离于核心圈层之外的部分，因此他并未充分理解中国的核心问题所在，也无法参与（更不论动员）核心知识群体的活动。"},{"book":"组织部来了个年轻人","author":"王蒙","text":"我总觉得语言也是一种艺术、一种音乐，是打开一种人心、一种文化的钥匙。多学一种语言就等于多长了一双眼睛、一对耳朵、一个舌头和一副头脑，学英语、读英语、听英语和说英语，是当前我的癖好之一。"},{"book":"组织部来了个年轻人","author":"王蒙","text":"在创作上我进行了一些试验，但从来认为生活是第一性的，生活的丰富决定了题材的多样性和手法的多样性。"},{"book":"生活在树上：卡尔维诺传（卡尔维诺百年诞辰纪念版）","author":"卢卡·巴拉内利 埃内斯托·费里罗","text":"一切皆可改变，但我们内在的语言不会改变，甚至它所包含的内在是比母亲的子宫更加独特和权威的一个世界。"},{"book":"生活在树上：卡尔维诺传（卡尔维诺百年诞辰纪念版）","author":"卢卡·巴拉内利 埃内斯托·费里罗","text":"对此我并不后悔：所有精力的消耗都是为文明社会而服务。"},{"book":"横空出世—核物理与原子弹的诞生","author":"[美]理查德·罗兹","text":"原子弹是权力，是最新的铸币厂，权力对政治而言如同金钱对银行而言一样，都是致富交换的一种媒介。只有不懂事的孩子和傻瓜才会放弃它。"},{"book":"横空出世—核物理与原子弹的诞生","author":"[美]理查德·罗兹","text":"保密本身泄露了秘密。"},{"book":"横空出世—核物理与原子弹的诞生","author":"[美]理查德·罗兹","text":"正如一名历史学家在阐释西拉德的思想时说的那样：“人人都认为这是一个经济上有保障的社会，因此智识上的成就被赋予了很高的价值。”"},{"book":"横空出世—核物理与原子弹的诞生","author":"[美]理查德·罗兹","text":"奥本海默曾一针见血地指出：“科学中深层的内容被发现并不是因为它们有用，而是因为它们能被发现。这是一个深刻而必然的真理。”"},{"book":"超越百岁：长寿的科学与艺术","author":"[美]彼得·阿提亚","text":"2500年前的佛陀说：“即使是最坏的敌人，也不能像自己毫无防御的内心般伤害自己。”公元一世纪，塞内卡(Seneca)对此进行了改进，指出“折磨我们的往往是想象，而不是真实”。"},{"book":"超越百岁：长寿的科学与艺术","author":"[美]彼得·阿提亚","text":"我们唯一的目标是活得更久，活得更好——享受“超越百岁”的人生(to outlive)。为此，我们必须改写许多前人所忍受的“衰退叙事”，并制定出一个计划，让每一个10年都比前一个10年更好。"},{"book":"黄仁勋:英伟达之芯","author":"[美]斯蒂芬·威特","text":"人类本应以提供离群值和差异值而贡献的创新价值，在机械异化后的教育与商业体系，被培养与教育的都是机器最擅长的记忆与重复执行能力，其结果是人类成为了机器，而机器却不得不做本应人类该做的事情。"},{"book":"黄仁勋:英伟达之芯","author":"[美]斯蒂芬·威特","text":"卡坦扎罗指出，我们需要一个对算力需求极大，以至于永远无法得到满足的应用程序。"},{"book":"黄仁勋:英伟达之芯","author":"[美]斯蒂芬·威特","text":"辛顿担心克里泽夫斯基的突破性贡献被忽视，鼓励他将SuperVision重命名以凸显其贡献。尽管克里泽夫斯基对此表示怀疑，但最终还是接受了建议，将SuperVision更名为“AlexNet”。"},{"book":"黄仁勋:英伟达之芯","author":"[美]斯蒂芬·威特","text":"为了掩盖他的工作内容以便更顺利地获取资金支持，他与其他神经网络研究者共同选择将他们的研究描述为“机器学习”，有时也称作“深度学习”，却唯独避免提及“人工智能”一词。"},{"book":"黄仁勋:英伟达之芯","author":"[美]斯蒂芬·威特","text":"金钱只是对未来可能发生的某些灾祸的一种临时保障。"},{"book":"联邦党人文集","author":"亚历山大·汉密尔顿 詹姆斯·麦迪逊 约翰·杰伊","text":"事物定义模糊不准确的根源有三个，一是事物本身的模糊性，二是人类认识感官的缺陷，三是思想表达的载体不足。"},{"book":"联邦党人文集","author":"亚历山大·汉密尔顿 詹姆斯·麦迪逊 约翰·杰伊","text":"当人们意识到自己在从事不正当或者卑鄙的事情时，他们之间往往会产生不信任感，阻碍他们之间的相互交流，这种不信任感还会随着人数的增加而增加。"},{"book":"联邦党人文集","author":"亚历山大·汉密尔顿 詹姆斯·麦迪逊 约翰·杰伊","text":"英国人民确实有可能因为其他原因沦为奴隶，虽然可能性很小；但是英国通常维持的军队规模是如此之小，这使他们永远不会沦为本国军队的奴隶。"},{"book":"价值","author":"张磊","text":"投资这个游戏的第一条规则就是得能够玩下去（The No.1 rule of the game is to stay in the game）"},{"book":"价值","author":"张磊","text":"长期持有只是结果，而不是目的"},{"book":"价值","author":"张磊","text":"晚清名臣张之洞在修建卢汉铁路时提出了“储铁宜急，勘路宜缓，开工宜迟，竣工宜速”的指导原则"},{"book":"价值","author":"张磊","text":"投资的本质是追求风险和成本调整之后的长期、可持续的投资回报，克服恐惧和贪婪，相信简单的常识。"},{"book":"价值","author":"张磊","text":"不管企业在什么行业什么阶段，只要能在适应的环境以适合自身组织的形式予以表达，持续创造出价值，就是好的投资机会。"},{"book":"价值","author":"张磊","text":"投资不是纯粹为了赚钱，一味受金钱驱动是这个行业里最危险的事情：要么挣了很多钱，挣到钱却不知道接着干什么；要么一直挣不到钱，甚至为钱铤而走险。"},{"book":"价值","author":"张磊","text":"归根到底，Zoom创造了又一个“用科技提高效率”的典型场景。"},{"book":"价值","author":"张磊","text":"“管理哲学之父”查尔斯·汉迪（Charles Handy）曾提出第二曲线理论，也就是企业应该在第一曲线（主营业务）增长平缓前，找到第二曲线代替第一曲线担当增长引擎。"},{"book":"价值","author":"张磊","text":"最好的分析方法未必是使用估值理论、资产定价模型、投资组合策略，而是坚持第一性原理，即追本溯源，这个“源”包括基本的公理、处世的哲学、人类的本性、万物的规律。"},{"book":"价值","author":"张磊","text":"。对于一家专注于研究行业、研究基本面的投资公司，核心能力就是对商业本质的敏锐洞察。"},{"book":"价值","author":"张磊","text":"零售即服务，内容即商品，所见即所得"},{"book":"价值","author":"张磊","text":"在无关处寻找有关，在有关处探求洞见，在洞见后构建方案。"},{"book":"价值","author":"张磊","text":"真正穿越周期的投资机构，往往做到了既看到眼下，时刻做好打算，又目光长远，不为一时一地而自乱阵脚。"},{"book":"价值","author":"张磊","text":"所有的快钱，它产生的理由无外乎这样几点：信息不对称下的博弈、热点追逐中的投机，甚至是权力寻租。"},{"book":"价值","author":"张磊","text":"尽管对此次拜访早有准备并胸有成竹，但对于回答不了的问题，我们仍然坦诚回应并记下应该关注的投资要点。"},{"book":"价值","author":"张磊","text":"第一是人品好，第二是爱学习，第三是能吃苦"},{"book":"价值","author":"张磊","text":"一个当时从没做过投资的女生，从做我的秘书干起，先后做过投研、风控、财务、基金运营等各个岗位，一路成长为高瓴的合伙人"},{"book":"洞见：从科学到哲学，打开人类的认知真相","author":"罗伯特·赖特","text":"好奇到底是迫切的渴望还是令人愉悦的诱惑，还要取决于这件事在自然选择定义下与我们的利益的相关程度，关联的直接性和紧迫性越低，感觉就越微妙和惬意。"},{"book":"洞见：从科学到哲学，打开人类的认知真相","author":"罗伯特·赖特","text":"“不要用佛教教义来使自己成为更好的佛教徒，用它来做更好的自己。”"},{"book":"华夏边缘：历史记忆与族群认同","author":"王明珂","text":"客观论指出族群可被观察的内涵，主观论描绘族群边界；根基论说明族群内部分子间的联系与传承，工具论强调族群认同的维持与变迁。"},{"book":"华夏边缘：历史记忆与族群认同","author":"王明珂","text":"原则上是，当我们与他人交往时，我们会宣称最小的共同认同，来增进彼此最大的凝聚。"},{"book":"光明共和国","author":"安德烈斯·巴尔瓦","text":"当一个社会开始怀疑一切，那么应该提出的问题并不是“存在通灵术吗？”，而应该是：我们哪里出错了？"},{"book":"燃烧的大洋：1941—1942，从突袭珍珠港到中途岛战役","author":"伊恩·托尔","text":"宫本武藏曾建议：“若想发动攻击，应任凭对手做无用之事，同时阻止其做有用之事。这是兵法的精髓所在。”"},{"book":"高效能人士的七个习惯（30周年纪念版）（全新增订版）","author":"史蒂芬·柯维","text":"工作本身并不能带来经济上的安全感，具备良好的思考、学习、创造与适应能力，才能立于不败之地。拥有财富，并不代表经济独立，拥有创造财富的能力才真正可靠。"},{"book":"高效能人士的七个习惯（30周年纪念版）（全新增订版）","author":"史蒂芬·柯维","text":"习惯是知识、技巧和意愿的交叉点。知识是做什么和为何做，技巧是如何做，而意愿是动力——想做。所有这三者必须集合在一起才能形成一个习惯。"},{"book":"高效能人士的七个习惯（30周年纪念版）（全新增订版）","author":"史蒂芬·柯维","text":"于我而言，我会说最重要的习惯就是你生活最艰难的时候采用的那个习惯。"},{"book":"高效能人士的七个习惯（30周年纪念版）（全新增订版）","author":"史蒂芬·柯维","text":"人的行为总是一再重复。因此卓越不是一时的行为，而是习惯。 ——亚里士多德(Aristotle)"},{"book":"高效能人士的七个习惯（30周年纪念版）（全新增订版）","author":"史蒂芬·柯维","text":"我们必不可停止探索，而一切探索的尽头，就是重回起点，并对起点有如初见般的了解。"},{"book":"君主论","author":"尼科洛·马基雅维里","text":"一切良好的忠言，不论来自任何人，必须产生于君主的贤明，而不是君主的贤明产生于良好的忠言。"},{"book":"君主论","author":"尼科洛·马基雅维里","text":"明智的人们常常提出这样的意见和论断：“世界上最弱和最不牢固的东西，莫过于不以自己的力量为基础的权力的声誉了”"},{"book":"君主论","author":"尼科洛·马基雅维里","text":"深深地认识人民的性质的人应该是君主，而深深地认识君主的性质的人应属于人民。"},{"book":"社会契约论（汉译世界学术名著丛书）","author":"[法]卢梭","text":"本书理应和亚当·斯密的《国富论》、康德的《纯粹理性批判》、达尔文的《物种起源》、穆勒的《论自由》、马克思的《资本论》等经典著作并列，标志着人类近代思想理论的高峰。"},{"book":"光刻巨人：ASML崛起之路","author":"瑞尼·雷吉梅克","text":"在任何缺乏经验的领域，雇用外部专家。"},{"book":"复杂生命的起源","author":"尼克·莱恩","text":"为什么病毒不算活物？因为它自身没有任何新陈代谢能力，完全依赖宿主的能量生产机制。"},{"book":"复杂生命的起源","author":"尼克·莱恩","text":"这些问题，其实不是在思考可能存在的外星生命，而是在思考地球上已知的生命：为什么地球上的生命会是这样？SETI的望远镜就像一面反射镜，把问题抛回给地球生物学家。"},{"book":"雪球专刊·特别版：段永平投资问答录商业逻辑篇","author":"雪球专刊","text":"差异化其实就是顾客需要但别人没能满足的需求。千万别简单地理解成不一样。差异化的好产品一般都是长期积累厚积薄发出来的，当然偶尔也有运气的成分，但长期来讲，运气的成分可以忽略。"},{"book":"雪球专刊·特别版：段永平投资问答录商业逻辑篇","author":"雪球专刊","text":"It's not an opinion，it is a fact."},{"book":"雪球专刊·特别版：段永平投资问答录商业逻辑篇","author":"雪球专刊","text":"不能简单用对错来判断这件事。但如果是因为钱多而做这件事，尤其是看到其以前的表现，感觉多半是错的。钱多（相关业务用不掉）就应该回购或派息，不然就是对自己公司没自信，那股价掉也正常。"},{"book":"雪球专刊·特别版：段永平投资问答录商业逻辑篇","author":"雪球专刊","text":"愤怒一下，然后平常心回归本源，该干嘛干嘛，不要因为愤怒做出任何决定。"},{"book":"雪球专刊·特别版：段永平投资问答录商业逻辑篇","author":"雪球专刊","text":"段永平：呵呵，你要是想忙一天的话，就请朋友来家里吃饭。 你要是想忙一年的话，就装修你的房子。 你要是想忙一辈子的话，就多买几个这样的企业。"},{"book":"雪球专刊·特别版：段永平投资问答录商业逻辑篇","author":"雪球专刊","text":"除非是经历销售量的巨幅成长，否则一家好的企业定义上应该是指那些可以产生大量现金的公司"},{"book":"雪球专刊·特别版：段永平投资问答录商业逻辑篇","author":"雪球专刊","text":"这种差别很微妙，但它却会影响每一件事：你聘用谁，提拔谁，会议上讨论什么事情。"},{"book":"解密Instagram：一款拍照软件如何改变社交","author":"莎拉·弗莱尔","text":"我们打算离开Instagram，再次探索自己的好奇心和创造力。创造新事物需要我们退一步思考，想清楚是什么给予了我们灵感，并将其和世界的需求结合在一起。这就是我们的计划。"},{"book":"不拘一格：网飞的自由与责任工作法","author":"里德·哈斯廷斯 艾琳·迈耶","text":"许多公司都是根据绩效考核结果决定员工薪资，而网飞的基本工资取决于市场，而非绩效。"},{"book":"雪球专刊·特别版：段永平投资问答录投资逻辑篇","author":"雪球专刊","text":"以前我们做VCD时，有人向我挑战说DVD将来会取代VCD，我说你觉得将来卖DVD的会是谁？"},{"book":"雪球专刊·特别版：段永平投资问答录投资逻辑篇","author":"雪球专刊","text":"长期而言，没有jobs的苹果可能会慢慢变成和别的同行一样的公司。但苹果的平台已经搭好，就像当年3大战役已经打完一样，jobs在不在影响都不大了。"},{"book":"雪球专刊·特别版：段永平投资问答录投资逻辑篇","author":"雪球专刊","text":"关于市场份额：好像很多人太在意市场份额这个其实没太多意义的指标。其实要提高市场份额不难，但保持有意义的份额不容易。诺基亚当年就是太在意市场份额才把自己推到绝境的。"},{"book":"雪球专刊·特别版：段永平投资问答录投资逻辑篇","author":"雪球专刊","text":"请教段大哥一个问题：股票价值投资者对社会整体创造财富有帮助吗？或者说，对比投机者，股票投资者对社会的贡献更大一些？ 段永平：如果没有股市，很多好企业就根本无法开始。没有价值投资者，就根本没有股市。"},{"book":"雪球专刊·特别版：段永平投资问答录投资逻辑篇","author":"雪球专刊","text":"学习除了看外，最重要的是悟。那么多人读着看图看线的书，如何才能学会投资呢？"},{"book":"雪球专刊·特别版：段永平投资问答录投资逻辑篇","author":"雪球专刊","text":"不过也顺便说明不看这些书也是可以做好投资的。这种书看多了对投资一定是帮倒忙的。芒格讲要过滤掉不必要的信息大概就是这个意思吧。"},{"book":"雪球专刊·特别版：段永平投资问答录投资逻辑篇","author":"雪球专刊","text":"做空不是价值投资，因为你经常需要面对市场的疯狂，最糟糕的是，你不知道市场到底有多疯狂，所以做空会睡不好觉的。总而言之，价值投资就是那种能睡好觉的投资。"},{"book":"雪球专刊·特别版：段永平投资问答录投资逻辑篇","author":"雪球专刊","text":"我对大盘的判断很简单。如果你有足够的钱把所有股票买下来，然后赚所有上市公司赚的钱，如果你觉得合适，那这个大盘就不贵，不然就贵了。（这里还没算交易费呢）"},{"book":"雪球专刊·特别版：段永平投资问答录投资逻辑篇","author":"雪球专刊","text":"所谓对宏观经济的了解应该是对经济现象的理解而不是花很多工夫去根据宏观经济的短期数据来不断调整自己的“投资”。"},{"book":"雪球专刊·特别版：段永平投资问答录投资逻辑篇","author":"雪球专刊","text":"记得有次有人问到我能接受一家公司的仓位的最高比例时，我说我能接受50%，但我目前喜欢的两家公司正好都叫苹果。"},{"book":"雪球专刊·特别版：段永平投资问答录投资逻辑篇","author":"雪球专刊","text":"好价和长期持有的关系是什么呢？其实是好股长期持有就是好价了，而不是买到了好价钱的意思。"},{"book":"雪球专刊·特别版：段永平投资问答录投资逻辑篇","author":"雪球专刊","text":"所谓价值投资者追求的是价值，与其是否热门无关。所有真正好公司都有热门的那一天。最关键是平常心去看一家公司到底价值何在，不要理市场的冷热。"},{"book":"雪球专刊·特别版：段永平投资问答录投资逻辑篇","author":"雪球专刊","text":"最重要还是“理性”吧，假设你今天刚刚结束冬眠，起来看看有啥股票可以买的，然后再决定。卖的时候也差不多这感觉。"},{"book":"雪球专刊·特别版：段永平投资问答录投资逻辑篇","author":"雪球专刊","text":"最重要的，是要把股票看作对于企业的一小片所有权，以企业的竞争优势来判断内在的价值。要寻找未来折现的现金利润比你支付的股价高的机会。这是很基础的，你得明白概率，只有当你赢的概率更大的时候才去下赌注。"},{"book":"雪球专刊·特别版：段永平投资问答录投资逻辑篇","author":"雪球专刊","text":"在卖出大部分网易之前，我一直理性考虑的问题主要是这家公司未来到底可以赚多少钱而不是想我的股票已经赚了多少钱的问题。要大致想明白这个问题，对公司、行业、产品等等的了解不深是做不到的。"},{"book":"雪球专刊·特别版：段永平投资问答录投资逻辑篇","author":"雪球专刊","text":"比如一个公司有净资产100亿，每年能赚10亿，这个公司大概值多少钱？ 段永平：大概就是你存X的钱能拿到10亿的利息（长期国债利息），再把x打6折。"},{"book":"雪球专刊·特别版：段永平投资问答录投资逻辑篇","author":"雪球专刊","text":"我一般只是想象如果某个公司是个非上市企业，我用目前的市值去拥有这家公司和我其他的机会比较，哪个在未来10年或20年得到的可能回报更高（这里的回报其实是指公司的盈利而不是股价的涨幅）。"},{"book":"雪球专刊·特别版：段永平投资问答录投资逻辑篇","author":"雪球专刊","text":"无形资产也是可以折现的，所以我不建议单独考虑无形资产，因为公司的获利能力里已经包含了。"},{"book":"雪球专刊·特别版：段永平投资问答录投资逻辑篇","author":"雪球专刊","text":"要学会什么是好生意，最好的办法就是去做个生意，别的办法都要比这个慢而且不扎实。"},{"book":"雪球专刊·特别版：段永平投资问答录投资逻辑篇","author":"雪球专刊","text":"我买股票时总是假设如果我有足够多的钱的话我是否会把整个公司买下来。"},{"book":"雪球专刊·特别版：段永平投资问答录投资逻辑篇","author":"雪球专刊","text":"查理和我过去在上百只股票上有过做空的想法，如果我们实施了，我们可能已经变成了穷光蛋。泡沫的演化基于人性，没有人知道什么时候它会破裂，或在破裂之前它会膨胀到多大。"},{"book":"雪球专刊·特别版：段永平投资问答录投资逻辑篇","author":"雪球专刊","text":"我总是觉得很多时候人们太注意所谓成功人士都干了啥，但就是不注意他们不干啥，而往往不干什么是决定成功的最重要因素（当然是在也干点什么的前提下）。"},{"book":"资本5000年：资本秩序如何塑造人类文明（典藏版）","author":"彭兴庭","text":"世人以上帝之名去干许多事，却必须以黄金、白银来衡量这些事的结果。"},{"book":"资本5000年：资本秩序如何塑造人类文明（典藏版）","author":"彭兴庭","text":"通过城市化和专业分工，在资本的催化下，古希腊通过与周边农业帝国的交换，建立了一个相对较小的、以资本为纽带的耗散型结构体系，第一次摆脱人类原始的增长方式，踏入非线性的内生型经济增长模式。"},{"book":"AI 3.0","author":"梅拉妮·米歇尔","text":"杰文斯悖论：技术进步可以提高自然资源的利用效率，但结果是增加而不是减少人们对这种资源的需求，因为效率的提高会导致生产规模的扩大，这会进一步刺激需要。"},{"book":"破茧","author":"施展","text":"社会学创始人之一涂尔干的研究告诉我们，仪式是人们获得共同体意识的重要途径。所以，这些固定播放的节目让人们在无意识中获得了共同体意识。"},{"book":"债：5000年债务史","author":"大卫·格雷伯","text":"然而中国的参与引入了一个全新的元素。完全有理由相信，从中国的角度来看，这是把美国降低为一个类似于中国传统附庸国的极其漫长过程的第一步。"},{"book":"债：5000年债务史","author":"大卫·格雷伯","text":"皮埃尔·布尔迪厄后来在描述当代阿尔及利亚一个类似的信用经济体时指出：荣誉易于转化为金钱，但金钱难以转化为荣誉。"},{"book":"债：5000年债务史","author":"大卫·格雷伯","text":"儒家正统学说公开敌视商人，乃至牟利动机本身。合理的利润是对商人将财货从一个地方运到另一个地方所花费的劳动的酬劳，而不应该是投机的成果。这意味着，实际上儒家正统学说支持市场，但反对资本主义。"},{"book":"债：5000年债务史","author":"大卫·格雷伯","text":"我将把这称为“底线共产主义”：除非人们认定对方是敌人，否则如果人们意识到需求足够大，或者成本足够合理，那么“各尽所能，按需分配”的原理就将被应用。"},{"book":"血路：革命中国中的沈定一（玄庐）传奇","author":"萧邦奇","text":"沈定一的思想就在这种与外界的交流中得以发展,且这种发展最初也没有表现出泾渭分明的特殊的意识形态认同或倾向——社会主义者、无政府主义者或保守主义者——这一切说明在革命过程中,参与革命本身带有随机性。"},{"book":"市场推手：纳斯达克CEO自述","author":"罗伯特·格雷菲尔德","text":"在每一次的销售游说中，我们似乎不是利用这种关系获得优势，就是竭尽全力摆脱品牌的束缚。"},{"book":"市场推手：纳斯达克CEO自述","author":"罗伯特·格雷菲尔德","text":"辩论的目的不是实现完美的民主理想，而是让所有相关事宜变得更清晰，让每个人都理解提议改变的原因，以及表明我的决策是透明的，并获得更充分的信息。"},{"book":"机器人大师（全集）","author":"[波兰]斯坦尼斯瓦夫·莱姆","text":"就好像某种新药的发明者并不是为了让已有药物的发明者身败名裂，他们发明新药是为了一起与病魔作斗争。所以新世界的创造者为什么要反对原有世界的造物者呢？"},{"book":"机器人大师（全集）","author":"[波兰]斯坦尼斯瓦夫·莱姆","text":"你没有对世界做改动，你只是想要改造世界中的人。不过请你原谅，我不得不说，你这么做实在是本末倒置，不懂章法。大家都听说过装修房子，谁听说过去别人房子里装修人的？我想要制造出替代物。"},{"book":"宇宙","author":"卡尔·萨根","text":"全世界所有书籍里的信息加起来也没有美国一座大城市一年的电视播放数据多。并不是每个比特都具有相等的价值。"},{"book":"宇宙","author":"卡尔·萨根","text":"农业的本质不过是以植物作为介质系统性地收集阳光。"},{"book":"宇宙","author":"卡尔·萨根","text":"人类生于群星，暂居于地球，现在终于开始了漫长的返乡之旅。"},{"book":"未来学大会（译林幻系列）","author":"[波兰]斯坦尼斯瓦夫·莱姆","text":"药理统治既有公开的一面，也有秘密的一面。前者的基础是后者。”"},{"book":"惨败（译林幻系列）","author":"[波兰]斯坦尼斯瓦夫·莱姆","text":"侦察任务的每一位参与者，都必须至少有一项专长跟另一人一致。这样的话，如果出现事故或疾病，整个队伍的功能仍然完整。"},{"book":"其主之声（译林幻系列）","author":"[波兰]斯坦尼斯瓦夫·莱姆","text":"有人可能会认为，如果一个人同意参与此类工作，并且良心上十分不安，那么他就更有可能带领队伍在关键时刻扛住压力；如果是一个毫无道德顾虑的人顶替了他的位置，那就绝对没有抵抗的可能。"},{"book":"其主之声（译林幻系列）","author":"[波兰]斯坦尼斯瓦夫·莱姆","text":"尽管在接收到来自群星的信息之后，我们的所作所为无异于一个野蛮人为了取暖而燃烧智者所著的书籍，他还认为自己捡了大便宜！"},{"book":"被淹没与被拯救的","author":"普里莫·莱维","text":"生活的目标是对死亡最好的防御，这不仅适用于集中营的生活。"},{"book":"沸腾新十年：移动互联网丛林里的勇敢穿越者（上）","author":"林军 胡喆","text":"张小龙坚持认为，当一个平台只是追求自身商业利益最大化的时候，它是短视的、不长久的；当一个平台可以造福人的时候，它才是有生命力的。"},{"book":"沸腾新十年：移动互联网丛林里的勇敢穿越者（上）","author":"林军 胡喆","text":"2012年，是新供给形成的一年，它们大多有一个共同的特征——深入挖掘智能手机某个传感器的功能，形成应用创新，再以这个创新为起点进行某个领域的模式变革。"},{"book":"沸腾新十年：移动互联网丛林里的勇敢穿越者（上）","author":"林军 胡喆","text":"关明生对他们说：“如果你们的广告是打给商家看的，那再好的广告也不如执行有力的线下队伍；如果你们的广告是打给消费者看的，那线上的转化效果超过线下很多，线下广告的打法更多是塑造品牌而不是带来流量。”"},{"book":"沸腾新十年：移动互联网丛林里的勇敢穿越者（上）","author":"林军 胡喆","text":"同时，王兴再度谈到商家推广之难，并得出了大型商家有门户、中小商家有百度、本地小微商家需要美团的三重金字塔理论，这个理论是当时所有讲团购的理论中最透彻的一个。"},{"book":"沸腾新十年：移动互联网丛林里的勇敢穿越者（上）","author":"林军 胡喆","text":"如果一个员工的拜访率高，就容易出业绩，有成就感，能增加收入，也就更愿意留下来。"},{"book":"沸腾新十年：移动互联网丛林里的勇敢穿越者（上）","author":"林军 胡喆","text":"牢牢抓住基本需求、极度重视用户体验、充分考虑到了早期流量费用较贵问题、想办法替用户省钱、漂亮的界面等，都是墨迹天气成功的重要因素。"},{"book":"沸腾新十年：移动互联网丛林里的勇敢穿越者（上）","author":"林军 胡喆","text":"他认为移动互联网是一种理念，理念理解到位了，在很差的技术环境里也能做出令人惊艳的产品。"},{"book":"沸腾新十年：移动互联网丛林里的勇敢穿越者（上）","author":"林军 胡喆","text":"王江反复阐述的概念是：颠覆PC互联网，用小屏幕结合智能手机硬件做出大的体验改变，才是移动互联网创业可能找到的机会。"},{"book":"祥瑞：王莽和他的时代","author":"张向荣","text":"王莽称帝的真正推手是无形的经学主张，他真正的统治基础是儒家士大夫们。这些人不是血缘的集合，而是经学或者说意识形态的聚拢。"},{"book":"理性乐观派（典藏版）","author":"马特·里德利","text":"农业就是专业化和交换的延伸，把其他物种也囊括了进来。"},{"book":"理性乐观派（典藏版）","author":"马特·里德利","text":"对亚当·斯密来说，资本“就是一定数量的堆积存储起来的劳动力，在必要的时候，用到其他的场合去”。"},{"book":"理性乐观派（典藏版）","author":"马特·里德利","text":"将来的企业不过是人员的临时聚合体，帮助人们从事方便他人消费的生产活动。"},{"book":"理性乐观派（典藏版）","author":"马特·里德利","text":"根据定义，政治决议是垄断性的，是多数派的暴政和专制，可市场极为擅长满足少数派的需求。"},{"book":"体验引擎：游戏设计全景探秘","author":"西尔维斯特","text":"为什么我们没有从经验中吸取教训呢？因为存在“后见偏差”（hindsight bias）。 后见偏差是一种认知偏差，它会悄声无息地将记忆中的内容重新编排，使得曾经发生的事情看起来比实际上更容易被预测。"},{"book":"体验引擎：游戏设计全景探秘","author":"西尔维斯特","text":"没有人只是玩游戏本身，人们是根据他们已经了解的内容来玩游戏的。这就意味着，设计师决不能忽略营销因素。"},{"book":"体验引擎：游戏设计全景探秘","author":"西尔维斯特","text":"有些游戏甚至根本不会尝试做到奖励的一致性。这种游戏的全部设计理念都围绕着如何创建强有力和可持续的动机，而不管对核心体验的影响如何。虽然这种做法可以让玩家留在游戏中，但是最终会导致玩家产生悔恨感。"},{"book":"体验引擎：游戏设计全景探秘","author":"西尔维斯特","text":"人类大脑是在缺乏现代游戏概念的环境下进化的，所以大脑并不能分辨出奖励是真实的还是虚拟的。虚拟的奖励所引发的动机通常不会和真实的奖励一样强烈，但是它们仍然保留着和真实的奖励类似的效果。"},{"book":"体验引擎：游戏设计全景探秘","author":"西尔维斯特","text":"多人游戏的设计必须足够健壮，以便能够应对玩家引发的各种混乱场面，比如半途退出，进行蓄意破坏，遗漏了关键技巧，或者用错误的方式进行游戏等等。"},{"book":"体验引擎：游戏设计全景探秘","author":"西尔维斯特","text":"真正重要的并不是双方火拼时的决策，而是玩家在没有看到敌人时所确定的决策。"},{"book":"体验引擎：游戏设计全景探秘","author":"西尔维斯特","text":"我们发现人类总是可以凭借直觉找到最优化的混合策略。"},{"book":"体验引擎：游戏设计全景探秘","author":"西尔维斯特","text":"但是我们改进了游戏的平衡性吗？明显没有，游戏深度并没有增加，游戏只是变得更复杂了而已。增加更多的可选策略并没有让游戏变得更好玩。"},{"book":"体验引擎：游戏设计全景探秘","author":"西尔维斯特","text":"玩家总是在寻找策略退化，但内心却希望找不到这样的策略。"},{"book":"体验引擎：游戏设计全景探秘","author":"西尔维斯特","text":"如果我们希望一个决策有意义，那么它的结果既不能无法预料，也不能无法避免。也就是说，决策的结果必须能够被部分预测。"},{"book":"体验引擎：游戏设计全景探秘","author":"西尔维斯特","text":"一个游戏想要持久地获得成功，必须使用新技术给玩家带来前所未体验过的交互和场景。"},{"book":"体验引擎：游戏设计全景探秘","author":"西尔维斯特","text":"和计算机对弈并获胜的感觉，和与人对弈并获胜的感觉不尽相同，即便每一步棋都一样。这是因为击败真正的人增加了情感上的社交意义。"},{"book":"体验引擎：游戏设计全景探秘","author":"西尔维斯特","text":"如果在经历了一长串的信息构建之后，所有这些信息各归其位，产生了明确的含义，这就是最棒的领悟方式。"},{"book":"体验引擎：游戏设计全景探秘","author":"西尔维斯特","text":"在线游戏为数亿玩家创造目标、荣耀、交互和情感，它击中了人类幸福的核心，并且将现实世界中匮乏的奖励、挑战和伟大的胜利呈现在我们的面前。"},{"book":"体验引擎：游戏设计全景探秘","author":"西尔维斯特","text":"一个利用潜意识沉思的方法是：交替地思考不同的问题。当我们思考一个问题时，我们的潜意识会思考另外一个问题。这就是为什么爱迪生、达尔文、达芬奇、米开朗基罗，以及梵高都会同时进行多项工作的原因。"},{"book":"癌症传（新版）","author":"悉达多·穆克吉","text":"他们也没必要等到我们在基础研究领域解决全部问题之后再提出治愈癌症的最佳方案……在医学史上，这种治疗手段先于作用机理数年、数十年甚至数百年问世的成功案例比比皆是。￼"},{"book":"癌症传（新版）","author":"悉达多·穆克吉","text":"或许世上唯一的原罪就是缺乏耐心。 因为缺乏耐心，我们被逐出了天堂； 因为缺乏耐心，我们再也不能返回。￼ ——弗朗茨·卡夫卡"},{"book":"癌症传（新版）","author":"悉达多·穆克吉","text":"16世纪的内科医生帕拉塞尔苏斯（Paracelsus）曾经认为药物就是伪装的毒药。￼其实人们在憧憬通过化疗消灭癌细胞的过程中也借鉴了逆向思维的逻辑：毒药也可能是隐藏的良方。"},{"book":"癌症传（新版）","author":"悉达多·穆克吉","text":"时至今日，医学界‘治疗’癌症的方法仍然只有以下两种：切除与破坏病变组织（前者通过手术，后者通过X射线）。"},{"book":"腾讯传1998-2016：中国互联网公司进化论","author":"吴晓波","text":"高级别的文明体从来都是在异常困难而非异常优越的环境中降生的。挑战越大，刺激越强"},{"book":"腾讯传1998-2016：中国互联网公司进化论","author":"吴晓波","text":"开辟疆土是相对容易的，但如果统治能力的半径达不到疆域的半径的话，这样的帝国难以持久。"},{"book":"腾讯传1998-2016：中国互联网公司进化论","author":"吴晓波","text":"生活如一条大河，所谓的“源头”都是后来者标示的产物。"},{"book":"腾讯传1998-2016：中国互联网公司进化论","author":"吴晓波","text":"望远镜的特点是：焦距越大，视野越小，望得越远。面对远处的未知迷雾，人们很难摆脱短视的袭扰，而只有把焦距拉大并将视线聚焦于一点，方可能稍稍看清真相的某一部分。"},{"book":"腾讯传1998-2016：中国互联网公司进化论","author":"吴晓波","text":"不要告诉我世界是怎样的，告诉我如何创造世界"},{"book":"腾讯传1998-2016：中国互联网公司进化论","author":"吴晓波","text":"小步、迭代、试错、快跑"},{"book":"腾讯传1998-2016：中国互联网公司进化论","author":"吴晓波","text":"“成长四阶段”论，即积累资源、资源的合理化利用、持续增长和对扩展中的资源的合理利用"},{"book":"腾讯传1998-2016：中国互联网公司进化论","author":"吴晓波","text":"裂变中的互联网经济仍然存在巨大的不确定性，由此造成了观察和定义的困难。"},{"book":"我们为什么要睡觉？","author":"马修·沃克","text":"美国企业家E·约瑟夫·科斯曼(E.Joseph Cossman)关于睡眠和情感的独到见解对这一部分进行总结：“绝望和希望之间的最佳桥梁是一场良好的睡眠。”"},{"book":"我们为什么要睡觉？","author":"马修·沃克","text":"在比赛中打破奥运会纪录的可能性与一天中的时间段有关，这并非巧合；破纪录的可能性会在人类昼夜节律的自然高峰（下午的早些时候）达到最大极限。"},{"book":"我们为什么要睡觉？","author":"马修·沃克","text":"睡眠是健康三要素（睡眠、饮食、运动）中最重要的。一晚糟糕睡眠所造成的身体和精神损害之严重，会让那些因食物或运动缺乏而引起的损害相形见绌。"},{"book":"第三种黑猩猩","author":"贾雷德·戴蒙德","text":"简而言之，尼安德特人的工具在不同的时空中都没有变化，因此缺乏人类最重要的素质——创新。"},{"book":"零售的哲学","author":"铃木敏文","text":"如果觉得厉害，就应该去分析具体是哪里厉害，并思考伊藤洋华堂如何才能做到这一步。"},{"book":"零售的哲学","author":"铃木敏文","text":"总之，我们不要把网络零售视为竞争对手，而应该通过网络和实体店铺的互相融合，进一步拓宽经营的可能性。"},{"book":"零售的哲学","author":"铃木敏文","text":"“滞销”并不是时代的过错，只说明消费者正在追求新的产品价值。"},{"book":"零售的哲学","author":"铃木敏文","text":"经营的过程中执著于出奇制胜或乘虚而入是无法长久的。当你顺应变化思考，答案自然会了然于心。"},{"book":"零售的哲学","author":"铃木敏文","text":"真正的竞争对手并不是其他品牌的便利店，而是不断变化的“客户需求”。"},{"book":"零售的哲学","author":"铃木敏文","text":"一双不会盲目轻信数据的眼睛，能在第一时间捕捉数据出现的细微变化，并深层次地思考变化的原因。"},{"book":"零售的哲学","author":"铃木敏文","text":"实现机遇并不需要特殊的才能，关键在于问题意识和思维力。其中，问题意识指能经常主动研究现行的工作模式是不是处于最优的状态。而思维力代表了深层次挖掘事物本质的能力。"},{"book":"零售的哲学","author":"铃木敏文","text":"灵活应对变化，贯彻基本原则"},{"book":"零售的哲学","author":"铃木敏文","text":"从变化中读懂“未来”，建立“假设”然后“执行”，再对结果进行“验证”。"},{"book":"侠隐（姜文《邪不压正》原著）","author":"张北海","text":"这么年轻，有说有笑，无忧无愁，李天然真觉得自己过了好几辈子。"},{"book":"侠隐（姜文《邪不压正》原著）","author":"张北海","text":"燕子归时，更能消几番风雨； 夕阳无语，最可惜一片江山。"},{"book":"故事：材质、结构、风格和银幕剧作的原理","author":"罗伯特·麦基","text":"我们快乐的深度和我们所经受的苦难是成正比的。"},{"book":"故事：材质、结构、风格和银幕剧作的原理","author":"罗伯特·麦基","text":"当面临那些不可调和的选择时，如进度VS移情，明智的作家会对故事进行重新设计，以保留其精华。你可以自由地打破或篡改常规，但只能出于一个原因：为了用某种更加重要的东西来取代它。"},{"book":"将心注入","author":"霍华德·舒尔茨 多莉·琼斯·扬","text":"我 时时刻刻琢磨着星巴克的事儿。虽说它比我在纽约工作过的跨国企业小得多，但它却诱人得多，就像一段在你脑海中萦绕不去的爵士乐。我觉得自己有许多方式可以为它做些事情。"},{"book":"将心注入","author":"霍华德·舒尔茨 多莉·琼斯·扬","text":"有些人只看见事物的表面，他们问的是“为什么”，而我却想象事物从未呈现的一面，我问“为什么不”。 ——乔治·萧伯纳 这段名言经常被罗伯特·F·肯尼迪引用"},{"book":"向前一步","author":"谢丽尔·桑德伯格","text":"思考全球化、行动本土化。”在谈判时，要做到“思考个人化，行动公共化”。"},{"book":"向前一步","author":"谢丽尔·桑德伯格","text":"如果一个人总是等着别人告诉自己该做什么，我们就很难设想他能成为领导别人的人"},{"book":"支付战争","author":"[美]杰克逊","text":"正如编程部门的一个同事所说的，没必要为了交换比特而移动原子。"},{"book":"人类简史：从动物到上帝","author":"尤瓦尔·赫拉利","text":"以上两种论点都有一个共同假设：快乐是一种主观感受（不管是感官的快感还是生命有意义），而想要判断快不快乐，靠的就是直接问他们的感受。"},{"book":"人类简史：从动物到上帝","author":"尤瓦尔·赫拉利","text":"如果快乐是在于感受快感，想要更快乐，就得操纵我们的生化系统。如果快乐是在于觉得生命有意义，想要更快乐，就得要骗自己骗得更彻底。"},{"book":"人类简史：从动物到上帝","author":"尤瓦尔·赫拉利","text":"所谓的快乐，很可能只是让个人对意义的错觉和现行的集体错觉达成同步而已。"},{"book":"人类简史：从动物到上帝","author":"尤瓦尔·赫拉利","text":"正如尼采所言，只要有了活下去的理由，几乎什么都能够忍受。"},{"book":"人类简史：从动物到上帝","author":"尤瓦尔·赫拉利","text":"快乐不只是“愉快的时刻多于痛苦的时刻”这么简单。相反，快乐要看的是某人生命的整体；生命整体有意义、有价值，就能得到快乐。快乐还有重要的认知和道德成分。"},{"book":"人类简史：从动物到上帝","author":"尤瓦尔·赫拉利","text":"快乐并不在于任何像是财富、健康甚至社群之类的客观条件，而在于客观条件和主观期望之间是否相符。"},{"book":"人类简史：从动物到上帝","author":"尤瓦尔·赫拉利","text":"大约在公元1500年，历史做出了最重大的选择，改变的不只是人类的命运，而是地球上所有生命的命运。我们将它称为“科学革命”"},{"book":"人类简史：从动物到上帝","author":"尤瓦尔·赫拉利","text":"历史的演进并不在意生物个体是否幸福"},{"book":"人类简史：从动物到上帝","author":"尤瓦尔·赫拉利","text":"自从法国大革命之后，全球人民逐渐同意“自由”和“平等”都是基本的价值观。然而这两者根本就互相抵触！想要确保“平等”，就得限制住那些较突出的人；而要人人都能“自由”，也就必然影响所有人的平等。"},{"book":"人类简史：从动物到上帝","author":"尤瓦尔·赫拉利","text":"三种全球秩序，首先第一种是经济上的货币秩序，第二种是政治上的帝国秩序，而第三种则是宗教上的全球性宗教，像是佛教、基督教和伊斯兰教。"},{"book":"人类简史：从动物到上帝","author":"尤瓦尔·赫拉利","text":"第二，就算身处不同阶级的人发展出了完全一样的能力，因为他们面对的游戏规则不同，最后结果也可能天差地别。"},{"book":"人类简史：从动物到上帝","author":"尤瓦尔·赫拉利","text":"通常把生物学上的区分称为“性”（sex），而文化上的区分称为“性别”（gender）。"},{"book":"人类简史：从动物到上帝","author":"尤瓦尔·赫拉利","text":"当然，天生自然的能力也很可能影响社会阶级差异，但是种种不同的能力和性格常常还是会受到想象阶级的影响。关于这一事实主要有两大方面。第一，也是最重要的一点，就是大多数的能力也需要培养和发展。"},{"book":"人类简史：从动物到上帝","author":"尤瓦尔·赫拉利","text":"如果人类的基因里并没有大规模合作的生物本能，所有的合作网络究竟如何维系？简单的讲法，是人类创造出了由想象建构的秩序、发明了文字，以这两者补足我们基因中的不足。"},{"book":"人类简史：从动物到上帝","author":"尤瓦尔·赫拉利","text":"演化观点并不是唯一判断物种成功与否的标准。它一切只考虑到生存和繁殖，而不顾个体的痛苦或幸福。"},{"book":"人类简史：从动物到上帝","author":"尤瓦尔·赫拉利","text":"自由人文主义追求的，是尽可能为个人争取更多自由；而社会人文主义追求的，则是让所有人都能平等。"},{"book":"人类简史：从动物到上帝","author":"尤瓦尔·赫拉利","text":"人工智能的领域还希望能够完全在计算机二进制的程序语言上创造一种新的智能。"},{"book":"人类简史：从动物到上帝","author":"尤瓦尔·赫拉利","text":"而这也正是文字对人类历史所造成最重要的影响：它逐渐改变了人类思维和看待这个世界的方式。过去的自由连接、整体思考，已经转变为分割思考、官僚制度。"},{"book":"人类简史：从动物到上帝","author":"尤瓦尔·赫拉利","text":"近来，数学符号已经带来另一种更革命性的文字系统，计算机所使用的二进制程序语言，全部只有两个符号：0与1。"},{"book":"人类简史：从动物到上帝","author":"尤瓦尔·赫拉利","text":"第三，也是最重要的一点，在于人类的大脑经过演化，只习惯储存和处理特定类型的信息。"},{"book":"人类简史：从动物到上帝","author":"尤瓦尔·赫拉利","text":"这样思考，是因为他们抛下了传统的人类思维方式，从头学习如何在外部数据处理系统的协助下思考。他们的思考过程有很重要的一部分并不是在他们的脑子里，而是在计算机里或是教室黑板上。"},{"book":"人类简史：从动物到上帝","author":"尤瓦尔·赫拉利","text":"只要能将信息转成数学符号，储存、传播和处理的速度和效率就能快到令人叹服。"},{"book":"人类简史：从动物到上帝","author":"尤瓦尔·赫拉利","text":"文字本来应该是人类意识的仆人，但现在正在反仆为主。计算机并无法理解智人如何说话、感觉和编织梦想，所以我们现在反而是用一种计算机能够理解的数字语言来教智人如何说话、感觉和编织梦想。"},{"book":"人类简史：从动物到上帝","author":"尤瓦尔·赫拉利","text":"苏美尔文字系统逐渐加入越来越多的符号，成为能够完整表意的文字，今天它们被称为楔形文字。"},{"book":"人类简史：从动物到上帝","author":"尤瓦尔·赫拉利","text":"我们还需要有组织工具（像是编目）、快速的复制工具（像是复印机）、快速准确的检索工具（像是计算机运算），而且还得有够聪明（最好心情还能好一些）的负责人员，能够了解这些工具的使用方法。"},{"book":"人类简史：从动物到上帝","author":"尤瓦尔·赫拉利","text":"人类的大脑并不是个很好的储存设备，主要原因有三。 第一，大脑的容量有限。"},{"book":"人类简史：从动物到上帝","author":"尤瓦尔·赫拉利","text":"第二，人类总难免一死，而大脑也随之死亡。"},{"book":"人类简史：从动物到上帝","author":"尤瓦尔·赫拉利","text":"文字最重要的任务仍然是记录大量的数字数据"},{"book":"人类简史：从动物到上帝","author":"尤瓦尔·赫拉利","text":"1.想象建构的秩序深深与真实的世界结合。"},{"book":"人类简史：从动物到上帝","author":"尤瓦尔·赫拉利","text":"不管是古代美索不达米亚的城市，还是秦朝和古罗马的帝国，都只是“由想象所建构的秩序”。支持它们的社会规范既不是人类自然的天性本能，也不是人际的交流关系，而是他们都相信着共同的虚构神话故事。"},{"book":"人类简史：从动物到上帝","author":"尤瓦尔·赫拉利","text":"2.想象建构的秩序塑造了我们的欲望。"},{"book":"人类简史：从动物到上帝","author":"尤瓦尔·赫拉利","text":"为了改变现有由想象建构出的秩序，就得先用想象建构出另一套秩序才行。"},{"book":"人类简史：从动物到上帝","author":"尤瓦尔·赫拉利","text":"演化的基础是差异，而不是平等。每个人身上带的基因码都有些许不同，而且从出生以后就接受着不同的环境影响，发展出不同的特质，导致不同的生存概率。“生而平等”其实该是“演化各有不同”。"},{"book":"人类简史：从动物到上帝","author":"尤瓦尔·赫拉利","text":"3.想象建构的秩序存在于人和人之间思想的连接。"},{"book":"人类简史：从动物到上帝","author":"尤瓦尔·赫拉利","text":"整个动物界从古至今，最重要也最具破坏性的力量，就是这群四处游荡、讲着故事的智人。"},{"book":"人类简史：从动物到上帝","author":"尤瓦尔·赫拉利","text":"我们必然需要问一些目前还没有解答的问题，否则就等于对人类7万年历史中的6万年视而不见，只以为“当时的人没做什么重要的事”。"},{"book":"人类简史：从动物到上帝","author":"尤瓦尔·赫拉利","text":"除了存在于人类共同的想象之外，这个宇宙中根本没有神、没有国家、没有钱、没有人权、没有法律，也没有正义。"},{"book":"人类简史：从动物到上帝","author":"尤瓦尔·赫拉利","text":"就算是大批互不相识的人，只要同样相信某个故事，就能共同合作。"},{"book":"人类简史：从动物到上帝","author":"尤瓦尔·赫拉利","text":"“虚构”这件事的重点不只在于让人类能够拥有想象，更重要的是可以“一起”想象"},{"book":"公正：该如何做是好？","author":"迈克尔·桑德尔","text":"40年之后，在2008年的总统竞选中，巴拉克·奥巴马同样触及了美国人对那种具有更高目的的公共生活的渴望，并阐明了一种具有道德和精神希冀的政治。"},{"book":"公正：该如何做是好？","author":"迈克尔·桑德尔","text":"这就是意志自由和康德的道德观念之间的联系。自由地行动并不是为给定的目的选择最佳的方式，而是选择目的本身—这是一种人类可以做出，而台球（以及大多数动物）却不能做出的选择。"},{"book":"公正：该如何做是好？","author":"迈克尔·桑德尔","text":"如果某些权利在这方面是根本性的—假如它们是自然的、神圣的、不可剥夺的和无条件的—我们该如何甄别它们呢？又是什么使得它们具有这样的根本性呢？"},{"book":"公正：该如何做是好？","author":"迈克尔·桑德尔","text":"使福利最大化、尊重自由和促进德性"},{"book":"公正：该如何做是好？","author":"迈克尔·桑德尔","text":"这一困境引出了政治哲学中的一个重要问题：一个公正的社会应当努力推进其公民的德性吗？或者，法律是否应当在各种德性观念保持中立，以使公民们能够自由地为自己选择最佳的生活方式？"},{"book":"公正：该如何做是好？","author":"迈克尔·桑德尔","text":"这种情绪经常被看做是一种原始的、不应当干涉公共政策或法律的感情而被摒弃。"},{"book":"公正：该如何做是好？","author":"迈克尔·桑德尔","text":"其目的并非在于向人们展示在政治思想史中谁影响了谁，而在于促使读者将自己关于公正的观念付诸批判性的检验，了解自己的真实想法，以及这些想法来自何处。"},{"book":"公正：该如何做是好？","author":"迈克尔·桑德尔","text":"某些道德困境源于相互冲突的道德原则。"},{"book":"反脆弱：从不确定性中获益","author":"纳西姆·尼古拉斯·塔勒布","text":"对于会自然消亡的事物，生命每增加一天，其预期寿命就会缩短一些。而对于不会自然消亡的事物，生命每增加一天，则可能意味着更长的预期剩余寿命。"},{"book":"乡土中国","author":"费孝通","text":"两者所以合，那是因为欲望并非生物事实，而是文化事实。我说它是文化事实，意思是人造下来教人这样想的。"},{"book":"解读中国经济","author":"林毅夫","text":"利用一个国家的比较优势来发展经济的政策，可以让一个发展中国家充分利用跟发达国家之间的技术差距，以低成本引进技术的方式来加快经济发展，而实现在收入、产业和技术水平上向发达国家的收敛。"},{"book":"解读中国经济","author":"林毅夫","text":"资本来自于剩余的积累，要最快地提升一个国家的要素禀赋结构，这个国家就必须在每一个时点创造最大的剩余，并将剩余中最大的部分用来作为积累。"},{"book":"解读中国经济","author":"林毅夫","text":"当前的分配制度是初次分配注重效率，也就是说初次分配可以不照顾公平，然后由二次分配再来解决公平的问题，这样做的结果往往是既不能实现效率，也无法达到公平。"},{"book":"解读中国经济","author":"林毅夫","text":"从1978年到1996年，出现了三轮的“放权—通货膨胀—整顿混乱—经济发展缓慢—放权”这样的“一放就活、一活就乱、一乱就收、一收就死”的周期循环"},{"book":"解读中国经济","author":"林毅夫","text":"1949年到1978年，计划经济从探索到实行也是28年，与建立新中国所花的时间一样长，后来证明这套制度行不通，所以需要转型与改革。"},{"book":"解读中国经济","author":"林毅夫","text":"从1921年建立到1949年，不过短短28年，差不多一代人的时间，中国共产党就从一个由几个知识分子推动社会运动的组织变成了统一中国的政党"},{"book":"解读中国经济","author":"林毅夫","text":"按照马克思的历史唯物主义，社会主义革命只有在资本家与工人阶级的矛盾积累到一定程度后才会爆发。资本家掌握了政权、财富，单个工人没法抵抗资本家的剥削和压迫，就需要把整个工人阶级联合起来。"},{"book":"解读中国经济","author":"林毅夫","text":"经济学家通常认为技术是一种关于怎样组织各种投入要素生产某种产品的知识"},{"book":"解读中国经济","author":"林毅夫","text":"做学问来说，指出现有理论的不足只是第一步，更重要的是能否在总结现有理论的基础之上提出一个能合理解释同样现象的新理论。"},{"book":"解读中国经济","author":"林毅夫","text":"个经济的开放程度通常由对外贸易占GDP的比重，即“对外贸易依存度”来衡量"},{"book":"一本书读懂财报","author":"肖星","text":"资产负债表和利润表告诉我们公司的运营情况，现金流量表告诉我们公司的风险状况，通俗点概括：如果资产负债表和利润表说这个公司好，说明它赚钱；现金流量表说这个公司好，说明它有钱。"},{"book":"一本书读懂财报","author":"肖星","text":"无论企业做了多少事，在会计眼中，其实就只有这三件事儿——经营、投资、融资"},{"book":"一本书读懂财报","author":"肖星","text":"企业一辈子其实只做了三件事：经营、投资和融资"},{"book":"一本书读懂财报","author":"肖星","text":"资产负债表、利润表和现金流量表三张财务报表"},{"book":"邓小平时代","author":"傅高义","text":"毅力、坚韧和十足的自信"},{"book":"邓小平时代","author":"傅高义","text":"如果不能比资本主义国家发展得更快，就无法证明我们的制度的优越性。"},{"book":"邓小平时代","author":"傅高义","text":"他已经在最高层积累了有关党政军各方面工作的不同寻常的深厚经验，熟知所有重大的内政外交问题，这构成了他反思中国如何进行改革的基础。"},{"book":"邓小平时代","author":"傅高义","text":"它不是组织有序的革命力量带来的结果，而是对帝国体制失效做出的反应。"},{"book":"邓小平时代","author":"傅高义","text":"1978年的邓小平，在思考中国最高领导人领导国家的战略方面已积累了50年的经验。"},{"book":"邓小平时代","author":"傅高义","text":"毛确实犯了严重的错误，但在邓小平看来，更大的问题是导致这些错误的制度缺陷"},{"book":"游戏改变世界","author":"简·麦戈尼格尔","text":"2006年，科技记者杰夫·豪（Jeff Howe）创造了“众包”这个词，是指将一份工作外包给群众。它的意思是，在互联网上邀请一大群人，合作解决大型的项目。"},{"book":"游戏改变世界","author":"简·麦戈尼格尔","text":"游戏不一定非得是电脑程序，它也可以像国际象棋或躲猫猫那么简单，只是一套玩家可以彼此传递的规则。"},{"book":"游戏改变世界","author":"简·麦戈尼格尔","text":"抛开类型的差异和复杂的技术，所有的游戏都有4个决定性特征：目标、规则、反馈系统和自愿参与。"},{"book":"必然（KK三部曲·展望）","author":"[美]凯文·凯利","text":"我们考察一样东西的价值，不再仅仅针对它所包含的原子。这件东西的非物质成分、设计，甚至是它根据我们的需求灵活变化的能力，也都会成为衡量价值的因素。"},{"book":"必然（KK三部曲·展望）","author":"[美]凯文·凯利","text":"解释性（Interpretation）"},{"book":"必然（KK三部曲·展望）","author":"[美]凯文·凯利","text":"个性化（Personalization）"},{"book":"必然（KK三部曲·展望）","author":"[美]凯文·凯利","text":"获取权（Accessibility）"},{"book":"必然（KK三部曲·展望）","author":"[美]凯文·凯利","text":"即时性（Immediacy）"},{"book":"必然（KK三部曲·展望）","author":"[美]凯文·凯利","text":"对于我们那不知足的人类欲望来说，梦想的确成真了：永无止境的改进，汇聚成了一条条河流。"},{"book":"必然（KK三部曲·展望）","author":"[美]凯文·凯利","text":"可靠性（Authenticity）"},{"book":"必然（KK三部曲·展望）","author":"[美]凯文·凯利","text":"实体化（Embodiment）"},{"book":"必然（KK三部曲·展望）","author":"[美]凯文·凯利","text":"可寻性（Discoverability）"},{"book":"必然（KK三部曲·展望）","author":"[美]凯文·凯利","text":"和信任一样难以复制的特性还有很多，它们成为了云端经济的价值所在。"},{"book":"必然（KK三部曲·展望）","author":"[美]凯文·凯利","text":"可赞助（patronage）"},{"book":"必然（KK三部曲·展望）","author":"[美]凯文·凯利","text":"大约500年前，科技推翻了言语。1440年，古登堡发明了金属制成的活字，将写作提升到了文化的中心位置。"},{"book":"必然（KK三部曲·展望）","author":"[美]凯文·凯利","text":"“组成宇宙的是故事，而非原子。”"},{"book":"天生就会跑","author":"克里斯托弗·麦克杜格尔","text":"而他学到的一切都没有记载，只保存在他自己的肌肉里。"},{"book":"硅谷钢铁侠：埃隆·马斯克的冒险人生","author":"阿什利·万斯","text":"SpaceX的根本目标一直是创造能够在火星上生存的技术。如果成为一家上市公司会降低创造这种技术的可能性，那么我们在火星计划确定以前就不应该上市。"},{"book":"硅谷钢铁侠：埃隆·马斯克的冒险人生","author":"阿什利·万斯","text":"马斯克的孩子们没有吃过他那样的苦，这让他觉得很苦恼。他觉得吃苦帮助他成为现在的自己，给了他额外的力量和意志"},{"book":"硅谷钢铁侠：埃隆·马斯克的冒险人生","author":"阿什利·万斯","text":"他们小时候经常一起去参加冒险活动，希望通过这样的长途跋涉为自己的生意找到一点灵感。"},{"book":"硅谷钢铁侠：埃隆·马斯克的冒险人生","author":"阿什利·万斯","text":"马斯克对此给出的解释是当时特斯拉有更重要的事情有待解决。“我们必定会信守诺言，有时候可能因为客观原因不能马上兑现，但总有一天我们会做到所承诺的事情。”"},{"book":"硅谷钢铁侠：埃隆·马斯克的冒险人生","author":"阿什利·万斯","text":"马斯克在Model S发布会结束后接受媒体采访时说道，“我也许低估了完成某些任务所需要的时间，但是最终结果一定令人满意。事实证明，我做到了我承诺的所有事情。”"},{"book":"硅谷钢铁侠：埃隆·马斯克的冒险人生","author":"阿什利·万斯","text":"不管特斯拉拿了政府多少钱，又把电动车这一噱头炒作得多么炙手可热，这个公司和团队的的确确在为开辟电动汽车前景的远大目标一步一个脚印地付出努力，并且在此过程中为成千上万的人创造了就业机会。"},{"book":"硅谷钢铁侠：埃隆·马斯克的冒险人生","author":"阿什利·万斯","text":"我们首先要决定世界上最好的遮阳板是什么样子的，然后做得比那更好。”马斯克一边说，几个助手一边在车外记录着。"},{"book":"硅谷钢铁侠：埃隆·马斯克的冒险人生","author":"阿什利·万斯","text":"马斯克说：“我知道我们肯定能做到，只是花多少精力和时间的问题。”"},{"book":"硅谷钢铁侠：埃隆·马斯克的冒险人生","author":"阿什利·万斯","text":"真正让人捏把汗的是建造用于制造车体以及相关部件的大型工厂。"},{"book":"硅谷钢铁侠：埃隆·马斯克的冒险人生","author":"阿什利·万斯","text":"零开始设计并建造一辆原型车总是会面临诸多挑战，但是更大的困难在于筹集大量资金和如何让汽车量产。"},{"book":"硅谷钢铁侠：埃隆·马斯克的冒险人生","author":"阿什利·万斯","text":"马斯克的这些公司尽可能从零开始，尝试重新思考航空航天、汽车和太阳能产业那些约定俗成的做法。"},{"book":"硅谷钢铁侠：埃隆·马斯克的冒险人生","author":"阿什利·万斯","text":"我认为现在有非常多的聪明人都在致力于互联网、金融和法律，”马斯克在路上说，“这是我们没能看到更多创新的部分原因。”"},{"book":"硅谷钢铁侠：埃隆·马斯克的冒险人生","author":"阿什利·万斯","text":"他常常引用丘吉尔的名言：“既然必须穿越地狱，那就走下去吧。”这种勇气往往会让人绝地逢生。"},{"book":"硅谷钢铁侠：埃隆·马斯克的冒险人生","author":"阿什利·万斯","text":"马斯克在采访中提及，他认为有5个领域将深刻影响人类的未来：互联网、新能源、太空探索、人工智能和生命科学。时至今日，他已经涉猎了前4个领域。"},{"book":"硅谷钢铁侠：埃隆·马斯克的冒险人生","author":"阿什利·万斯","text":"万斯坚信这种社会环境导致了马斯克从一开始便把拯救人类放在首位，而非解决南非一个国家乃至非洲这块大陆的问题。"},{"book":"千面英雄","author":"约瑟夫·坎贝尔","text":"他相信任何存在人类想象的地方都存在着神话，正是人类的想象赋予了神话生命。"},{"book":"千面英雄","author":"约瑟夫·坎贝尔","text":"“神话是公开的梦，梦是私人的神话”"},{"book":"千面英雄","author":"约瑟夫·坎贝尔","text":"令他同样十分着迷的还有每个神话描述的被他称作“人类同一个伟大故事”的方式"},{"book":"千面英雄","author":"约瑟夫·坎贝尔","text":"在研究宗教神话（“神话即人的另一个宗教”）时，他没有聚焦于“那里有什么”这类神学问题，而是对“为什么我们要讲述关于那些事物的故事（无论它们是什么）”做出了解答。"},{"book":"腾讯之道：我们应该向腾讯学什么？","author":"刘官华 艾永亮 梁璐","text":"保持了创业团队对业务的敏感和团队凝聚力的同时，又补充了职业经理人对公司业务和企业科学管理方面的能力。"},{"book":"穷查理宝典：查理·芒格智慧箴言录（全新增订本）","author":"彼得·考夫曼","text":"人类社会只有发明了发明的方法之后才能发展，同样道理，你们只有学习了学习的方法之后才能进步。"},{"book":"穷查理宝典：查理·芒格智慧箴言录（全新增订本）","author":"彼得·考夫曼","text":"简化任务的最佳方法一般是先解决那些答案显而易见的大问题"},{"book":"穷查理宝典：查理·芒格智慧箴言录（全新增订本）","author":"彼得·考夫曼","text":"向比我优秀的人学习几种有用的思维方法，帮助我自己避免犯一些我这个年龄段的人容易犯的大错"},{"book":"穷查理宝典：查理·芒格智慧箴言录（全新增订本）","author":"彼得·考夫曼","text":"人类的大脑需要理由才能更好地理解事情。你们应该把现实悬挂在附带理由的理论结构之上。"},{"book":"穷查理宝典：查理·芒格智慧箴言录（全新增订本）","author":"彼得·考夫曼","text":"爱因斯坦曾经很好地总结过这一点：“一切应该尽可能简单，但不能过于简单。”"},{"book":"穷查理宝典：查理·芒格智慧箴言录（全新增订本）","author":"彼得·考夫曼","text":"在大多数情况下，要说服一个人，从这个人的利益出发是最有效的。"},{"book":"穷查理宝典：查理·芒格智慧箴言录（全新增订本）","author":"彼得·考夫曼","text":"我们并不期待它会直线增长，只要价格适中，周期性增长我们也能接受。"},{"book":"穷查理宝典：查理·芒格智慧箴言录（全新增订本）","author":"彼得·考夫曼","text":"让人们抛弃最近大获成功的做法是有悖人类本能的。但这往往是个好主意。减少欲望，而不是为了满足欲望而增加风险也同样是个好主意。"},{"book":"穷查理宝典：查理·芒格智慧箴言录（全新增订本）","author":"彼得·考夫曼","text":"所以制定正确的激励机制是非常、非常重要的教训。"},{"book":"穷查理宝典：查理·芒格智慧箴言录（全新增订本）","author":"彼得·考夫曼","text":"他们并没有进行第二步分析——也就是弄清楚有多少钱会落在你手里，多少钱会流向消费者。"},{"book":"穷查理宝典：查理·芒格智慧箴言录（全新增订本）","author":"彼得·考夫曼","text":"如果你告诉人们事情的时候，总是告诉他们原因，他们就能更深刻地理解你说的话，就会更加重视你说的话，也会更倾向于听从你说的话。就算他们不理解你的理由，他们也会更倾向于听你的话。"},{"book":"穷查理宝典：查理·芒格智慧箴言录（全新增订本）","author":"彼得·考夫曼","text":"好奇、专注、毅力和自省"},{"book":"穷查理宝典：查理·芒格智慧箴言录（全新增订本）","author":"彼得·考夫曼","text":"直率和基于常识的敏锐商业触觉"},{"book":"穷查理宝典：查理·芒格智慧箴言录（全新增订本）","author":"彼得·考夫曼","text":"结合了极度的耐心和极度的决心"},{"book":"穷查理宝典：查理·芒格智慧箴言录（全新增订本）","author":"彼得·考夫曼","text":"你要寻找的是标错赔率的赌局。这就是投资的本质。你必须拥有足够多的知识，才能知道赌局的赔率是不是标错了。这就是价值投资。”"},{"book":"穷查理宝典：查理·芒格智慧箴言录（全新增订本）","author":"彼得·考夫曼","text":"通过逻辑、本能和直觉决定最具前景的投资“棋步”"},{"book":"穷查理宝典：查理·芒格智慧箴言录（全新增订本）","author":"彼得·考夫曼","text":"上面提到的这种机会很少，它们通常会落在不断地寻找和等待、充满求知欲望而又热衷于对各种不同的可能性作出分析的人头上。"},{"book":"穷查理宝典：查理·芒格智慧箴言录（全新增订本）","author":"彼得·考夫曼","text":"理性、客观、积极与睿智。他既不怨天尤人，也不消极放弃，在平静中积极地寻求应对方法"},{"book":"穷查理宝典：查理·芒格智慧箴言录（全新增订本）","author":"彼得·考夫曼","text":"我职业生涯中最大的失败并不是由我错误决定造成的损失（当然我的这类错误也绝不在少数），而是在这一段时间里不能够大量买进我喜欢的几只最优秀的股票。"},{"book":"成为乔布斯","author":"布伦特·施兰德 里克·特策利","text":"更重要的是你的野心到底是什么？你是否能够不断成长，从失败与挫折中重新站起来？是否能够为宏伟目标一往无前？是否能将自己的智慧、能量、天赋、才华与想法外化为推动事业发展的力量？这才是伟大领袖的特质。"},{"book":"成为乔布斯","author":"布伦特·施兰德 里克·特策利","text":"苹果公司并没有正式的研究部门，史蒂夫不喜欢把前瞻性的研究职责放到某一个独立的部门，因为这样一来，研究和产品开发就脱节了。"},{"book":"成为乔布斯","author":"布伦特·施兰德 里克·特策利","text":"史蒂夫也理解，对于和他一样优秀的人才来说，成就感是最好的激励方式。"},{"book":"成为乔布斯","author":"布伦特·施兰德 里克·特策利","text":"如果缺乏卓越的讲故事的能力，再宏大的目标都无济于事，这是显而易见的。"},{"book":"青年尼采作品：悲剧的诞生","author":"弗里德里希·尼采","text":"根本的问题只有一个，就是如何为本无意义的世界和人生创造出一种最有说服力的意义来。"},{"book":"青年尼采作品：悲剧的诞生","author":"弗里德里希·尼采","text":"前者体现为由酒神现象而理解希腊艺术进而提出为世界和人生作审美辩护的艺术形而上学这一条线索，后者体现为对苏格拉底科学乐观主义的批判这一条线索。"},{"book":"青年尼采作品：悲剧的诞生","author":"弗里德里希·尼采","text":"尼采当时主要关注两个问题，一是生命意义的解释，二是现代文化的批判。"},{"book":"亚历山大三部曲2：波斯少年","author":"玛丽·瑞瑙特","text":"一台悲剧……其悲哀在于主角们从未相遇"},{"book":"亚历山大三部曲2：波斯少年","author":"玛丽·瑞瑙特","text":"人的不死并非在于永远地活着，那愿望源自恐惧。令人不死的是每一个超脱于恐惧的瞬间。"},{"book":"牛津通识读本：佛学概论（中文版）","author":"关大眠","text":"悉达多意为“一切义成”（达到自己目的者）；而乔达摩则是族名，传自印度古代圣人。"},{"book":"长安十二时辰（全集）","author":"马伯庸","text":"深知很多事情并不需要搜考秘闻，真相就藏在人人可见的文卷之中，就看你能不能找出来——此所谓“大案牍”之术。"},{"book":"未来简史：从智人到智神","author":"尤瓦尔·赫拉利","text":"每次叙事自我要对我们的体验下判断时，并不会在意时间持续多长，只会采用“峰终定律”（peak-end rule），也就是只记得高峰和终点这两者，再平均作为整个体验的价值。"},{"book":"未来简史：从智人到智神","author":"尤瓦尔·赫拉利","text":"宗教最在乎的其实是秩序，宗教的目的就是创造和维持社会结构；而科学最在乎的则是力量，科学的目的是通过研究得到力量，以治疗疾病、征伐作战、生产食物。"},{"book":"未来简史：从智人到智神","author":"尤瓦尔·赫拉利","text":"先将“他者”称为野兽，之后才能待之以野兽。"},{"book":"未来简史：从智人到智神","author":"尤瓦尔·赫拉利","text":"“契诃夫法则”（Chekhov Law）。契诃夫有一句名言：在第一幕中出现的枪，在第三幕中必然会发射。"},{"book":"旧制度与大革命（精译·珍藏版）","author":"亚力克西·德·托克维尔","text":"照亮18世纪欧洲的火炬早在15世纪就被不费吹灰之力地熄灭了。要想使这种论据引发革命，人们的地位、习惯、风俗方面必须已经发生了某些变化，才能使人类的思想做好准备，接受这些学说。"},{"book":"浪漫主义的根源（人文与社会译丛）","author":"以赛亚·伯林著 亨利·哈代编","text":"要想了解希腊哲学，你得了解希腊艺术；要想了解希腊艺术，你得了解希腊历史；要想了解希腊历史，你得了解希腊地理，你得亲眼看到希腊人曾看到的植物，你得了解他们脚下的土壤，还有其他的事物，等等。"},{"book":"安娜·卡列尼娜（经典译林）","author":"列夫·托尔斯泰","text":"他看到满足于这种欲望，就是犯了人们常犯的那种无法挽救的错误，人们往往把欲望的满足看成幸福。"},{"book":"安娜·卡列尼娜（经典译林）","author":"列夫·托尔斯泰","text":"他们各人都以为自己所过的是唯一正确的生活，而别人却在虚度年华。"},{"book":"第二次世界大战回忆录（套装共12本）","author":"丘吉尔","text":"战争时：坚决刚毅 失败时：顽强不屈 胜利时：宽容敦厚 和平时：友好亲善"},{"book":"海权论（战争论丛书）","author":"马汉","text":"但是构成这种战术配合的一些原则，即选择敌队形最不易得到支援的部分，用优势兵力去攻击它，这些都还不曾过时。"},{"book":"海权论（战争论丛书）","author":"马汉","text":"在混战中，上述这些有利条件将不能充分利用，而运气将起最重要的作用，并且等于把他的舰队看作是一伙过去从没有在一起活动的舰艇凑集成的乌合之众。"},{"book":"海权论（战争论丛书）","author":"马汉","text":"若想取得战争的胜利，就必须认识战争的客观规律，将其抽象为战略战术，在客观条件许可范围内，运用从客观中抽象出来的战略战术指导战争"},{"book":"富兰克林自传","author":"[美]富兰克林","text":"按时代的要求完善自我，造福社会，一切从教育后人着眼。"},{"book":"黑客与画家（10万册纪念版）","author":"保罗·格雷厄姆","text":"慎重选择公理还不够，还必须控制它的规模。"},{"book":"黑客与画家（10万册纪念版）","author":"保罗·格雷厄姆","text":"有点像买房子的时候你应该先考虑地理位置。别的地方将来出问题都有办法弥补，但是地理位置是没法变的。"},{"book":"黑客与画家（10万册纪念版）","author":"保罗·格雷厄姆","text":"好设计是一种再设计。很少有人一次就把事情做对。专家的做法是先完成一个早期原型，然后提出修改计划，最后把早期原型扔掉。"},{"book":"黑客与画家（10万册纪念版）","author":"保罗·格雷厄姆","text":"在数学和工程学中，递归尤其有用。归纳式证明方法既简洁又美妙。在软件中，能用递归解决的问题通常代表已经找到了最佳解法。"},{"book":"黑客与画家（10万册纪念版）","author":"保罗·格雷厄姆","text":"对称有两种：重复性对称和递归性对称。"},{"book":"黑客与画家（10万册纪念版）","author":"保罗·格雷厄姆","text":"你需要的是咬牙向前冲刺的痛苦，而不是脚被钉子扎破的痛苦。"},{"book":"黑客与画家（10万册纪念版）","author":"保罗·格雷厄姆","text":"美依赖于一些精心选择的结构性元素，而不依赖于表面装饰品的堆砌。（装饰品本身并不是坏事，只有当它被用来掩盖结构的苍白时，才变成了一件坏事。）"},{"book":"黑客与画家（10万册纪念版）","author":"保罗·格雷厄姆","text":"尽快拿出1.0版，然后根据用户的反映而不是自己的猜测进行软件优化。"},{"book":"黑客与画家（10万册纪念版）","author":"保罗·格雷厄姆","text":"大多数时候，促成买方掏钱的最好办法不是让买家看到有获利的可能，而是让他们感到失去机会的恐惧。对于买家来说，最强的收购动机就是看到竞争对手可能收购你。"},{"book":"黑客与画家（10万册纪念版）","author":"保罗·格雷厄姆","text":"有一个办法可以发现是否存在可放大性，那就是看失败的可能性。因为收入和风险是对称的，所以如果有巨大的获利可能，就必然存在巨大的失败可能。"},{"book":"黑客与画家（10万册纪念版）","author":"保罗·格雷厄姆","text":"CEO也是一种同时具备可测量性和可放大性的工作。公司的表现就是CEO的表现，所以它具备可测量性。CEO的决策决定了整个公司的方向，所以它具备可放大性。"},{"book":"黑客与画家（10万册纪念版）","author":"保罗·格雷厄姆","text":"要致富，你需要两样东西：可测量性和可放大性。你的职位产生的业绩，应该是可测量的，否则你做得再多，也不会得到更多的报酬。此外，你还必须有可放大性，也就是说你做出的决定能够产生巨大的效应。"},{"book":"黑客与画家（10万册纪念版）","author":"保罗·格雷厄姆","text":"程序写出来是给人看的，附带能在机器上运行。"},{"book":"黑客与画家（10万册纪念版）","author":"保罗·格雷厄姆","text":"（1）搭建原型 （2）上线运营（别管bug） （3）收集反馈 （4）调整产品 （5）成长壮大"},{"book":"黑客与画家（10万册纪念版）","author":"保罗·格雷厄姆","text":"工作就是在一个组织中，与许多人共同合作，做出某种人们需要的东西。"},{"book":"黑客与画家（10万册纪念版）","author":"保罗·格雷厄姆","text":"真正重要的是做出人们需要的东西，而不是加入某个公司。"},{"book":"黑客与画家（10万册纪念版）","author":"保罗·格雷厄姆","text":"历尽了千辛万苦，你最终写出了一个大受欢迎的软件，这时你可能会发现，你所做的一切其实只是在为微软公司做市场调查。"},{"book":"黑客与画家（10万册纪念版）","author":"保罗·格雷厄姆","text":"经济学里有一条拉弗曲线（Laffer curve），认为随着税率的上升，税收收入会先增加后减少。我认为政府的力量也是如此，随着对公民自由的限制不断上升，政府的力量会先增加后减小。"},{"book":"黑客与画家（10万册纪念版）","author":"保罗·格雷厄姆","text":"Michael Rabin￼遇到难题的时候，会把问题重新定义成一个较简单的形式，同时一定会假想一个对手正在与他比赛谁能更快地解决问题。"},{"book":"黑客与画家（10万册纪念版）","author":"保罗·格雷厄姆","text":"只有深入了解当前的技术，黑客才能构想下一代技术。"},{"book":"黑客与画家（10万册纪念版）","author":"保罗·格雷厄姆","text":"创业是最有效的创造财富的方法，对创始人、对投资者、对社会都是如此。"},{"book":"黑客与画家（10万册纪念版）","author":"保罗·格雷厄姆","text":"“所有东西都在变成软件。印刷机诞生后，人类写过多少个字，未来就有多少家软件公司。”"},{"book":"黑客与画家（10万册纪念版）","author":"保罗·格雷厄姆","text":"我们生活中的一切，都正在成为计算机。所以，如果你想理解我们目前的世界以及它的未来动向，那么多了解一些黑客的想法会对你有帮助。"},{"book":"黑客与画家（10万册纪念版）","author":"保罗·格雷厄姆","text":"因为创立Viaweb的主要目的就是希望被收购，这样才能快速赚到钱。"},{"book":"黑客与画家（10万册纪念版）","author":"保罗·格雷厄姆","text":"格雷厄姆心想，如果网景公司的设想是正确的，未来人们都在互联网上购物，那么必须有人为零售商们开发软件。所以，他决定开发一个搭建网店的软件。"},{"book":"黑客与画家（10万册纪念版）","author":"保罗·格雷厄姆","text":"一页写满了数学公式的纸真是令人印象深刻啊。（小窍门：用希腊字母表示变量名会令人印象更深刻。）因此，你就受到巨大的诱惑，去解决那些能够用数学公式处理的问题，而不是去解决真正重要的问题。"},{"book":"黑客与画家（10万册纪念版）","author":"保罗·格雷厄姆","text":"判断一个人是否具备“换位思考”的能力有一个好方法，那就是看他怎样向没有技术背景的人解释技术问题。"},{"book":"黑客与画家（10万册纪念版）","author":"保罗·格雷厄姆","text":"“换位思考”并不就意味着你要做自我牺牲。实际上，这是完全不同的两回事。了解别人对于事情的看法，并不代表你为他的利益服务。某些情况下，比如打仗的时候，了解对手正是为了打击对手"},{"book":"黑客与画家（10万册纪念版）","author":"保罗·格雷厄姆","text":"好玩的软件的需求量，比不上解决客户麻烦问题的软件的需求量。"},{"book":"黑客与画家（10万册纪念版）","author":"保罗·格雷厄姆","text":"如果你想赚钱，你可能不得不去干那些很麻烦很讨厌的事情，因为这些事情没人愿意义务来干。"},{"book":"黑客与画家（10万册纪念版）","author":"保罗·格雷厄姆","text":"本人需要有良好的设计感，才能去考核别人的设计是否良好。但是，你觉得你有“良好的设计感”，与你实际是否具有，不存在相关关系，甚至可能存在负相关。"},{"book":"黑客与画家（10万册纪念版）","author":"保罗·格雷厄姆","text":"人类喜欢工作，在世界上大多数地方，你的工作就是你的身份证明。"},{"book":"黑客与画家（10万册纪念版）","author":"保罗·格雷厄姆","text":"书呆子已经在思考的东西，正是真实世界看重的东西。他们与别人不一样，不把所有时间用来玩一种耗尽全力但又毫无意义的游戏。"},{"book":"黑客与画家（10万册纪念版）","author":"保罗·格雷厄姆","text":"真实世界的特点是，它极其庞大。如果总体足够大，即使是人数最少的少数派，只要聚集在一起，也能产生可观的力量。"},{"book":"黑客与画家（10万册纪念版）","author":"保罗·格雷厄姆","text":"表面上这是一个机器的时代，但是实际上机器的设计者决定了我们的时代。"},{"book":"西西弗神话","author":"[法]加缪","text":"本书书名“西西弗神话”已成法文谚语，借喻“永久无望又无用的人生状况”。所以我们采用法语sisyphe的音译名，而不用希腊名sisuphos的音译“西叙福斯”。"},{"book":"关山夺路：回忆录四部曲之三","author":"王鼎钧","text":"明珠是在蚌的身体里头结成的，但是明珠并不是蚌的私人收藏，回忆录是我对今生今世的交代，是我对国家社会的回馈，我来了，我看见了，我也说出来了！"},{"book":"关山夺路：回忆录四部曲之三","author":"王鼎钧","text":"黄埔军校校歌押wu，同样不顾声韵，使人想起苏东坡在赤壁赋里形容的“其声呜呜然”，可见当年南京重庆主持文宣大计的人，如何忽略了听觉。他们只想到继承已往的五千年，没设想开创未来的五千年。"},{"book":"论中国","author":"亨利·基辛格","text":"几十年来，逐渐出现了一个变化——邓小平开始用普通人的幸福和发展来重新定义善政的标准。他专注于快速发展——其中也展现出相当多的民族特性——即使这要求采用昔日敌对的资本主义世界的方法。"},{"book":"论中国","author":"亨利·基辛格","text":"换言之，只要不妨害共同对付苏联威胁的需要，各方都可使用任何意识形态口号来满足自己国内的需要。意识形态将沦为国内管理工具，而与外交政策分家了。当然，意识形态之间的停战只有在目标不相悖的时候才有可能。"},{"book":"论中国","author":"亨利·基辛格","text":"透明固然重要，但为了建立更为和平的世界秩序，抓住历史机遇也是必要的。"},{"book":"论中国","author":"亨利·基辛格","text":"政治家都需要在过去的经历和未来的需要之间寻求平衡，最能证明这一点的莫过于刚刚执掌中国的毛泽东和共产党。"},{"book":"远山淡影（彩虹版石黑一雄作品）","author":"[英]石黑一雄","text":"那时常是一种我无法用文字表达的情感，但它确实就在那里，在歌手的声音里，而现在我得到了一个可以瞄准的目标。"},{"book":"远山淡影（彩虹版石黑一雄作品）","author":"[英]石黑一雄","text":"我在这里指的并不是唱出来的歌词，而是演唱本身。我们知道，歌唱的人声能够传达复杂得超乎想象的情感混合物。"},{"book":"复杂","author":"梅拉妮·米歇尔","text":"一旦思想的时机成熟，就必然会有人想到。"},{"book":"复杂","author":"梅拉妮·米歇尔","text":"科学总是寻求发现和了解客观世界的新现象，研究和掌握新规律，总是在不懈地追求真理。科学是认真的、严谨的、实事求是的，同时，科学又是创造的。科学的最基本态度之一就是疑问，科学的最基本精神之一就是批判。"},{"book":"发现的乐趣","author":"理查德·费曼","text":"如果你有理由去做一件事，而且理由很充分，那么你就开始去做，但是你一定要时不时关注一下现在的情形，看看最初的动机是否还是正当的。"},{"book":"发现的乐趣","author":"理查德·费曼","text":"你要把一个问题的重要性乘以你解决这个问题的可能性。"},{"book":"发现的乐趣","author":"理查德·费曼","text":"没有什么无穷倒退性：复杂性到了一定程度就会停止下来。"},{"book":"发现的乐趣","author":"理查德·费曼","text":"能让他为之奋斗的事业是：通过彻底重建物理学来理解大自然的工作机理。"},{"book":"激荡十年，水大鱼大：中国企业2008-2018","author":"吴晓波","text":"速度可以掩盖很多的矛盾，其中有一部分，可以通过发展的方式冲决过去，可是也有相当的一部分——尤其是制度建构层面的，却始终无法绕将过去，你不得不勇敢直面。"},{"book":"激荡十年，水大鱼大：中国企业2008-2018","author":"吴晓波","text":"我们的国家就是一艘驶往未来的大船，途经无数险滩、渡口，很难有人可以自始至终随行到终点，每一代人离去之时，均心怀不甘和不舍，而下一代人则感念前辈却又注定反叛。"},{"book":"好战略，坏战略（畅销版）","author":"理查德·鲁梅尔特","text":"正如夏洛克·福尔摩斯对华生医生所说的那样：“你看到了，但什么也观察不出来。”只有目光敏锐的观察家才能将固有的事实与自身的预期进行比较，并在比较中发现异常现象。"},{"book":"好战略，坏战略（畅销版）","author":"理查德·鲁梅尔特","text":"今天，和那时候一样，很多有效的战略都是设计出来的，而不是筛选各种方案之后做出的决定。"},{"book":"好战略，坏战略（畅销版）","author":"理查德·鲁梅尔特","text":"其他条件相同的情况下，规模较大的军队是占优势的一方，在商业竞争中胜出的企业往往是产品最受消费者青睐的企业，企业的规模扩大是竞争成功的结果，而不是竞争成功的原因。"},{"book":"好战略，坏战略（畅销版）","author":"理查德·鲁梅尔特","text":"好战略的宗旨在于为克服关键挑战提供一套可能实现的行动方案。如果领导者设定的战略目标实现起来与克服挑战的难度相当，那么这个战略的价值就会大打折扣。"},{"book":"原则","author":"瑞·达利欧","text":"英文“integrity”（正直）一词来源于拉丁文“integritas”，意思是“一”或“完整”。表里不一的人，即不“完整”的人，是不正直的，他们当面一套、背后一套（duality）。"},{"book":"原则","author":"瑞·达利欧","text":"如卡尔·荣格所说：“除非你意识到你的潜意识，否则潜意识将主导你的人生，而你将其称为命运。”"},{"book":"原则","author":"瑞·达利欧","text":"我想招聘的人是独立的思考者，有创造力，概念性强，常识性强。"},{"book":"原则","author":"瑞·达利欧","text":"太多人犯的错误是，一心想着执行，所以几乎不花时间来规划。谨记：规划先于行动！"},{"book":"原则","author":"瑞·达利欧","text":"生活根本不关心你喜欢什么。你必须根据自己的愿望找到实现愿望的途径，然后鼓起勇气坚持下去。"},{"book":"原则","author":"瑞·达利欧","text":"世 界上最重要的事情是理解现实如何运行，以及如何应对现实。"},{"book":"原则","author":"瑞·达利欧","text":"假如我是对的，这就不是小事，所以我想和顶级决策者们讨论自己观察到的情况，一方面提醒他们，另一方面看他们的看法是否不同，能否纠正我。"},{"book":"原则","author":"瑞·达利欧","text":"我知道什么能带来资产收益，但我也知道不管持有什么类型的资产，总有一天它会失去大部分价值。这些资产包括现金，现金是长期投资产品里最差的一种，因为它会因通胀和税收因素而不断贬值。"},{"book":"原则","author":"瑞·达利欧","text":"利用这些机器运行系统解放了我们，使我们不必再盯着市场的每日变动，可以从更高的层面思考问题，从而创造出新颖的、有创意的联系，为我们的客户进行创新。"},{"book":"原则","author":"瑞·达利欧","text":"我相信拥有把事情探究明白的能力，要比拥有如何做某件事的具体知识更重要。"},{"book":"原则","author":"瑞·达利欧","text":"我发现这个道理不仅对投资适用，对人和事物的关系同样适用：明智的人在经历各种沉浮时都始终盯紧稳健的基本面；而轻浮的人跟着感觉走，做出情绪化的反应，对于热门的东西一拥而上，不热的时候又马上放弃。"},{"book":"原则","author":"瑞·达利欧","text":"如果你以勤奋和有创造性的方式工作，你几乎可以得到你想要的任何东西，但你不可能同时得到所有东西。成熟意味着你可以放弃一些好的选择，从而追求更好的选择。"},{"book":"我的天才女友（HBO同名热剧原著）","author":"埃莱娜·费兰特","text":"在不久之前——可能是十天，也可能是一个月之前，没人知道，那时候我们不太重视时间"},{"book":"刷新：重新发现商业与未来","author":"萨提亚·纳德拉","text":"“我为什么存在？” “我们的机构为什么存在？” “跨国公司在这个世界上的角色是什么？” “数字技术领导者的角色是什么，特别是在当今世界把科技作为推动增长的一个关键因素的时候？”"},{"book":"刷新：重新发现商业与未来","author":"萨提亚·纳德拉","text":"我经常会被人问：“什么情况下建立伙伴关系比并购更合适？”这个问题最好通过另一个问题来回答，即“我们作为一个共同实体为客户创造的价值多，还是作为两个单一实体为客户创造的价值多？”"},{"book":"刷新：重新发现商业与未来","author":"萨提亚·纳德拉","text":"她始终认为，人要依照自己的意愿去做事，并遵循自己的节奏。当你依照自己的意愿做事时，节奏就上来了。只要是你喜欢的事，用心去做，把它做好，而且保持正当的目标，生活就不会辜负你。"},{"book":"刷新：重新发现商业与未来","author":"萨提亚·纳德拉","text":"我把改造公司文化列为首要任务。我说我们要重新发现微软的灵魂，重新发现我们存在的理由。我认识到我的主要任务是管理我们的文化，唯有如此，微软10万名充满创造力的员工才能更好地塑造我们的未来。"},{"book":"天朝的崩溃：鸦片战争再研究（修订版）","author":"茅海建","text":"林则徐所设想的“水军”，只是传统水师的强化，并非近代海军。一支近代化的海军须由近代化的科技和工业为基础。缺乏这一基础，林则徐或其他人，空手是建不成近代海军的。"},{"book":"天朝的崩溃：鸦片战争再研究（修订版）","author":"茅海建","text":"世界各国民众反对侵略的历史已经表明，他们最为有利有效的战法是游击战，即凭借地理环境的熟悉，抗敌斗志的高昂，设计消灭单独活动的敌军小部队，切忌使用正规的阵地战。"},{"book":"天朝的崩溃：鸦片战争再研究（修订版）","author":"茅海建","text":"长久的和平，使清朝统治者们忘记了未来战争的大课题，他们从未制定过长期的武器装备研制计划。"},{"book":"天朝的崩溃：鸦片战争再研究（修订版）","author":"茅海建","text":"天朝”对外体制，使中国成为一个世界，而不是世界的一部分。"},{"book":"现实不似你所见","author":"卡洛·罗韦利","text":"伽利略、开普勒、牛顿将会建立惊人的概念工具：空间中的直线运动；构成世界的基本要素与相互作用；空间是世界的容器。"},{"book":"网：阿加西自传","author":"安德烈·阿加西","text":"长久以来，我几乎与读书绝缘，在所有我希望我的孩子们不要再犯的错误当中，这是最重要的一项。"},{"book":"网：阿加西自传","author":"安德烈·阿加西","text":"我们所有人都应该对自己如此真实，如此始终如一。"},{"book":"网：阿加西自传","author":"安德烈·阿加西","text":"我打球并且坚持打球是因为我选择这样做。即使那不是你的理想生活，你也可以选择它。无论你的生活如何，如果你主动选择它，一切便会随之改变。"},{"book":"网：阿加西自传","author":"安德烈·阿加西","text":"在意与不在意的完美融合，才是最好的准备。"},{"book":"网：阿加西自传","author":"安德烈·阿加西","text":"我是我母亲的儿子。"},{"book":"网：阿加西自传","author":"安德烈·阿加西","text":"当梅德韦杰夫闪身并胳膊僵硬地挥拍时，我是第二个知道我已成为法网冠军的人——布拉德是第一个，梅德韦杰夫是第三个。球远远地飞出了底线——注视着它降落是我人生最快乐的事情之一。"},{"book":"网：阿加西自传","author":"安德烈·阿加西","text":"布拉德知道我的想法，知道我大脑运转的方式。他知道命令、特殊性以及一个清晰而精确的目标，对我而言就像一颗糖果。"},{"book":"网：阿加西自传","author":"安德烈·阿加西","text":"他并非不认为我赢得法网的可能性微乎其微，但一旦我缺席法网，我也会很轻易地就退出温网，然后整个1999年我都会如此。再见，重塑辉煌！你好，退役！"},{"book":"网：阿加西自传","author":"安德烈·阿加西","text":"在比赛行将结束时，他似乎一定程度上都在为我鼓气。他知道我正在试图征服什么，他知道我还要走多远。"},{"book":"网：阿加西自传","author":"安德烈·阿加西","text":"走出球场时，我气喘吁吁，但浑身都是力量——久违的那种力量。"},{"book":"网：阿加西自传","author":"安德烈·阿加西","text":"现在我更加接近于成熟的人类一员了…… 她认为她以前从未有机会去感受人类所拥有的力量，去承受痛苦；她热爱并敬畏曾经遭受痛苦的人们，甚至那些没能经受住痛苦的人。"},{"book":"网：阿加西自传","author":"安德烈·阿加西","text":"“我已经加倍投入于网球。如果我能挺过这段艰难的时期，如果我能卷土重来，一切的一切都将不同，我也将大大不同于以往。但即使我不能，即使我完蛋了，即使我失去了一切，我仍然会与以往不同。”"},{"book":"网：阿加西自传","author":"安德烈·阿加西","text":"眼前的情景仿佛在对我说：所有这些动物身处危险的世界，却在每一天开始时都表现得如此从容和平静，毫无怨言地等待命运的赐予——你为什么不能呢？"},{"book":"网：阿加西自传","author":"安德烈·阿加西","text":"我不能相信人生是如此具有讽刺意味。《60分钟》的一则报道导致我被父亲送走，从而使我痛彻心扉，而现在《60分钟》的另一则报道则为我点亮了回家的路，为我描绘出了找寻生命意义和使命的图谱。"},{"book":"网：阿加西自传","author":"安德烈·阿加西","text":"“你去过哪里并不重要，从现在开始，我们关注的是我们将去往何方。”"},{"book":"网：阿加西自传","author":"安德烈·阿加西","text":"我每天早上花两个小时与吉尔待在一起，再和布拉德打两个小时的球，然后在一天中最热的时段跑到吉尔山顶，再跑下来。我想品味炎热，品味痛苦。"},{"book":"网：阿加西自传","author":"安德烈·阿加西","text":"帮助别人是完美的，这是人生仅有的完美，是我们能够做的唯一具有持久价值和意义的事情。这就是我们为什么存在的原因——使彼此感到安全。"},{"book":"网：阿加西自传","author":"安德烈·阿加西","text":"我一直跑，直到我的思想乞求我的身体停下来，但我会忽略我思想的请求，继续再跑一段。"},{"book":"网：阿加西自传","author":"安德烈·阿加西","text":"我对他们说网球与命运一点儿关系都没有，命运之神除了计算ATP积分外还有更重要的事情要去做。"},{"book":"网：阿加西自传","author":"安德烈·阿加西","text":"如果我的外科医生恰巧就是医学界的安德烈·阿加西怎么办？"},{"book":"网：阿加西自传","author":"安德烈·阿加西","text":"“重新回到赛场上，”他说，“这是唯一的方法，我的孩子。” 去他妈的那个赛场。 “去吧，”温迪说，“说实话，反正也不会比这更糟了，不是吗？”"},{"book":"网：阿加西自传","author":"安德烈·阿加西","text":"他说：“当你醒着的时候还有梦想是一件多么幸福的事啊。当你醒着的时候去追求你的梦想，安德烈。所有的人都可以在睡觉的时候做梦，但是你需要一直做梦。大声地说出你的梦想，并且相信你能够实现它们。”"},{"book":"网：阿加西自传","author":"安德烈·阿加西","text":"在我看来，你从事的这项运动关键不在于奔跑的过程，而在于起步和止步。你需要集中精力为‘启动’和‘紧急刹车’构建肌肉。”"},{"book":"网：阿加西自传","author":"安德烈·阿加西","text":"整个地方从远处看起来会好很多。 什么事情不是这样的呢？有时我们需要距离。"},{"book":"网：阿加西自传","author":"安德烈·阿加西","text":"我突然意识到，追根溯源，我和佩里的约定其实是一个成为彼此父亲的承诺——彼此扶持，互相照顾。"},{"book":"网：阿加西自传","author":"安德烈·阿加西","text":"父亲说，如果我每天击球2500次，每周就会击球17500次，这样一年结束时，我击球的次数就将接近100万。他相信数学，他说数字是不会骗人的。如果一个孩子每年击球100万次，那么他将是不可战胜的。"},{"book":"网：阿加西自传","author":"安德烈·阿加西","text":"慢慢享受，细细体会，好好观察一切，注意一切转瞬即逝的细节，因为尽管你痛恨网球，但今后你可能会怀念今晚的一切。"},{"book":"卡拉马佐夫兄弟（套装上下册）（译文名著精选）","author":"陀思妥耶夫斯基","text":"陀氏观察到人身上有专横跋扈的倾向，一种与生俱来的权力欲。他发现爱的因素中包含着对所爱者行使权力的欲望。如果这种欲望得不到满足，所爱者就可能同时被既爱又恨。"},{"book":"卡拉马佐夫兄弟（套装上下册）（译文名著精选）","author":"陀思妥耶夫斯基","text":"许多读者知道这是世界文学的一座高峰、一颗明珠，但尝试阅读又半途而废的大有人在。如果这个译本的读者中坚持读完的人数比重较之过去有所增长，那就意味着我实现了自己追求的目标。"},{"book":"卡拉马佐夫兄弟（套装上下册）（译文名著精选）","author":"陀思妥耶夫斯基","text":"揭示人的心灵隐秘（Revelation of Man's secret heart）、革命（Revolution）、俄罗斯（Russia）和宗教（Religion）"},{"book":"卡拉马佐夫兄弟（套装上下册）（译文名著精选）","author":"陀思妥耶夫斯基","text":"我实实在在的告诉你们：一粒麦子落在地里如若不死，仍旧是一粒；若是死了，就会结出许多子粒来。"},{"book":"卡拉马佐夫兄弟（套装上下册）（译文名著精选）","author":"陀思妥耶夫斯基","text":"思辨尚奥，求索务高，因为我们的归宿在凌霄"},{"book":"卡拉马佐夫兄弟（套装上下册）（译文名著精选）","author":"陀思妥耶夫斯基","text":"那一双纯真的眼睛当时就像一把剃刀在我心上刷的划了一下"},{"book":"卡拉马佐夫兄弟（套装上下册）（译文名著精选）","author":"陀思妥耶夫斯基","text":"在大多数情况下，人们，甚至恶人，要比我们想象中的他们幼稚得多、天真得多。其实我们自己也一样。"},{"book":"卡拉马佐夫兄弟（套装上下册）（译文名著精选）","author":"陀思妥耶夫斯基","text":"因为怪人不仅“并不总是”个别和特殊的现象，而且相反，在某些情况下，他身上也许还具有整体的内核，倒是其余和他同时代的人全都像遭到狂风袭击似的，不知为何一时间纷纷脱离了他"},{"book":"长日将尽（彩虹版石黑一雄作品）","author":"[英]石黑一雄","text":"以其巨大的情感力量，发掘了隐藏在我们与世界联系的幻觉之下的深渊"},{"book":"哲学的故事【让深奥的哲学立刻生动起来!上市首年连续再版22次，迅速译成18种语言，掀起全球哲学热潮】","author":"威尔•杜兰特 (Will Durant)","text":"让·保尔·里克特[69]写道：“上帝赐予法国土地，赐予英国大海，赐予德国天空的帝国。”"},{"book":"哲学的故事【让深奥的哲学立刻生动起来!上市首年连续再版22次，迅速译成18种语言，掀起全球哲学热潮】","author":"威尔•杜兰特 (Will Durant)","text":"感觉是无组织的刺激；知觉是有组织的刺激；概念是有组织的知觉；科学是有组织的知识；智慧则是有组织的生活。每一项都在条理、序列和统一性上更进一步。"},{"book":"哲学的故事【让深奥的哲学立刻生动起来!上市首年连续再版22次，迅速译成18种语言，掀起全球哲学热潮】","author":"威尔•杜兰特 (Will Durant)","text":"社会是时间的产物，不是简单的哲学三段论。当过去被关在门外时，它还会从窗户跳进来。问题是什么样的改变能消除这个真实世界中的种种痛苦和不公。"},{"book":"哲学的故事【让深奥的哲学立刻生动起来!上市首年连续再版22次，迅速译成18种语言，掀起全球哲学热潮】","author":"威尔•杜兰特 (Will Durant)","text":"他的灵丹妙药就是广散钱财：财产可以给予人人格尊严，使人自信。“拥有财产可以使人备感力量。拥有财产的人管理自己的产业肯定比管理别人的要好。”"},{"book":"哲学的故事【让深奥的哲学立刻生动起来!上市首年连续再版22次，迅速译成18种语言，掀起全球哲学热潮】","author":"威尔•杜兰特 (Will Durant)","text":"国家所追求的目标应该由公众来决定，但实现它的途径只能由专家来决定和执行；选择的权利应该以民主的方式广泛散布，但政府职务只能严格地由具备条件并且经过筛选的人担当。"},{"book":"英伟达之道","author":"[美]金泰","text":"黄仁勋在人工智能军备竞赛的早期就意识到，竞争不只是看谁能制造出最快的深度学习芯片，同样重要的是如何让这一切——硬件和软件基础设施——协同工作。"},{"book":"英伟达之道","author":"[美]金泰","text":"“我们原以为自己打造了伟大的技术和伟大的产品，”马拉科夫斯基说道，“结果我们只打造了伟大的技术，而不是伟大的产品。”"},{"book":"英伟达之道","author":"[美]金泰","text":"我们会专注于我们擅长的事情，如果一件事你不擅长，那就不适合你做。"},{"book":"艺术的故事","author":"贡布里希 (Sir E.H.Gombrich)","text":"可是，不管我们对现代艺术家的看法如何，我们都可以毫无保留地相信他们有足够的知识，完全能够画得“正确”。如果他们不那样画，其原因可能跟瓦尔特·迪斯尼一样。"},{"book":"創造與漫想","author":"傑夫．貝佐斯（Jeff Bezos）","text":"身為高階主管，你領薪水究竟要做什麼事？你領薪水是要做少數高品質決策。你的工作不是每天做上千個決定。"},{"book":"創造與漫想","author":"傑夫．貝佐斯（Jeff Bezos）","text":"你得聆聽內心的聲音並運用直覺，你要承擔風險，要發揮本能，所有好的決策都要這樣。你要和大家一起做決定，拿出謙卑態度，順帶一提，就算弄錯了也沒那麼糟，那是另一回事。"},{"book":"創造與漫想","author":"傑夫．貝佐斯（Jeff Bezos）","text":"我強烈相信創業家資本主義（entrepreneurial capitalism）和自由市場能解決世界上的許多問題。不是所有問題都能解決，但能解決的問題很多。"},{"book":"創造與漫想","author":"傑夫．貝佐斯（Jeff Bezos）","text":"我寧願在眾人眼中是「發明家貝佐斯」、「企業家貝佐斯」或「為人父的貝佐斯」。那些事情對我而言有意義多了，它們衡量的是你付出了多少。"},{"book":"創造與漫想","author":"傑夫．貝佐斯（Jeff Bezos）","text":"推動事情發展的所有關鍵在，你會遇到問題、失敗和不成功。你需要回過頭，再嘗試一次。每一次遇到挫折，你都回過頭，再嘗試一次。你發揮足智多謀的一面，你自立自強，你嘗試突破思維框架找出自己的解決之道。"},{"book":"創造與漫想","author":"傑夫．貝佐斯（Jeff Bezos）","text":"寫給每一位展信者：要仁慈、要獨特、要創造勝於消耗，還有，永遠、永遠、永遠別讓宇宙把你融入周圍環境變得無異於眾生。"},{"book":"創造與漫想","author":"傑夫．貝佐斯（Jeff Bezos）","text":"我可以告訴你，能與如此聰明、有想像力、熱情的人們共事，每一天都令我感受到無比的喜悅。"},{"book":"創造與漫想","author":"傑夫．貝佐斯（Jeff Bezos）","text":"反過來看比較不那麼有趣，而且一定會有一些倖存者偏誤（survivorship bias）的情形。凡習慣於採用輕量級的第二類決策流程，來制訂第一類決策的公司，都會在壯大前滅亡。"},{"book":"創造與漫想","author":"傑夫．貝佐斯（Jeff Bezos）","text":"現在，亞馬遜與我心目中三個符合前述條件的人生伴侶，幸福地結為連理。他們分別是亞馬遜市集、尊榮會員制和AWS。"},{"book":"創造與漫想","author":"傑夫．貝佐斯（Jeff Bezos）","text":"一個令人夢寐以求的生意至少要符合四項特質：受顧客喜愛、可擴張至極大規模、資本報酬可觀、歷久不衰（有維持數十年的潛力）。"},{"book":"創造與漫想","author":"傑夫．貝佐斯（Jeff Bezos）","text":"我們也知道，我們不能想要鉅細靡遺地移植書本的每一項特色，我們永遠不可能以一本書的樣子贏過實體書。我們必須加入新功能，傳統書籍永遠不可能出現的功能。"},{"book":"創造與漫想","author":"傑夫．貝佐斯（Jeff Bezos）","text":"以亞馬遜的大幅成長和網際網路的長足發展來看，我們依然堅持以相同的基本方針經營公司，格外了不起。"},{"book":"創造與漫想","author":"傑夫．貝佐斯（Jeff Bezos）","text":"我們放棄實體世界的房地產，追求科技（成本逐年下降，能力逐年提升）。"},{"book":"創造與漫想","author":"傑夫．貝佐斯（Jeff Bezos）","text":"可以確定我們面臨的挑戰之中，絕大部分並非尋找擴大生意的新方法，而是落在如何排定投資的優先順序。"},{"book":"創造與漫想","author":"傑夫．貝佐斯（Jeff Bezos）","text":"亞馬遜網站的員工人數從一百五十八增加到六百一十四人，管理團隊也比以前更充實。"},{"book":"創造與漫想","author":"傑夫．貝佐斯（Jeff Bezos）","text":"一名投資人曾經抱怨，指責貝佐斯忘了亞馬遜要賣出東西才會賺錢，負面評價將不利於銷售。貝佐斯說：「我讀到那封信的時候心想，我們不是靠賣東西賺錢，我們是靠幫助顧客做出購物決定來賺錢。」"},{"book":"原则：应对变化中的世界秩序","author":"瑞·达利欧","text":"在他们看来，市场经济是一种提升大多数人生活水平的方式，不是为资本家服务的。"},{"book":"原则：应对变化中的世界秩序","author":"瑞·达利欧","text":"他们拥有最重要的东西：创造伟大变化的明确使命、品行良好的聪明人士、有利于快速学习的开放头脑和实现目标的坚定决心。对他们来说，这不是一项工作，而是改善国家的崇高使命。"},{"book":"原则：应对变化中的世界秩序","author":"瑞·达利欧","text":"投资的目的是以一种财富贮藏手段储存资金，以便今后将其转化成购买力。投资是一次性地支付未来的款项。"},{"book":"原则：应对变化中的世界秩序","author":"瑞·达利欧","text":"在债市和股市创建之前，所有的财富都是有形财富。"},{"book":"原则：应对变化中的世界秩序","author":"瑞·达利欧","text":"一个社会如何使用资金是个很重要的问题。相比于不能提高生产率和收入的消费项目，投资于可提高生产率和收入的消费项目，才能带来更好的未来。"},{"book":"原则：应对变化中的世界秩序","author":"瑞·达利欧","text":"因为资本是可以产生收入的资产，所以人力资本可以被定义为产生收入的个人。● 如果一个人能够使自己的收入超过支出，就拥有良好的人力资本，可以自给自足。"},{"book":"原则：应对变化中的世界秩序","author":"瑞·达利欧","text":"荷兰人很有创造力，在鼎盛时期，荷兰的发明占世界主要发明的1/4。其中之一是发明造船术。造出的船能够开到世界各地搜集大量财富。荷兰人还发明了我们所知的资本主义。"},{"book":"原则：应对变化中的世界秩序","author":"瑞·达利欧","text":"所有这些实力指标的涨跌都与该国的兴衰吻合。这是因为这些优势和劣势是相辅相成的。也就是说，教育、竞争力、经济产出、世界贸易份额等方面的优势和劣势会促使该国在其他方面变得强大或者疲弱，这是合乎逻辑的。"},{"book":"原则：应对变化中的世界秩序","author":"瑞·达利欧","text":"各国存在永恒普适的共性，这些共性远比差异更重要。如果我们仅因这些差异而无视共性（我们可以从共性中获得历史借鉴），那就太可悲了。"},{"book":"原则：应对变化中的世界秩序","author":"瑞·达利欧","text":"除了这些传统工具失效之外，印钞和购买金融资产（现在被称作“量化宽松”）也扩大了贫富差距，因为购买金融资产会推高资产价格，这有利于持有更多金融资产的富人，而无利于贫困者。这会对未来产生何种影响？"},{"book":"原则：应对变化中的世界秩序","author":"瑞·达利欧","text":"二战后，货币曾经是“硬通货”（与黄金挂钩），直至20世纪70年代，为了支撑借贷和防止实体破产，各国政府使货币“走软”（即发行法定货币）。"},{"book":"八次危机","author":"温铁军","text":"在中国的真实基尼系数早都突破0.6的情况下，中共若在十八大权力更迭时推出更多“还账”政策，其制度收益就尤其明显。"},{"book":"论个人在历史上的作用问题 (汉译世界学术名著丛书)","author":"普列汉诺夫","text":"我们说，在社会观念领域天才之超越其同时代人是在这样的意义上：他比他们更早地理解新的、产生着的社会关系的意义 。"},{"book":"论个人在历史上的作用问题 (汉译世界学术名著丛书)","author":"普列汉诺夫","text":"伟大人物之所以伟大，不是因为他的个人特点使伟大的历史事变具有个别的外貌，而是因为他所具备的特点使得他最能为当时在一般原因和特殊原因影响下产生的伟大社会需要服务。"},{"book":"论个人在历史上的作用问题 (汉译世界学术名著丛书)","author":"普列汉诺夫","text":"有影响的人物由于自己的智慧和性格的种种特点，可以改变事变的个别外貌和事变的某些局部后果 ，但它们不能改变事变的总的方向 ，这个方向是由别的力量决定的。"},{"book":"论个人在历史上的作用问题 (汉译世界学术名著丛书)","author":"普列汉诺夫","text":"这里也包括一个正数 ，即意志坚强的人们因确信其意图和理想是客观必然性的主观表现而受到的那种鼓舞作用。"},{"book":"Unknown","author":"Unknown","text":"识别需求、触发器和替代品。"},{"book":"Unknown","author":"Unknown","text":"如果我正在读一本书并感觉看不懂这就像锻炼时肌肉会感觉到酸痛或疲劳只不过现在是换作我的大脑不堪重负了。从长远来说我会变得更聪明因为我正在我的能力界限或边缘工作吸收了新概念。"},{"book":"Unknown","author":"Unknown","text":"你可以定义判断力吗 ￼ 我对智慧的定义是知道你行为的长期后果。智慧被用在外部问题的就是判断力。他们是高度相关的知道行为的长期后果然后做正确的决定去利用它。"},{"book":"Unknown","author":"Unknown","text":"你不可能通过花时间去省钱而致富。你能通过节省你时间而致富。 努力工作的价值真的被高估了。在现代经济中努力工作不是那么重要。   那什么被低估了 ￼ 判断力。判断力被低估了。"},{"book":"Unknown","author":"Unknown","text":"我的联合创始人Nivi说“在一个长期游戏里好像每个人都在让彼此发财而在一个短期游戏里好像每个人都在让自己发财。”"},{"book":"Unknown","author":"Unknown","text":"任何游戏的赢家都是那沉浸于游戏中的人即使获胜的边际效益下降他们也会继续玩下去。"},{"book":"Unknown","author":"Unknown","text":"现实是你必须在九个月内掌握一门新专业而且四年后这么专业也会被淘汰。不过在这三个生产年中你可以获得大量的财富。"},{"book":"大师谈游戏设计 - 创意与节奏","author":"[日]吉泽秀雄","text":"人类是一种很会偏袒自己的生物，出现失误时倾向于将问题归咎于外因，所以游戏必须剔除所有能让玩家推卸责任的元素才行。"},{"book":"大师谈游戏设计 - 创意与节奏","author":"[日]吉泽秀雄","text":"人会自然而然地去思考自己觉得有趣的事情。"},{"book":"大师谈游戏设计 - 创意与节奏","author":"[日]吉泽秀雄","text":"一个人能想到的创意毕竟有限，它需要借由拥有不同人生经验的人来完善、融合，从而引起化学反应，成长为前所未有的新创意。"},{"book":"大师谈游戏设计 - 创意与节奏","author":"[日]吉泽秀雄","text":"如果你的创意只能让人派生出一两个创意，表明它不足以成为核心。"},{"book":"大师谈游戏设计 - 创意与节奏","author":"[日]吉泽秀雄","text":"正是节奏酿出了核心创意的“舒服”体验。"},{"book":"大师谈游戏设计 - 创意与节奏","author":"[日]吉泽秀雄","text":"问问自己“为什么会有这种感觉”，然后把引起这种感觉的要素整理出来。这些信息在将来扩展创意的时候会对我们大有助益。 所谓研究“玩”，其实就是在研究“什么样的情况会触动人的内心”。"},{"book":"大师谈游戏设计 - 创意与节奏","author":"[日]吉泽秀雄","text":"希望各位一定要找到“唯有这种视觉效果才能体现的游戏性”。这样一来，视觉效果与创意就成为了一对充要条件，从中诞生出新游戏的时刻指日可待。"},{"book":"大师谈游戏设计 - 创意与节奏","author":"[日]吉泽秀雄","text":"有一次我听团队里有人说了句“这两屏幕要是再近些就好了”，于是我就想，有没有哪个创意能让人觉得“两屏幕离得远反而更好”呢？"},{"book":"大师谈游戏设计 - 创意与节奏","author":"[日]吉泽秀雄","text":"此时会发现创意已经从“射击让人舒服”变成了“威力不断增强的子弹让人舒服”。那么，我们不妨以它为核心继续思考。子弹通过什么方式增强威力比较有趣呢？"},{"book":"大师谈游戏设计 - 创意与节奏","author":"[日]吉泽秀雄","text":"01. 玩家能通过参与游戏获得“舒服”的体验 02. 每次“舒服”的体验都使得玩家更接近游戏目标 03. 完成游戏目标时获得更高层次的“舒服”体验 因为在这种结构下，人们能产生源源不断的动力去克服眼前的困难。"},{"book":"大师谈游戏设计 - 创意与节奏","author":"[日]吉泽秀雄","text":"要知道，人是一种喜欢舒服的动物。舒服的事让人欲罢不能，舒服再久也不觉得累。在享受舒服的过程中，人们还会去追求更高层次的舒服。所以我认为，以“舒服”作为创意的基准是个非常不错的点子。"},{"book":"1844年经济学哲学手稿","author":"马克思","text":"工业成了战争，而商业成了赌博。"},{"book":"1844年经济学哲学手稿","author":"马克思","text":"工业直到现在还处于掠夺战争的状态： “它像大征服者那样冷酷无情地浪费那些构成其军队的人的生命。它的目的是占有财富，而不是人的幸福”。"},{"book":"1844年经济学哲学手稿","author":"马克思","text":"现在的经济制度 “同时降低了劳动的价格和劳动的报酬；它造就了工人，却贬低了人”。"},{"book":"1844年经济学哲学手稿","author":"马克思","text":"“出租自己的劳动”，“出借自己的劳动换取利息”，“代替别人劳动”。 “出租劳动材料”，“出借劳动材料换取利息”，“让别人代替自己劳动”。"},{"book":"1844年经济学哲学手稿","author":"马克思","text":"为了生活，一无所有者不得不直接地或间接地替所有者效劳，也就是说，依赖于他们。"},{"book":"1844年经济学哲学手稿","author":"马克思","text":"不幸的是，千百万人只有通过那种伤害身体、使道德和智力畸形发展的紧张劳动，才能挣钱勉强养活自己，而且他们甚至不得不把找到这样一种工作的不幸看作是一种幸运。"},{"book":"1844年经济学哲学手稿","author":"马克思","text":"尽管因机器改进而节省了时间，工厂中奴隶劳动的持续时间对众多居民来说却有增无已。"},{"book":"1844年经济学哲学手稿","author":"马克思","text":"国民要想在精神方面更自由地发展，就不应该再当自己的肉体需要的奴隶，自己的肉体的奴仆。因此，他们首先必须有能够进行精神创造和﻿ 精神享受的时间。"},{"book":"1844年经济学哲学手稿","author":"马克思","text":"只得到他不是作为人而是作为工人生存所必要的那一部分，只得到不是为繁衍人类而是为繁衍工人这个奴隶阶级所必要的那一部分。"},{"book":"1844年经济学哲学手稿","author":"马克思","text":"关于工人和资本家之间的关系还应指出，工资的提高对资本家来说，可以由劳动时间量的减少而绰绰有余地得到补偿；工资的提高和资本利息的提高会像单利和复利那样影响商品的价格。"},{"book":"1844年经济学哲学手稿","author":"马克思","text":"由此可见，即使在对工人最有利的社会状态中，工人的结局﻿ 也必然是劳动过度和早死，沦为机器，沦为资本的奴隶（资本的积累危害着工人），发生新的竞争以及一部分工人饿死或行乞。"},{"book":"1844年经济学哲学手稿","author":"马克思","text":"当资本家赢利时工人不一定有利可得，而当资本家亏损时工人就一定跟着吃亏。"},{"book":"1844年经济学哲学手稿","author":"马克思","text":"显然，应当同分工区别开来：这里不是一件工作由许多人来分担，而是大家各自从事同样的劳动，这就是无数次地重复同样的劳动"},{"book":"1844年经济学哲学手稿","author":"马克思","text":"从堕落的无产者的恶习中抽取利息"},{"book":"1844年经济学哲学手稿","author":"马克思","text":"商人的利益始终在于扩大市场和限制卖者的竞争……这是这样一些人的阶级，他们的利益决不会同社会的利益完全一致，他们的利益一般在于欺骗和压迫公众。"},{"book":"1844年经济学哲学手稿","author":"马克思","text":"通常的利息率和纯利润率之间应当保持的比例，必然随着利润的升降而变化。在英国，人们认为，双倍利息就是商人所称的正当的、适度的、合理的利润；这些说法无非是指通常的和普通的利润。"},{"book":"1844年经济学哲学手稿","author":"马克思","text":"继承了大宗财产的人并不因此直接得到政治权力。这种财富直接和径直提供给他的那种权力是购买的权力，这是对一切他人劳动或者说对当时市场上存在着的他人劳动的一切产品的控制权。"},{"book":"治理中国：从革命到改革","author":"[美]李侃如","text":"“依法治国”(rule by law)，与西方广泛使用的“法治”(rule of law)是不同的。“法治”使法律高于官员的个人意愿，而“依法治国”则让官员来主宰，法律为其治理的一个工具。"},{"book":"治理中国：从革命到改革","author":"[美]李侃如","text":"邓设想的中顾委是一个适应老一代革命家让出权力的这一特殊情况的临时机构。他期望一旦这一代人全部退休或去世就废止这个机构。"},{"book":"治理中国：从革命到改革","author":"[美]李侃如","text":"迅速让支持者受益。邓寻求以其成功所带来的巨大利益来激发民众热情和造就支持者。因此，他恢复了城市工人的奖金，支持高价收购农产品，为数百万受害者平反，等等。"},{"book":"治理中国：从革命到改革","author":"[美]李侃如","text":"这种观念造成了民众的消极和领导者的保守，它与毛泽东主张的对革命成功具有关键作用的积极社会和强有力的领导恰恰相反。毛把自己描述为一个相信人民固有的智慧和力量的平民主义者。"},{"book":"治理中国：从革命到改革","author":"[美]李侃如","text":"在瑞金，毛泽东开始深化他对4个重要问题的理解：如何进行土地改革；如何发展并保持农民的政治活力；如何治理中共控制下的地区；如何在农村发展、训练和运用军队。"},{"book":"毛泽东选集","author":"毛泽东","text":"我们的任务是消灭封建制度，消灭地主之为阶级，而不是消灭地主个人。"},{"book":"毛泽东选集","author":"毛泽东","text":"新民主主义的革命任务，除了取消帝国主义在中国的特权以外，在国内，就是要消灭地主阶级和官僚资产阶级（大资产阶级）的剥削和压迫，改变买办的封建的生产关系，解放被束缚的生产力。"},{"book":"毛泽东选集","author":"毛泽东","text":"所有这些努力，都不能挽救蒋介石匪帮的失败。这是因为我们的战略战术是建立在人民战争这个基础上的，任何反人民的军队都不能利用我们的战略战术。"},{"book":"毛泽东选集","author":"毛泽东","text":"“针锋相对”，要看形势。有时候不去谈，是针锋相对；有时候去谈，也是针锋相对。从前不去是对的，这次去也是对的，都是针锋相对。"},{"book":"毛泽东选集","author":"毛泽东","text":"一九三九年七月七日，中国共产党中央委员会发表宣言，针对着当时的危机，提出了这样的口号：“坚持抗战，反对投降；坚持团结，反对分裂；坚持进步，反对倒退。”"},{"book":"毛泽东选集","author":"毛泽东","text":"中国确实需要统一，但是应该统一于抗战，统一于团结，统一于进步。如果向相反的方面统一，那中国就会亡国。"},{"book":"毛泽东选集","author":"毛泽东","text":"使有经验的同志们整理自己的经验，使之带上原则性，而避免重复经验主义的错误"},{"book":"毛泽东选集","author":"毛泽东","text":"斯大林说得好：“理论若不和革命实践联系起来，就会变成无对象的理论，同样，实践若不以革命理论为指南，就会变成盲目的实践。”"},{"book":"毛泽东选集","author":"毛泽东","text":"客观现实世界的变化运动永远没有完结，人们在实践中对于真理的认识也就永远没有完结。马克思列宁主义并没有结束真理，而是在实践中不断地开辟认识真理的道路。"},{"book":"毛泽东选集","author":"毛泽东","text":"我们的革命依靠干部，正像斯大林所说的话：“干部决定一切。”"},{"book":"毛泽东选集","author":"毛泽东","text":"给敌以杀伤，是作为给敌以歼灭的手段而采取的，否则便没有意义。因给敌以杀伤而给我以消耗，又因给敌以歼灭而给我以补充，这样就不但抵偿了我军的消耗，而且增加了我军的力量。"},{"book":"毛泽东选集","author":"毛泽东","text":"当“围剿”已经证明无法在内线解决时，应该使用红军主力突破敌之围攻线，转入我之外线即敌之内线去解决这个问题。"},{"book":"毛泽东选集","author":"毛泽东","text":"因为没有缴获或缴获不超过消耗，在我们看来是很少意义的。我们的战略是“以一当十”，我们的战术是“以十当一”，这是我们制胜敌人的根本法则之一。"},{"book":"毛泽东选集","author":"毛泽东","text":"照我的意见，在有强大敌军存在的条件下，无论自己有多少军队，在一个时间内，主要的使用方向只应有一个，不应有两个。我不反对作战方向有两个或两个以上，但主要的方向，在同一个时间内，只应有一个。"},{"book":"毛泽东选集","author":"毛泽东","text":"退却阶段时必须计算到反攻阶段，反攻阶段时必须计算到进攻阶段，进攻阶段时又须计算到退却阶段。"},{"book":"毛泽东选集","author":"毛泽东","text":"经验对于干部是必需的，失败确是成功之母。但是虚心接受别人的经验也属必需，如果样样要待自己经验，否则固执己见拒不接受，这就是十足的“狭隘经验论”。"},{"book":"毛泽东选集","author":"毛泽东","text":"由轻敌而发生的对于准备的放松，和由被敌人进攻所吓倒而发生的惊惶失措，都是应该坚决反对的不良倾向。我们需要的是热烈而镇定的情绪，紧张而有秩序的工作。"},{"book":"毛泽东选集","author":"毛泽东","text":"明确、坚决而充分地告诉红军人员和根据地的人民，关于敌人进攻的必然性和迫切性，敌人进攻危害人民的严重性，同时，关于敌人的弱点，红军的优良条件，我们一定要胜利的志愿，我们工作的方向等。"},{"book":"毛泽东选集","author":"毛泽东","text":"准备阶段中的主要的问题，是红军的准备退却，政治动员，征集新兵，财政和粮食的准备，政治异己分子的处置等。"},{"book":"毛泽东选集","author":"毛泽东","text":"积极防御，又叫攻势防御，又叫决战防御。消极防御，又叫专守防御，又叫单纯防御。消极防御实际上是假防御，只有积极防御才是真防御，才是为了反攻和进攻的防御。"},{"book":"毛泽东选集","author":"毛泽东","text":"革命战争是民众的事，常常不是先学好了再干，而是干起来再学习，干就是学习。从“老百姓”到军人之间有一个距离，但不是万里长城，而是可以迅速地消灭的，干革命，干战争，就是消灭这个距离的方法。"},{"book":"毛泽东选集","author":"毛泽东","text":"只有无产阶级和共产党，才最没有狭隘性和自私自利性，最有远大的政治眼光和最有组织性，而且也最能虚心地接受世界上先进的无产阶级及其政党的经验而用之于自己的事业。"},{"book":"毛泽东选集","author":"毛泽东","text":"军事家不能超过物质条件许可的范围外企图战争的胜利，然而军事家可以而且必须在物质条件许可的范围内争取战争的胜利。"},{"book":"毛泽东选集","author":"毛泽东","text":"任何军事计划，是应该建立于必要的侦察和敌我情况及其相互关系的周密思索的基础之上的"},{"book":"毛泽东选集","author":"毛泽东","text":"总之，一个原则，就是注意于那些有关全局的重要的关节。"},{"book":"毛泽东选集","author":"毛泽东","text":"消灭它的方法只有一个，就是用战争反对战争，用革命战争反对反革命战争，用民族革命战争反对民族反革命战争，用阶级革命战争反对阶级反革命战争。"},{"book":"毛泽东选集","author":"毛泽东","text":"我们研究在各个不同历史阶段、各个不同性质、不同地域和民族的战争的指导规律，应该着眼其特点和着眼其发展，反对战争问题上的机械论。"},{"book":"毛泽东选集","author":"毛泽东","text":"不论做什么事，不懂得那件事的情形，它的性质，它和它以外的事情的关联，就不知道那件事的规律，就不知道如何去做，就不能做好那件事。"},{"book":"毛泽东选集","author":"毛泽东","text":"战前的政治准备——取信于民，叙述了利于转入反攻的阵地——长勺，叙述了利于开始反攻的时机——彼竭我盈之时，叙述了追击开始的时机——辙乱旗靡之时。虽然是一个不大的战役，却同时是说的战略防御的原则。"},{"book":"毛泽东选集","author":"毛泽东","text":"中国革命战争还是持久战，帝国主义的力量和革命发展的不平衡，规定了这个持久性。"},{"book":"毛泽东选集","author":"毛泽东","text":"半殖民地的政治和经济的主要特点之一，就是民族资产阶级的软弱性。正是因为这样，帝国主义敢于欺负他们，而这也就规定了他们不喜欢帝国主义的特点。"},{"book":"毛泽东选集","author":"毛泽东","text":"它是站在海岸遥望海中已经看得见桅杆尖头了的一只航船，它是立于高山之巅远看东方已见光芒四射喷薄欲出的一轮朝日，它是躁动于母腹中的快要成熟了的一个婴儿。"},{"book":"毛泽东选集","author":"毛泽东","text":"不顾主客观条件，犯着革命的急性病，不愿意艰苦地做细小严密的群众工作，只想大干，充满着幻想。"},{"book":"毛泽东选集","author":"毛泽东","text":"各地许多小块红色区域的失败，不是客观上条件不具备，就是主观上策略有错误。"},{"book":"毛泽东选集","author":"毛泽东","text":"红色政权的长期的存在并且发展，除了上述条件之外，还须有一个要紧的条件，就是共产党组织的有力量和它的政策的不错误。"},{"book":"Empire of AI","author":"Karen Hao","text":"他承认，技术总是会摧毁一些工作，同时创造其他工作。OpenAI 的挑战将是构建 AGI，让每个人都能获得“经济自由”，同时允许他们在新的现实中继续“过有意义的生活”。如果它成功了，它将使工作与生存脱钩。"},{"book":"Empire of AI","author":"Karen Hao","text":"在硅谷，办公室设计是一种货币，是公司对财务前景充满信心的象征，也是公司在顶级人才争夺战中获得微弱优势的一种方式。"},{"book":"Empire of AI","author":"Karen Hao","text":"格雷厄姆和泰尔极大地影响了阿尔特曼的世界观，他建立有效企业的方法，以及他作为政治操盘手的精明。这两位导师给阿尔特曼留下了深刻的印象，即规模的必要性和资本主义的效率高于政府。"},{"book":"货币的非国家化（哈耶克破除逃不开的经济周期的晚年之作，预言区块链和数字货币的超前经典）","author":"弗里德里希·冯·哈耶克","text":"寻找某种能有充足资金履行义务以保证币值稳定的投资是相当困难的问题。"},{"book":"原始碼：成為比爾．蓋茲","author":"比爾．蓋茲（Bill Gates）","text":"我不是容易緬懷過去的人，但有時候我真希望能回到13歲，重新與這個世界約定：只要你勇往直前、不斷地學習更多、讓理解更深刻，就能創造出真正有用與創新的東西。"},{"book":"原始碼：成為比爾．蓋茲","author":"比爾．蓋茲（Bill Gates）","text":"寫程式可以弭平社會差異，只要能寫出好程式、解決很酷的問題，年齡就不成問題。"},{"book":"中国国家治理的制度逻辑：一个组织学研究","author":"周雪光","text":"史学家黄仁宇曾经说过，学术研究的意义不在发现和批评荒谬，而在发掘和解释荒谬背后的逻辑。本书的研究有近似之处，即发掘和理解中国国家治理诸多现象背后稳定的制度逻辑。"},{"book":"可能性的艺术：比较政治学30讲（学者刘瑜比较政治学新著，跳出现象，通过比较洞察政治，突破认知偏见，在浩瀚的可能性中理解我们自身 理想国出品）","author":"刘瑜","text":"官僚系统是什么？就是政府的条条与块块——所谓条条，就是各级政府；所谓块块，就是政府各部门。条条与块块，就像经线和纬线，编成一个政治网络，附着在整个社会肌体之上。"},{"book":"父权制与资本主义","author":"上野千鹤子","text":"解放的思想需要解放的理论。如果不知道谁、从何、如何解放，那么源于对现状的不满和愤怒所产生的动力就会迷失方向。"},{"book":"中国历代政治得失","author":"钱穆","text":"帝王专制只是一种政治制度，所以只要变法，改革此制度即够。"},{"book":"如何预防下一次大流行（比尔·盖茨2022年新书，直面当下全球健康与创新议题，在危机中找机会，向科学要答案！）","author":"比尔·盖茨","text":"我们认为对办公室文化至关重要的结构已经开始演变，随着企业和员工适应新的工作方式，这种变化在未来几年只会加剧。"},{"book":"如何预防下一次大流行（比尔·盖茨2022年新书，直面当下全球健康与创新议题，在危机中找机会，向科学要答案！）","author":"比尔·盖茨","text":"我想大多数人会震惊于未来10年的创新速度，因为软件行业现在专注于远程工作场景的开发。在同一物理空间工作的许多优势，如在饮水机旁遇到的同事，都可以通过正确的用户界面重塑。"},{"book":"如何预防下一次大流行（比尔·盖茨2022年新书，直面当下全球健康与创新议题，在危机中找机会，向科学要答案！）","author":"比尔·盖茨","text":"我非常喜欢在线学习，但我一直认为它是对年轻学生和教师面对面学习的一种补充，而不是替代。"},{"book":"如何预防下一次大流行（比尔·盖茨2022年新书，直面当下全球健康与创新议题，在危机中找机会，向科学要答案！）","author":"比尔·盖茨","text":"但创新并不仅仅是一台新机器或一种疫苗，尽管这些都很重要。它可以是一种不同的方式、一项新的政策，或一个为公益事业筹措资金的锦囊妙计。"},{"book":"刘擎西方现代思想讲义","author":"刘擎","text":"他的观点并不是“过去好、现在坏”。他的问题意识在于：当人类已经取得了如此卓越的技术文明进步之后，为什么人们还无法摆脱（始终没有减少）劳动的异化状态，而是陷入了一种新的异化形态？"},{"book":"刘擎西方现代思想讲义","author":"刘擎","text":"在前现代的传统社会，有很多人能够维系这种质朴的生活。在这种生活里，不是没有艰辛和磨难，但它的“意义框架”是确定的和稳定的；并且，人们的世界观、道德观和人生观大约不会经历巨大的挑战。"},{"book":"刘擎西方现代思想讲义","author":"刘擎","text":"选择什么，在根本上取决于“你是什么样的人”，以及更重要的，“你想要成为什么样的人”。"},{"book":"刘擎西方现代思想讲义","author":"刘擎","text":"虽然尼采用积极的虚无主义代替了消极的虚无主义，但又带来另外一个巨大的问题：我们凭借什么创造，自我创造是否有一个评判标准，怎么判断我们的创造是好是坏？"},{"book":"刘擎西方现代思想讲义","author":"刘擎","text":"尼采说，人类的高贵在于自身有决定价值的能力，不需要别人同意，他懂得自己给事物以荣耀。"},{"book":"刘擎西方现代思想讲义","author":"刘擎","text":"西西弗斯用自己的选择创造出了意义，用无尽的斗争精神去对抗虚无。所以加缪写道：“登上顶峰的斗争本身足以充实人的心灵。应该设想，西西弗斯是幸福的。”"},{"book":"刘擎西方现代思想讲义","author":"刘擎","text":"认识到世界本无意义，这恰恰带来了创造的自由。在尼采看来，价值不是现成在哪里等你“发现”，所有的价值都是人主观创造出来的，生命活动的标志就是能够自己确立价值，这是生命本身的力量。"},{"book":"间谍与叛徒：改变历史的英苏谍战【比尔·盖茨2020年度推荐作品，比间谍小说更为传奇】 (甲骨文系列)","author":"本•麦金泰尔","text":"苏联人过于偏执，不敢让真正知道秘密的人去当诱饵。“他们从不会将现役的克格勃军官拱手相送……他们不相信自己人在和西方情报人员接触时不会叛变。”"},{"book":"间谍与叛徒：改变历史的英苏谍战【比尔·盖茨2020年度推荐作品，比间谍小说更为传奇】 (甲骨文系列)","author":"本•麦金泰尔","text":"“我没有任何犹豫。当一支精英部队向你表示招揽之意，你不会有丝毫顾虑。”"},{"book":"翦商 : 殷周之变与华夏新生","author":"李硕","text":"商朝灭亡后，很多商族人从事的便是贸易行业，所以，在部族、 王朝之名外,“商”还衍变为行业、职业之名，结果,本来代表贸易的“贾” 字被“商”所取代。"},{"book":"Building the Next Era of the Internet","author":"Chris Dixon","text":"计算机接受这些编码的思维并以闪电般的速度运行它们。这就是为什么史蒂夫·乔布斯曾经将计算机描述为“思维的自行车”。它加速了我们的能力。"},{"book":"張忠謀自傳：上冊 一九三一──一九六四","author":"張忠謀","text":"其實失敗已經有懲罰了，它的懲罰就是沒有成功，因為我們重賞成功，失敗的人得不到重賞。"},{"book":"張忠謀自傳：上冊 一九三一──一九六四","author":"張忠謀","text":"「給我：你的疲勞、貧窮、畏懼的人民， 他們要呼吸自由的氣息。 把那些失去家園、久經風暴的送過來吧， 我舉起我的燈光， 靜候在這黃金門旁！」"},{"book":"張忠謀自傳：上冊 一九三一──一九六四","author":"張忠謀","text":"當眾人稱讚他的科技成就，張忠謀只看到責任； 當世人羨慕他的世紀榮耀，張忠謀只想到奉獻。"},{"book":"張忠謀自傳：下冊 一九六四──二○一八","author":"張忠謀","text":"我是美國文豪海明威忠實的信徒，他對年輕作者的勸告是：「簡單的字句，真實的感情。」兩者我都有。"},{"book":"历史的教训（习近平中南海办公室藏书，中纪委“2015年首推书”;美国普利策奖获得者的传世经典，浓缩对历史经验教训的独特见解）","author":"[ 美] 威尔·杜兰特 阿里尔·杜兰特/ 著","text":"有时我们感到，相比于今天我们一再努力扩大我们的手段而不去改善我们的目标，中世纪和文艺复兴时期的人们重在强调神话和艺术，而不是科学和力量，其做法显然要更为明智。"},{"book":"Focus: The ASML way - Inside the power struggle over the most complex machine on earth","author":"Marc Hijink","text":"这是一家经营状况良好的公司所能负担的奢侈品。例如，2021年，ASML的利润接近60亿欧元，比上年增长70%。"},{"book":"Focus: The ASML way - Inside the power struggle over the most complex machine on earth","author":"Marc Hijink","text":"ASML 知道的一件事是：如果你承担了所有风险，你永远不会按时收到芯片机器。"},{"book":"A Brief History of Intelligence","author":"Max Bennett","text":"从某些方面来看，真菌策略比动物策略更成功——从生物量来看，地球上真菌的数量大约是动物数量的六倍。但是，正如我们将不断看到的，创新往往源自更糟糕、更困难的策略。"},{"book":"原子習慣：細微改變帶來巨大成就的實證法則","author":"譯者：蔡世偉","text":"结论很清楚：对何时何地运行一项新习惯做出确切计划的人，比较可能真的去运行。"},{"book":"原子習慣：細微改變帶來巨大成就的實證法則","author":"譯者：蔡世偉","text":"许多人认为自己缺乏激励，其实他们缺的是清晰。"},{"book":"技术革命与金融资本","author":"","text":"资本主义一方面做出了太多关于社会进步的允诺，另一方面兑现得却不够多；一方面显示了太多的财富创造能力，另一方面分配给人的却不够。"},{"book":"大教堂与集市（开源运动的《圣经》，中文版首次出版）","author":"（美）Eric S. Raymond 著","text":"只凭态度并不会让你成为黑客，就像只凭态度不会让你成为冠军运动员或摇滚明星一样。要成为一名黑客，你需要智慧、实践、投入和努力。"},{"book":"美国反对美国","author":"王沪宁","text":"任何抽象推理都只能源自对事实的观察和分析，抽象推理要能够说服人，很重要的，点是驾有没有令人信服的事实奠基有时候人们需要做一种工作，这就是提供思维的机会，而非思维的结论。"},{"book":"国步艰难：中国社会主义路径的五次选择 (博源文库)","author":"萧冬连","text":"到了某种阶段，我们还是需要去回答人们研究历史的终极兴趣，就是为什么？光靠事实的自然连接，不能投射出这个结论，还是需要用哲理、用历史细节以外更高层面的东西去归纳，才能回答这个为什么。"},{"book":"国步艰难：中国社会主义路径的五次选择 (博源文库)","author":"萧冬连","text":"然而他所期待的“自由人联合体”并没有出现，摆脱了资本的奴役，却跌入了无所不在的体制之中。在这个体制中，个人无条件服从国家又高度依赖于国家，自由选择既无可能也无必要，没有竞争没有选择也就没有创新。"},{"book":"国步艰难：中国社会主义路径的五次选择 (博源文库)","author":"萧冬连","text":"李先念在总结报告中提出，“必须勇敢地改造一切不适应生产力发展的生产关系和不适应经济基础要求的上层建筑，放手发挥经济手段和经济组织的作用。”"},{"book":"国步艰难：中国社会主义路径的五次选择 (博源文库)","author":"萧冬连","text":"真正的危险不在因缺乏经验而犯错，而在于因阻塞批评而丧失纠错的能力。"},{"book":"美国反对美国","author":"王沪宁","text":"美国有两条海岸线，实在是地理上的天赐，东海岸遥望欧洲，西海岸相隔亚洲。最强大的经济和文化力量均在两个海岸地区。中国的沿海地区也是最为发达的，如果有一条西海岸，恐怕中国不是今天的中国了。"},{"book":"美国反对美国","author":"王沪宁","text":"他们认为：在现代社会中，每个国家都面临着前所未有的挑战，都必须管理疾速变迁的社会和经济。公共部门有着至关重要的作用。要适应这种变化，公共部门的官员就必须掌握政策分析、决策和政策执行的技能。"},{"book":"美国反对美国","author":"王沪宁","text":"另外一点值得注意的是，象国会议员这样的“高级选举”，并不那样吸引人和激励人心，大部分人似乎无动于衷。这是民主的一项重要条件，虽然并不是理想条件。如果人人对政治怀着强烈的兴趣，民主是不会成熟地运转的。"},{"book":"美国反对美国","author":"王沪宁","text":"这种制度自然进化的结果是：大型利益集团，经济的也罢，政治的也罢，拥有统治权力。"},{"book":"美国反对美国","author":"王沪宁","text":"“对自由和平等的看法不同，共和党侧重于自由，民主党侧重于平等。”"},{"book":"美国反对美国","author":"王沪宁","text":"任何抽象推理都只能源自对事实的观察和分析，抽象推理要能够说服人，很重要的一点是有没有令人信服的事实奠基。有时候人们需要做一种工作，这就是提供思维的机会，而非思维的结论。"},{"book":"Facebook：一个商业帝国的崛起与逆转（官方授权采访，直击Facebook内幕。樊登、秦朔、胡泳鼎力推荐。）","author":"史蒂文·利维","text":"确保我们能创造一个让每个人都有目标感和意义的世界。”这就是他的主题——目标。"},{"book":"Facebook：一个商业帝国的崛起与逆转（官方授权采访，直击Facebook内幕。樊登、秦朔、胡泳鼎力推荐。）","author":"史蒂文·利维","text":"归根结底，Facebook投注在问答服务上的热情比不上两位创业者围绕这个概念建立起来的创业公司。"}];
